/**
 * Corgi Dashboard — StatusBarEnhanced
 * Drop-in replacement for the basic StatusBar.
 * Integrates HeartbeatIndicator, TelegramStatus, CronOverview, NodeStatus.
 */
import React from 'react';
import { Cpu } from 'lucide-react';
import { useResponsive } from '../layout/ResponsiveProvider';
import { useStatus } from '../../gateway/hooks';
import { HeartbeatIndicator } from './HeartbeatIndicator';
import { TelegramStatus } from './TelegramStatus';
import { CronOverview } from './CronOverview';
import { NodeStatus } from './NodeStatus';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface StatusBarEnhancedProps {
  /** Model name override — defaults to status.currentModel */
  modelName?: string;
  /** Token count override */
  tokenCount?: number;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const StatusBarEnhanced: React.FC<StatusBarEnhancedProps> = ({ modelName, tokenCount }) => {
  const { isMobile } = useResponsive();
  const { status } = useStatus();

  const resolvedModel = modelName ?? (status?.currentModel as string | undefined) ?? (status?.model as string | undefined);

  return (
    <footer
      style={{
        height: 'var(--statusbar-height)',
        background: 'var(--bg-secondary)',
        borderTop: '1px solid var(--border-subtle)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        paddingLeft: 'var(--space-4)',
        paddingRight: 'var(--space-4)',
        gap: 'var(--space-3)',
        fontSize: 'var(--text-xs)',
        color: 'var(--text-muted)',
        zIndex: 'var(--z-sticky)',
        flexShrink: 0,
        userSelect: 'none',
        overflow: 'hidden',
      }}
    >
      {/* ── Left: Heartbeat + Telegram ─────────────────────────────── */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--space-3)',
          flex: '0 1 auto',
          minWidth: 0,
          overflow: 'hidden',
        }}
      >
        <HeartbeatIndicator showTooltip />

        {!isMobile && (
          <>
            <Divider />
            <TelegramStatus compact showTooltip />
          </>
        )}
      </div>

      {/* ── Center: Model + tokens ─────────────────────────────────── */}
      {!isMobile && (
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 'var(--space-2)',
            flex: '0 0 auto',
          }}
        >
          {resolvedModel && (
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 'var(--space-1)',
                color: 'var(--text-muted)',
              }}
            >
              <Cpu size={10} />
              <span style={{ fontFamily: 'var(--font-mono)', fontSize: 'var(--text-xs)' }}>
                {shortenModel(resolvedModel)}
              </span>
            </div>
          )}
          {tokenCount !== undefined && (
            <>
              {resolvedModel && <Divider />}
              <span style={{ fontFamily: 'var(--font-mono)', color: 'var(--text-muted)' }}>
                {tokenCount.toLocaleString()} tok
              </span>
            </>
          )}
        </div>
      )}

      {/* ── Right: Cron + Nodes ────────────────────────────────────── */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--space-3)',
          flex: '0 0 auto',
        }}
      >
        {!isMobile && (
          <>
            <CronOverview compact />
            <Divider />
            <NodeStatus compact />
          </>
        )}

        {/* Mobile: just show a summary pill */}
        {isMobile && (
          <span style={{ color: 'var(--text-muted)', fontSize: 'var(--text-xs)' }}>
            {resolvedModel ? shortenModel(resolvedModel) : 'Corgi'}
          </span>
        )}
      </div>
    </footer>
  );
};

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

const Divider: React.FC = () => (
  <span
    style={{
      width: 1,
      height: 10,
      background: 'var(--border-subtle)',
      flexShrink: 0,
      display: 'inline-block',
    }}
  />
);

function shortenModel(model: string): string {
  // Strip provider prefix: "anthropic/claude-sonnet-4-6" → "claude-sonnet-4-6"
  const slash = model.lastIndexOf('/');
  const base = slash >= 0 ? model.slice(slash + 1) : model;
  // Cap to ~22 chars
  return base.length > 22 ? base.slice(0, 21) + '…' : base;
}

export default StatusBarEnhanced;
