/**
 * MessageList — Renders all finalized messages, streaming segments, tool cards,
 * and the current streaming text in the correct order WITHOUT duplication.
 */
import React, { useMemo } from 'react';
import { AnimatePresence } from 'framer-motion';
import type { ChatMessage, ChatSegment, ToolStreamEntry } from '@/gateway';
import MessageBubble from './MessageBubble';
import ToolCard from './tools/ToolCard';
import ToolCardGroup from './tools/ToolCardGroup';
import StreamingIndicator from './StreamingIndicator';

interface MessageListProps {
  messages: ChatMessage[];
  segments: ChatSegment[];
  toolStream: ToolStreamEntry[];
  streamingText: string;
  isStreaming: boolean;
}

/** Build a stable key for a message */
function messageKey(msg: ChatMessage, idx: number): string {
  const ts = msg.ts ?? 0;
  const ik = msg.idempotencyKey ?? '';
  return `${idx}-${msg.role}-${ts}-${ik}`;
}

const MessageList: React.FC<MessageListProps> = React.memo(
  ({ messages, segments, toolStream, streamingText, isStreaming }) => {
    // Determine avatar grouping: hide avatar if previous message is same role
    const hideAvatarFlags = useMemo(() => {
      return messages.map((msg, i) => {
        if (i === 0) return false;
        return messages[i - 1].role === msg.role;
      });
    }, [messages]);

    // Build tool map: latest entry per toolCallId for the current stream
    const toolMap = useMemo(() => {
      const map = new Map<string, ToolStreamEntry>();
      for (const entry of toolStream) {
        const existing = map.get(entry.toolCallId);
        // Keep latest phase
        if (!existing || entry.ts >= existing.ts) {
          map.set(entry.toolCallId, entry);
        }
      }
      return map;
    }, [toolStream]);

    return (
      <div className="flex flex-col py-2">
        <AnimatePresence initial={false}>
          {/* 1. Finalized messages */}
          {messages.map((msg, i) => (
            <MessageBubble
              key={messageKey(msg, i)}
              message={msg}
              hideAvatar={hideAvatarFlags[i]}
            />
          ))}

          {/* 2. Streaming segments (text committed before tool calls) */}
          {segments.map((seg, i) => {
            if (seg.type === 'text' && seg.text) {
              return (
                <MessageBubble
                  key={`seg-text-${i}`}
                  message={{
                    role: 'assistant',
                    content: [{ type: 'text', text: seg.text }],
                  }}
                  hideAvatar={i > 0 || messages.length > 0}
                />
              );
            }
            if (seg.type === 'tool' && seg.toolEntry) {
              // Look up latest state from toolMap
              const latest = toolMap.get(seg.toolEntry.toolCallId) ?? seg.toolEntry;
              return (
                <div key={`seg-tool-${seg.toolEntry.toolCallId}`} className="px-4 py-0.5 ml-10">
                  <ToolCard entry={latest} />
                </div>
              );
            }
            return null;
          })}

          {/* 3. Any active tool calls NOT yet in segments */}
          {(() => {
            const segToolIds = new Set(
              segments.filter((s) => s.type === 'tool' && s.toolEntry).map((s) => s.toolEntry!.toolCallId),
            );
            const extras = Array.from(toolMap.values()).filter(
              (e) => !segToolIds.has(e.toolCallId),
            );
            if (extras.length === 0) return null;
            if (extras.length > 1) {
              return (
                <div key="tool-group-extras" className="px-4 py-0.5 ml-10">
                  <ToolCardGroup entries={extras} />
                </div>
              );
            }
            return extras.map((entry) => (
              <div key={`tool-${entry.toolCallId}`} className="px-4 py-0.5 ml-10">
                <ToolCard entry={entry} />
              </div>
            ));
          })()}

          {/* 4. Current streaming text */}
          {streamingText && (
            <MessageBubble
              key="streaming-current"
              message={{
                role: 'assistant',
                content: [{ type: 'text', text: streamingText }],
              }}
              hideAvatar={messages.length > 0 || segments.length > 0}
              isStreaming
            />
          )}

          {/* 5. Typing indicator (streaming but no text yet) */}
          {isStreaming && !streamingText && segments.length === 0 && (
            <StreamingIndicator key="typing-indicator" />
          )}
        </AnimatePresence>
      </div>
    );
  },
);

MessageList.displayName = 'MessageList';

export default MessageList;
