/**
 * FileViewer — Display file contents with syntax highlighting, line numbers,
 * copy buttons, and diff view for `edit` operations.
 */
import React, { useState, useCallback, useMemo } from 'react';
import { Check, Copy, ChevronDown, ChevronUp, FileText } from 'lucide-react';

/* ------------------------------------------------------------------ */
/*  Language detection                                                 */
/* ------------------------------------------------------------------ */

const EXT_LANG: Record<string, string> = {
  ts: 'typescript',
  tsx: 'typescript',
  js: 'javascript',
  jsx: 'javascript',
  py: 'python',
  rb: 'ruby',
  rs: 'rust',
  go: 'go',
  java: 'java',
  kt: 'kotlin',
  swift: 'swift',
  c: 'c',
  cpp: 'cpp',
  h: 'c',
  hpp: 'cpp',
  cs: 'csharp',
  css: 'css',
  scss: 'scss',
  html: 'html',
  xml: 'xml',
  json: 'json',
  yaml: 'yaml',
  yml: 'yaml',
  toml: 'toml',
  md: 'markdown',
  sh: 'bash',
  bash: 'bash',
  zsh: 'bash',
  sql: 'sql',
  dockerfile: 'docker',
  makefile: 'makefile',
};

function detectLanguage(filePath: string): string {
  const name = filePath.split('/').pop()?.toLowerCase() ?? '';
  if (name === 'dockerfile') return 'docker';
  if (name === 'makefile') return 'makefile';
  const ext = name.split('.').pop() ?? '';
  return EXT_LANG[ext] ?? 'plaintext';
}

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const COLLAPSE_LINES = 50;

/* ------------------------------------------------------------------ */
/*  DiffView                                                           */
/* ------------------------------------------------------------------ */

interface DiffViewProps {
  oldText: string;
  newText: string;
}

const DiffView: React.FC<DiffViewProps> = React.memo(({ oldText, newText }) => (
  <div
    className="rounded overflow-hidden text-sm font-mono"
    style={{ border: '1px solid var(--border-subtle)' }}
  >
    {/* Removed */}
    <div
      className="px-3 py-2"
      style={{
        background: 'rgba(255, 71, 87, 0.06)',
        borderBottom: '1px solid var(--border-subtle)',
      }}
    >
      {oldText.split('\n').map((line, i) => (
        <div key={`old-${i}`} className="flex">
          <span className="select-none shrink-0 w-5 text-right mr-2" style={{ color: '#ff6e67', opacity: 0.6 }}>−</span>
          <span style={{ color: '#ff6e67' }}>{line}</span>
        </div>
      ))}
    </div>
    {/* Added */}
    <div
      className="px-3 py-2"
      style={{ background: 'rgba(0, 214, 143, 0.06)' }}
    >
      {newText.split('\n').map((line, i) => (
        <div key={`new-${i}`} className="flex">
          <span className="select-none shrink-0 w-5 text-right mr-2" style={{ color: '#5af78e', opacity: 0.6 }}>+</span>
          <span style={{ color: '#5af78e' }}>{line}</span>
        </div>
      ))}
    </div>
  </div>
));

DiffView.displayName = 'DiffView';

/* ------------------------------------------------------------------ */
/*  FileViewer                                                         */
/* ------------------------------------------------------------------ */

interface FileViewerProps {
  filePath: string;
  content: string;
  /** For edit diffs */
  oldText?: string;
  newText?: string;
}

const FileViewer: React.FC<FileViewerProps> = React.memo(
  ({ filePath, content, oldText, newText }) => {
    const [copied, setCopied] = useState(false);
    const [pathCopied, setPathCopied] = useState(false);
    const [expanded, setExpanded] = useState(false);

    const language = useMemo(() => detectLanguage(filePath), [filePath]);
    const lines = useMemo(() => content.split('\n'), [content]);
    const isLong = lines.length > COLLAPSE_LINES;
    const displayLines = isLong && !expanded ? lines.slice(0, COLLAPSE_LINES) : lines;
    const hiddenCount = isLong && !expanded ? lines.length - COLLAPSE_LINES : 0;
    const showDiff = oldText != null && newText != null;

    const copyContent = useCallback(async () => {
      try {
        await navigator.clipboard.writeText(content);
      } catch { /* ignore */ }
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }, [content]);

    const copyPath = useCallback(async () => {
      try {
        await navigator.clipboard.writeText(filePath);
      } catch { /* ignore */ }
      setPathCopied(true);
      setTimeout(() => setPathCopied(false), 2000);
    }, [filePath]);

    return (
      <div
        className="rounded-lg overflow-hidden my-1.5 group/fv"
        style={{
          background: 'var(--bg-primary)',
          border: '1px solid var(--border-subtle)',
        }}
      >
        {/* Header */}
        <div
          className="flex items-center justify-between px-3 py-1.5 gap-2"
          style={{
            background: 'var(--bg-tertiary)',
            borderBottom: '1px solid var(--border-subtle)',
          }}
        >
          <div className="flex items-center gap-2 min-w-0">
            <FileText size={14} style={{ color: 'var(--text-muted)', flexShrink: 0 }} />
            <span
              className="truncate font-mono text-xs"
              style={{ color: 'var(--text-secondary)' }}
            >
              {filePath}
            </span>
            <button
              onClick={copyPath}
              className="shrink-0 opacity-0 group-hover/fv:opacity-100 transition-opacity"
              style={{ color: pathCopied ? 'var(--success)' : 'var(--text-muted)', transitionDuration: 'var(--duration-normal)' }}
              title="Copy path"
            >
              {pathCopied ? <Check size={12} /> : <Copy size={12} />}
            </button>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <span className="text-xs uppercase tracking-wide" style={{ color: 'var(--text-muted)' }}>
              {language}
            </span>
            <button
              onClick={copyContent}
              className="flex items-center gap-1 px-1.5 py-0.5 rounded text-xs opacity-0 group-hover/fv:opacity-100 transition-opacity"
              style={{
                color: copied ? 'var(--success)' : 'var(--text-secondary)',
                transitionDuration: 'var(--duration-normal)',
              }}
              title="Copy content"
            >
              {copied ? <Check size={12} /> : <Copy size={12} />}
              {copied ? 'Copied' : 'Copy'}
            </button>
          </div>
        </div>

        {/* Diff or content */}
        {showDiff ? (
          <div className="p-3">
            <DiffView oldText={oldText!} newText={newText!} />
          </div>
        ) : (
          <div className="overflow-x-auto" style={{ maxHeight: '500px', overflowY: 'auto' }}>
            <pre
              className="p-0 m-0"
              style={{
                fontFamily: 'var(--font-mono)',
                fontSize: 'var(--text-sm)',
                lineHeight: 'var(--leading-snug)',
                color: 'var(--text-primary)',
              }}
            >
              <code>
                <table className="border-collapse w-full">
                  <tbody>
                    {displayLines.map((line, i) => (
                      <tr key={i} className="hover:bg-[rgba(255,255,255,0.02)]">
                        <td
                          className="select-none text-right pr-3 pl-3 align-top"
                          style={{
                            color: 'var(--text-muted)',
                            width: '1%',
                            whiteSpace: 'nowrap',
                            userSelect: 'none',
                            fontSize: 'var(--text-xs)',
                          }}
                        >
                          {i + 1}
                        </td>
                        <td
                          className="pr-3"
                          style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
                        >
                          {line}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </code>
            </pre>
          </div>
        )}

        {/* Expand toggle */}
        {isLong && !showDiff && (
          <button
            onClick={() => setExpanded(!expanded)}
            className="w-full flex items-center justify-center gap-1 py-1.5 text-xs font-medium transition-colors"
            style={{
              color: 'var(--accent-primary)',
              background: 'var(--bg-tertiary)',
              borderTop: '1px solid var(--border-subtle)',
              transitionDuration: 'var(--duration-normal)',
            }}
          >
            {expanded ? (
              <><ChevronUp size={14} /> Collapse</>
            ) : (
              <><ChevronDown size={14} /> Show {hiddenCount} more lines</>
            )}
          </button>
        )}
      </div>
    );
  },
);

FileViewer.displayName = 'FileViewer';

export default FileViewer;
