/**
 * MarkdownRenderer — Renders markdown with GFM, syntax highlighting, and custom components.
 */
import React, { useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeHighlight from 'rehype-highlight';
import type { Components } from 'react-markdown';
import CodeBlock from './CodeBlock';

interface MarkdownRendererProps {
  content: string;
  className?: string;
}

const MarkdownRenderer: React.FC<MarkdownRendererProps> = React.memo(({ content, className }) => {
  const components = useMemo<Components>(
    () => ({
      // Code blocks & inline code
      code({ children, className: codeClassName, ...props }) {
        const match = /language-(\w+)/.exec(codeClassName || '');
        const language = match?.[1];
        const text = String(children).replace(/\n$/, '');

        // If it's a block code (has language class or multi-line), render CodeBlock
        if (language || text.includes('\n')) {
          return <CodeBlock language={language}>{text}</CodeBlock>;
        }

        // Inline code
        return (
          <code
            className="px-1.5 py-0.5 rounded text-sm"
            style={{
              background: 'var(--bg-tertiary)',
              color: 'var(--accent-primary)',
              fontFamily: 'var(--font-mono)',
              fontSize: '0.85em',
            }}
            {...props}
          >
            {children}
          </code>
        );
      },

      // Pre — just pass through, CodeBlock handles styling
      pre({ children }) {
        return <>{children}</>;
      },

      // Links
      a({ href, children }) {
        return (
          <a
            href={href}
            target="_blank"
            rel="noopener noreferrer"
            className="underline underline-offset-2 transition-colors"
            style={{
              color: 'var(--accent-primary)',
              transitionDuration: 'var(--duration-normal)',
            }}
            onMouseEnter={(e) => {
              (e.target as HTMLElement).style.color = 'var(--accent-hover)';
            }}
            onMouseLeave={(e) => {
              (e.target as HTMLElement).style.color = 'var(--accent-primary)';
            }}
          >
            {children}
          </a>
        );
      },

      // Tables
      table({ children }) {
        return (
          <div className="overflow-x-auto my-3 rounded-lg" style={{ border: '1px solid var(--border-subtle)' }}>
            <table className="w-full border-collapse text-sm">{children}</table>
          </div>
        );
      },
      thead({ children }) {
        return (
          <thead style={{ background: 'var(--bg-tertiary)' }}>{children}</thead>
        );
      },
      th({ children }) {
        return (
          <th
            className="text-left px-3 py-2 font-semibold"
            style={{
              color: 'var(--text-primary)',
              borderBottom: '1px solid var(--border-default)',
            }}
          >
            {children}
          </th>
        );
      },
      td({ children }) {
        return (
          <td
            className="px-3 py-2"
            style={{
              color: 'var(--text-secondary)',
              borderBottom: '1px solid var(--border-subtle)',
            }}
          >
            {children}
          </td>
        );
      },

      // Lists
      ul({ children }) {
        return (
          <ul className="list-disc pl-6 my-2 space-y-1" style={{ color: 'var(--text-primary)' }}>
            {children}
          </ul>
        );
      },
      ol({ children }) {
        return (
          <ol className="list-decimal pl-6 my-2 space-y-1" style={{ color: 'var(--text-primary)' }}>
            {children}
          </ol>
        );
      },
      li({ children }) {
        return (
          <li className="leading-relaxed" style={{ color: 'var(--text-primary)' }}>
            {children}
          </li>
        );
      },

      // Blockquotes
      blockquote({ children }) {
        return (
          <blockquote
            className="pl-4 my-3 italic"
            style={{
              borderLeft: '3px solid var(--accent-primary)',
              color: 'var(--text-secondary)',
            }}
          >
            {children}
          </blockquote>
        );
      },

      // Headings
      h1({ children }) {
        return (
          <h1
            className="text-2xl font-bold mt-6 mb-3 leading-tight"
            style={{ color: 'var(--text-primary)' }}
          >
            {children}
          </h1>
        );
      },
      h2({ children }) {
        return (
          <h2
            className="text-xl font-bold mt-5 mb-2 leading-tight"
            style={{ color: 'var(--text-primary)' }}
          >
            {children}
          </h2>
        );
      },
      h3({ children }) {
        return (
          <h3
            className="text-lg font-semibold mt-4 mb-2 leading-snug"
            style={{ color: 'var(--text-primary)' }}
          >
            {children}
          </h3>
        );
      },
      h4({ children }) {
        return (
          <h4
            className="text-base font-semibold mt-3 mb-1 leading-snug"
            style={{ color: 'var(--text-primary)' }}
          >
            {children}
          </h4>
        );
      },

      // Paragraphs
      p({ children }) {
        return (
          <p className="my-2 leading-relaxed" style={{ color: 'var(--text-primary)' }}>
            {children}
          </p>
        );
      },

      // Horizontal rules
      hr() {
        return (
          <hr
            className="my-4 border-none"
            style={{ height: '1px', background: 'var(--border-subtle)' }}
          />
        );
      },

      // Images
      img({ src, alt }) {
        return (
          <img
            src={src}
            alt={alt ?? ''}
            className="max-w-full rounded-lg my-2 cursor-pointer hover:opacity-90 transition-opacity"
            style={{ maxHeight: '400px', transitionDuration: 'var(--duration-normal)' }}
            loading="lazy"
          />
        );
      },

      // Strong / em
      strong({ children }) {
        return <strong className="font-semibold" style={{ color: 'var(--text-primary)' }}>{children}</strong>;
      },
      em({ children }) {
        return <em style={{ color: 'var(--text-secondary)' }}>{children}</em>;
      },
    }),
    [],
  );

  return (
    <div
      className={`markdown-body break-words ${className ?? ''}`}
      style={{
        fontFamily: 'var(--font-sans)',
        fontSize: 'var(--text-base)',
        lineHeight: 'var(--leading-relaxed)',
      }}
    >
      <ReactMarkdown
        remarkPlugins={[remarkGfm]}
        rehypePlugins={[rehypeHighlight]}
        components={components}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
});

MarkdownRenderer.displayName = 'MarkdownRenderer';

export default MarkdownRenderer;
