/**
 * ChatInput — Multi-line input with file attachments, paste, drag-drop, streaming abort.
 */
import React, { useState, useRef, useCallback, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Square, Paperclip, X, Image as ImageIcon } from 'lucide-react';
import { scaleIn } from '@/theme';

interface Attachment {
  id: string;
  file: File;
  preview?: string;
  type: string;
  name: string;
}

interface ChatInputProps {
  onSend: (text: string, attachments?: Array<{ type: string; name?: string; data?: string; media_type?: string }>) => void;
  onAbort: () => void;
  isStreaming: boolean;
  isConnected: boolean;
  disabled?: boolean;
}

const MAX_LINES = 12;
const CHAR_COUNT_THRESHOLD = 500;

const ChatInput: React.FC<ChatInputProps> = React.memo(
  ({ onSend, onAbort, isStreaming, isConnected, disabled = false }) => {
    const [text, setText] = useState('');
    const [attachments, setAttachments] = useState<Attachment[]>([]);
    const [isDragOver, setIsDragOver] = useState(false);
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Auto-resize textarea
    useEffect(() => {
      const el = textareaRef.current;
      if (!el) return;
      el.style.height = 'auto';
      const lineHeight = 24; // approx
      const maxHeight = lineHeight * MAX_LINES;
      el.style.height = `${Math.min(el.scrollHeight, maxHeight)}px`;
    }, [text]);

    const fileToAttachment = useCallback(async (file: File): Promise<Attachment> => {
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onload = () => {
          const base64 = (reader.result as string).split(',')[1];
          resolve({
            id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
            file,
            preview: file.type.startsWith('image/') ? reader.result as string : undefined,
            type: file.type || 'application/octet-stream',
            name: file.name,
          });
        };
        reader.readAsDataURL(file);
      });
    }, []);

    const addFiles = useCallback(
      async (files: FileList | File[]) => {
        const newAttachments = await Promise.all(
          Array.from(files).map((f) => fileToAttachment(f)),
        );
        setAttachments((prev) => [...prev, ...newAttachments]);
      },
      [fileToAttachment],
    );

    const removeAttachment = useCallback((id: string) => {
      setAttachments((prev) => prev.filter((a) => a.id !== id));
    }, []);

    const handleSend = useCallback(() => {
      const trimmed = text.trim();
      if (!trimmed && attachments.length === 0) return;

      const atts = attachments.length > 0
        ? attachments.map((a) => ({
            type: a.type.startsWith('image/') ? 'image' : 'file',
            name: a.name,
            data: a.preview?.split(',')[1],
            media_type: a.type,
          }))
        : undefined;

      onSend(trimmed, atts);
      setText('');
      setAttachments([]);
      // Reset height
      if (textareaRef.current) {
        textareaRef.current.style.height = 'auto';
      }
    }, [text, attachments, onSend]);

    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent) => {
        // Cmd+Enter or Ctrl+Enter to send
        if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
          e.preventDefault();
          if (isStreaming) {
            onAbort();
          } else {
            handleSend();
          }
        }
      },
      [handleSend, isStreaming, onAbort],
    );

    // Paste images from clipboard
    const handlePaste = useCallback(
      async (e: React.ClipboardEvent) => {
        const items = e.clipboardData.items;
        const imageFiles: File[] = [];
        for (let i = 0; i < items.length; i++) {
          if (items[i].type.startsWith('image/')) {
            const file = items[i].getAsFile();
            if (file) imageFiles.push(file);
          }
        }
        if (imageFiles.length > 0) {
          e.preventDefault();
          await addFiles(imageFiles);
        }
      },
      [addFiles],
    );

    // Drag and drop
    const handleDragOver = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDragOver(true);
    }, []);
    const handleDragLeave = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDragOver(false);
    }, []);
    const handleDrop = useCallback(
      async (e: React.DragEvent) => {
        e.preventDefault();
        setIsDragOver(false);
        if (e.dataTransfer.files.length > 0) {
          await addFiles(e.dataTransfer.files);
        }
      },
      [addFiles],
    );

    const canSend = (text.trim().length > 0 || attachments.length > 0) && !disabled;
    const showCharCount = text.length > CHAR_COUNT_THRESHOLD;
    const isDisconnected = !isConnected;

    return (
      <div
        className="relative px-4 pb-4 pt-2"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {/* Disconnected overlay */}
        {isDisconnected && (
          <div
            className="absolute inset-0 flex items-center justify-center rounded-xl z-10"
            style={{
              background: 'var(--bg-overlay)',
              backdropFilter: 'blur(4px)',
            }}
          >
            <span className="text-sm font-medium" style={{ color: 'var(--error)' }}>
              Disconnected
            </span>
          </div>
        )}

        {/* Drag overlay */}
        <AnimatePresence>
          {isDragOver && (
            <motion.div
              className="absolute inset-0 flex items-center justify-center rounded-xl z-10 pointer-events-none"
              style={{
                background: 'var(--accent-muted)',
                border: '2px dashed var(--accent-primary)',
              }}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
            >
              <div className="flex items-center gap-2" style={{ color: 'var(--accent-primary)' }}>
                <ImageIcon size={20} />
                <span className="text-sm font-medium">Drop files here</span>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Attachment previews */}
        <AnimatePresence>
          {attachments.length > 0 && (
            <motion.div
              className="flex gap-2 mb-2 overflow-x-auto"
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
            >
              {attachments.map((att) => (
                <div
                  key={att.id}
                  className="relative shrink-0 rounded-lg overflow-hidden"
                  style={{
                    background: 'var(--bg-tertiary)',
                    border: '1px solid var(--border-subtle)',
                  }}
                >
                  {att.preview ? (
                    <img
                      src={att.preview}
                      alt={att.name}
                      className="w-16 h-16 object-cover"
                    />
                  ) : (
                    <div className="w-16 h-16 flex items-center justify-center text-xs" style={{ color: 'var(--text-muted)' }}>
                      {att.name.split('.').pop()?.toUpperCase()}
                    </div>
                  )}
                  <button
                    className="absolute top-0.5 right-0.5 p-0.5 rounded-full"
                    style={{
                      background: 'var(--bg-primary)',
                      color: 'var(--text-secondary)',
                    }}
                    onClick={() => removeAttachment(att.id)}
                    aria-label={`Remove ${att.name}`}
                  >
                    <X size={10} />
                  </button>
                </div>
              ))}
            </motion.div>
          )}
        </AnimatePresence>

        {/* Input area */}
        <div
          className="flex items-end gap-2 rounded-xl px-3 py-2 transition-colors"
          style={{
            background: 'var(--bg-input)',
            border: `1px solid ${isDragOver ? 'var(--accent-primary)' : 'var(--border-default)'}`,
            transitionDuration: 'var(--duration-normal)',
          }}
        >
          {/* Attach button */}
          <button
            className="p-1.5 rounded-lg transition-colors shrink-0 mb-0.5"
            style={{
              color: 'var(--text-muted)',
              transitionDuration: 'var(--duration-normal)',
            }}
            onClick={() => fileInputRef.current?.click()}
            title="Attach file"
          >
            <Paperclip size={18} />
          </button>
          <input
            ref={fileInputRef}
            type="file"
            multiple
            accept="image/*,.pdf,.txt,.md,.json,.csv"
            className="hidden"
            onChange={async (e) => {
              if (e.target.files) await addFiles(e.target.files);
              e.target.value = '';
            }}
          />

          {/* Textarea */}
          <textarea
            ref={textareaRef}
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={handleKeyDown}
            onPaste={handlePaste}
            placeholder="Message Brock..."
            rows={1}
            disabled={disabled || isDisconnected}
            className="flex-1 resize-none bg-transparent outline-none py-1.5 text-base leading-relaxed placeholder-[var(--text-muted)]"
            style={{
              color: 'var(--text-primary)',
              fontFamily: 'var(--font-sans)',
              fontSize: 'var(--text-base)',
              maxHeight: `${24 * MAX_LINES}px`,
            }}
          />

          {/* Character count */}
          {showCharCount && (
            <span
              className="text-xs shrink-0 mb-1"
              style={{ color: 'var(--text-muted)' }}
            >
              {text.length.toLocaleString()}
            </span>
          )}

          {/* Send / Stop button */}
          <AnimatePresence mode="wait">
            {isStreaming ? (
              <motion.button
                key="stop"
                className="p-2 rounded-lg shrink-0 mb-0.5 transition-colors"
                style={{
                  background: 'var(--error-muted)',
                  color: 'var(--error)',
                  transitionDuration: 'var(--duration-normal)',
                }}
                onClick={onAbort}
                title="Stop generating"
                variants={scaleIn}
                initial="hidden"
                animate="visible"
                exit="exit"
              >
                <Square size={16} fill="currentColor" />
              </motion.button>
            ) : (
              <motion.button
                key="send"
                className="p-2 rounded-lg shrink-0 mb-0.5 transition-colors"
                style={{
                  background: canSend ? 'var(--accent-primary)' : 'var(--bg-tertiary)',
                  color: canSend ? 'var(--text-inverse)' : 'var(--text-muted)',
                  cursor: canSend ? 'pointer' : 'default',
                  transitionDuration: 'var(--duration-normal)',
                }}
                onClick={canSend ? handleSend : undefined}
                disabled={!canSend}
                title="Send (⌘ Enter)"
                variants={scaleIn}
                initial="hidden"
                animate="visible"
                exit="exit"
              >
                <Send size={16} />
              </motion.button>
            )}
          </AnimatePresence>
        </div>
      </div>
    );
  },
);

ChatInput.displayName = 'ChatInput';

export default ChatInput;
