/**
 * EmptyState — Welcome screen shown when there are no messages.
 */
import React from 'react';
import { motion } from 'framer-motion';
import { fadeIn, staggerChildren, staggerItem } from '@/theme';

interface EmptyStateProps {
  onSendMessage: (text: string) => void;
}

const suggestions = [
  "What's on my calendar today?",
  'Check the status of my Cloudflare projects',
  'Show me my memory',
  'What tools do you have access to?',
];

const EmptyState: React.FC<EmptyStateProps> = React.memo(({ onSendMessage }) => {
  return (
    <motion.div
      className="flex flex-col items-center justify-center h-full px-4 select-none"
      variants={fadeIn}
      initial="hidden"
      animate="visible"
    >
      {/* Logo */}
      <motion.div
        className="text-6xl mb-6 opacity-40"
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 0.4 }}
        transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
      >
        C
      </motion.div>

      {/* Heading */}
      <h2
        className="text-xl font-semibold mb-2 text-center"
        style={{ color: 'var(--text-primary)' }}
      >
        What can I help you build?
      </h2>
      <p
        className="text-sm mb-8 text-center max-w-md"
        style={{ color: 'var(--text-secondary)' }}
      >
        Ask me anything, my Tribal Chief.
      </p>

      {/* Suggestion chips */}
      <motion.div
        className="flex flex-wrap gap-2 justify-center max-w-lg"
        variants={staggerChildren}
        initial="hidden"
        animate="visible"
      >
        {suggestions.map((text) => (
          <motion.button
            key={text}
            className="px-4 py-2 rounded-full text-sm transition-all cursor-pointer"
            style={{
              background: 'var(--bg-secondary)',
              border: '1px solid var(--border-subtle)',
              color: 'var(--text-secondary)',
              transitionDuration: 'var(--duration-normal)',
            }}
            variants={staggerItem}
            whileHover={{
              scale: 1.02,
              borderColor: 'var(--accent-primary)',
              color: 'var(--accent-primary)',
            }}
            whileTap={{ scale: 0.98 }}
            onClick={() => onSendMessage(text)}
          >
            {text}
          </motion.button>
        ))}
      </motion.div>

      {/* Shortcut hint */}
      <p
        className="mt-12 text-xs"
        style={{ color: 'var(--text-muted)' }}
      >
        <kbd
          className="px-1.5 py-0.5 rounded text-xs"
          style={{ background: 'var(--bg-tertiary)', border: '1px solid var(--border-subtle)' }}
        >
          ⌘ Enter
        </kbd>
        {' '}to send
      </p>
    </motion.div>
  );
});

EmptyState.displayName = 'EmptyState';

export default EmptyState;
