/* ------------------------------------------------------------------ */
/*  Header                                                             */
/* ------------------------------------------------------------------ */

interface HeaderProps {
  connectionStatus?: ConnectionStatus;
  sessionName?: string;
  onSettingsClick?: () => void;
  onSessionPickerClick?: () => void;
  onThemeToggle?: () => void;
  theme?: 'dark' | 'light' | 'auto';
}

export const Header: React.FC<HeaderProps> = ({
  connectionStatus = 'connected',
  sessionName = 'Main Session',
  onSettingsClick,
  onSessionPickerClick,
  onThemeToggle,
  theme = 'dark',
}) => {
  const { isMobile } = useResponsive();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  return (
    <header
      className="flex items-center justify-between px-4 shrink-0"
      style={{
        height: 'var(--header-height)',
        background: 'var(--bg-secondary)',
        borderBottom: '1px solid var(--border-subtle)',
        zIndex: 'var(--z-header)',
        position: 'relative',
      }}
    >
      {/* Left — Logo */}
      <div className="flex items-center gap-3">
        <CorgiLogo />
      </div>

      {/* Center — Session picker (desktop) */}
      {!isMobile && (
        <button
          onClick={onSessionPickerClick}
          className="flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors"
          style={{
            background: 'var(--bg-tertiary)',
            border: '1px solid var(--border-subtle)',
            color: 'var(--text-primary)',
            cursor: 'pointer',
            fontSize: 'var(--text-sm)',
            fontWeight: 'var(--font-medium)',
          }}
        >
          {sessionName}
          <ChevronDown size={14} style={{ color: 'var(--text-muted)' }} />
        </button>
      )}

      {/* Right — Status & actions */}
      {isMobile ? (
        <>
          <button
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            style={{
              background: 'none',
              border: 'none',
              color: 'var(--text-secondary)',
              cursor: 'pointer',
              padding: '0.5rem',
            }}
          >
            {mobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
          </button>

          <AnimatePresence>
            {mobileMenuOpen && (
              <motion.div
                initial={{ opacity: 0, y: -8 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -8 }}
                transition={{ duration: 0.15 }}
                className="absolute top-full left-0 right-0 p-4 flex flex-col gap-3"
                style={{
                  background: 'var(--bg-secondary)',
                  borderBottom: '1px solid var(--border-default)',
                  zIndex: 'var(--z-dropdown)',
                }}
              >
                <button
                  onClick={onSessionPickerClick}
                  className="flex items-center gap-2 px-3 py-2 rounded-lg"
                  style={{
                    background: 'var(--bg-tertiary)',
                    border: '1px solid var(--border-subtle)',
                    color: 'var(--text-primary)',
                    cursor: 'pointer',
                    fontSize: 'var(--text-sm)',
                  }}
                >
                  {sessionName}
                  <ChevronDown size={14} style={{ color: 'var(--text-muted)' }} />
                </button>

                <div className="flex items-center gap-2" style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                  <span
                    style={{
                      width: 8,
                      height: 8,
                      borderRadius: 'var(--radius-full)',
                      background: statusColors[connectionStatus],
                      display: 'inline-block',
                    }}
                  />
                  {statusLabels[connectionStatus]}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </>
      ) : (
        <div className="flex items-center gap-4">
          {/* Connection status */}
          <div className="flex items-center gap-2" style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
            <motion.span
              style={{
                width: 8,
                height: 8,
                borderRadius: 'var(--radius-full)',
                background: statusColors[connectionStatus],
                display: 'inline-block',
              }}
              animate={
                connectionStatus === 'connected'
                  ? { scale: [1, 1.2, 1], opacity: [1, 0.8, 1] }
                  : connectionStatus === 'reconnecting'
                    ? { opacity: [1, 0.3, 1] }
                    : {}
              }
              transition={
                connectionStatus === 'connected'
                  ? { duration: 2, repeat: Infinity, ease: 'easeInOut' }
                  : connectionStatus === 'reconnecting'
                    ? { duration: 1, repeat: Infinity }
                    : {}
              }
            />
            {statusLabels[connectionStatus]}
          </div>

          {/* Theme toggle */}
          <button
            onClick={onThemeToggle}
            className="px-2 py-1 rounded-md transition-colors"
            style={{
              background: 'none',
              border: '1px solid var(--border-subtle)',
              color: 'var(--text-secondary)',
              cursor: 'pointer',
              fontSize: 'var(--text-xs)',
              fontWeight: 'var(--font-medium)',
              textTransform: 'uppercase',
              letterSpacing: '0.05em',
            }}
          >
            {theme === 'dark' ? '🌙' : theme === 'light' ? '☀️' : '🔄'}
          </button>

          {/* User avatar placeholder */}
          <div
            style={{
              width: 28,
              height: 28,
              borderRadius: 'var(--radius-full)',
              background: 'var(--accent-muted)',
              border: '1px solid var(--accent-primary)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 'var(--text-xs)',
              color: 'var(--accent-primary)',
              fontWeight: 'var(--font-semibold)',
            }}
          >
            J
          </div>

          {/* Settings */}
          <button
            onClick={onSettingsClick}
            style={{
              background: 'none',
              border: 'none',
              color: 'var(--text-secondary)',
              cursor: 'pointer',
              padding: '0.25rem',
              display: 'flex',
              alignItems: 'center',
              transition: 'color var(--transition-fast)',
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = 'var(--text-primary)')}
            onMouseLeave={(e) => (e.currentTarget.style.color = 'var(--text-secondary)')}
          >
            <Settings size={18} />
          </button>
        </div>
      )}
    </header>
  );
};

export { CorgiLogo };
export default Header;
