/**
 * Corgi Dashboard — Generic Resizable Side Panel
 *
 * Slides in from the right on desktop, from the bottom on mobile.
 * Resizable via drag handle on the left edge. Escape to close.
 */
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { AnimatePresence, motion, type Variants } from 'framer-motion';
import { X } from 'lucide-react';
import { useResponsive } from '../layout/ResponsiveProvider';
import { transitionSlow } from '../../theme/animations';

/* ------------------------------------------------------------------ */
/*  Props                                                              */
/* ------------------------------------------------------------------ */

interface SidePanelProps {
  open: boolean;
  onClose: () => void;
  title?: string;
  /** Header right-side actions */
  headerActions?: React.ReactNode;
  children: React.ReactNode;
  /** Default width as percentage (0–1). Default: 0.4 */
  defaultWidth?: number;
  /** Minimum width as percentage (0–1). Default: 0.25 */
  minWidth?: number;
  /** Maximum width as percentage (0–1). Default: 0.6 */
  maxWidth?: number;
}

/* ------------------------------------------------------------------ */
/*  Animation variants                                                 */
/* ------------------------------------------------------------------ */

const desktopVariants = {
  hidden: { x: '100%', opacity: 0 },
  visible: { x: 0, opacity: 1, transition: transitionSlow },
  exit: { x: '100%', opacity: 0, transition: transitionSlow },
};

const mobileVariants: Variants = {
  hidden: { y: '100%' },
  visible: { y: 0, transition: { duration: 0.3, ease: [0.65, 0, 0.35, 1] as [number, number, number, number] } },
  exit: { y: '100%', transition: { duration: 0.3, ease: [0.65, 0, 0.35, 1] as [number, number, number, number] } },
};

const backdropVariants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { duration: 0.2 } },
  exit: { opacity: 0, transition: { duration: 0.2 } },
};

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const SidePanel: React.FC<SidePanelProps> = ({
  open,
  onClose,
  title,
  headerActions,
  children,
  defaultWidth = 0.4,
  minWidth = 0.25,
  maxWidth = 0.6,
}) => {
  const { isMobile } = useResponsive();
  const [widthPct, setWidthPct] = useState(defaultWidth);
  const isDragging = useRef(false);
  const containerRef = useRef<HTMLDivElement>(null);

  /* ---- Escape key ---- */
  useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [open, onClose]);

  /* ---- Drag-to-resize (desktop only) ---- */
  const onDragStart = useCallback(
    (e: React.MouseEvent) => {
      if (isMobile) return;
      e.preventDefault();
      isDragging.current = true;
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';

      const onMove = (ev: MouseEvent) => {
        if (!isDragging.current) return;
        const viewportWidth = window.innerWidth;
        const newPct = 1 - ev.clientX / viewportWidth;
        setWidthPct(Math.min(maxWidth, Math.max(minWidth, newPct)));
      };

      const onUp = () => {
        isDragging.current = false;
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
        window.removeEventListener('mousemove', onMove);
        window.removeEventListener('mouseup', onUp);
      };

      window.addEventListener('mousemove', onMove);
      window.addEventListener('mouseup', onUp);
    },
    [isMobile, minWidth, maxWidth],
  );

  return (
    <AnimatePresence>
      {open && (
        <>
          {/* Backdrop */}
          <motion.div
            key="panel-backdrop"
            variants={backdropVariants}
            initial="hidden"
            animate="visible"
            exit="exit"
            onClick={onClose}
            style={{
              position: 'fixed',
              inset: 0,
              background: 'rgba(0, 0, 0, 0.3)',
              zIndex: 40,
            }}
          />

          {/* Panel */}
          {isMobile ? (
            /* ---- Mobile: bottom sheet ---- */
            <motion.div
              key="side-panel-mobile"
              ref={containerRef}
              variants={mobileVariants}
              initial="hidden"
              animate="visible"
              exit="exit"
              style={{
                position: 'fixed',
                bottom: 0,
                left: 0,
                right: 0,
                height: '85vh',
                background: 'var(--bg-primary)',
                borderTop: '1px solid var(--border-default)',
                borderTopLeftRadius: 'var(--radius-xl)',
                borderTopRightRadius: 'var(--radius-xl)',
                zIndex: 50,
                display: 'flex',
                flexDirection: 'column',
                overflow: 'hidden',
              }}
            >
              {/* Drag handle */}
              <div className="flex justify-center py-2">
                <div
                  style={{
                    width: 32,
                    height: 4,
                    borderRadius: 'var(--radius-full)',
                    background: 'var(--border-default)',
                  }}
                />
              </div>

              {/* Header */}
              <PanelHeader title={title} onClose={onClose} actions={headerActions} />

              {/* Content */}
              <div className="flex-1 overflow-y-auto" style={{ padding: 'var(--space-4)' }}>
                {children}
              </div>
            </motion.div>
          ) : (
            /* ---- Desktop: right side panel ---- */
            <motion.div
              key="side-panel-desktop"
              ref={containerRef}
              variants={desktopVariants}
              initial="hidden"
              animate="visible"
              exit="exit"
              style={{
                position: 'fixed',
                top: 0,
                right: 0,
                bottom: 0,
                width: `${widthPct * 100}%`,
                background: 'var(--bg-primary)',
                borderLeft: '1px solid var(--border-subtle)',
                zIndex: 50,
                display: 'flex',
                flexDirection: 'column',
                overflow: 'hidden',
                boxShadow: '-4px 0 24px rgba(0, 0, 0, 0.15)',
              }}
            >
              {/* Resize handle */}
              <div
                onMouseDown={onDragStart}
                style={{
                  position: 'absolute',
                  left: 0,
                  top: 0,
                  bottom: 0,
                  width: 6,
                  cursor: 'col-resize',
                  zIndex: 10,
                  background: 'transparent',
                }}
                onMouseEnter={(e) => {
                  (e.currentTarget as HTMLElement).style.background = 'var(--accent-primary)';
                  (e.currentTarget as HTMLElement).style.opacity = '0.4';
                }}
                onMouseLeave={(e) => {
                  if (!isDragging.current) {
                    (e.currentTarget as HTMLElement).style.background = 'transparent';
                    (e.currentTarget as HTMLElement).style.opacity = '1';
                  }
                }}
              />

              {/* Header */}
              <PanelHeader title={title} onClose={onClose} actions={headerActions} />

              {/* Content */}
              <div className="flex-1 overflow-y-auto" style={{ padding: 'var(--space-4)' }}>
                {children}
              </div>
            </motion.div>
          )}
        </>
      )}
    </AnimatePresence>
  );
};

/* ------------------------------------------------------------------ */
/*  Panel Header                                                       */
/* ------------------------------------------------------------------ */

const PanelHeader: React.FC<{
  title?: string;
  onClose: () => void;
  actions?: React.ReactNode;
}> = ({ title, onClose, actions }) => (
  <div
    className="flex items-center justify-between px-4 py-3"
    style={{
      borderBottom: '1px solid var(--border-subtle)',
      backdropFilter: 'blur(12px)',
      WebkitBackdropFilter: 'blur(12px)',
      background: 'color-mix(in srgb, var(--bg-primary) 80%, transparent)',
      flexShrink: 0,
    }}
  >
    <span
      style={{
        fontSize: 'var(--text-sm)',
        fontWeight: 'var(--font-semibold)',
        color: 'var(--text-primary)',
        overflow: 'hidden',
        textOverflow: 'ellipsis',
        whiteSpace: 'nowrap',
        maxWidth: '70%',
      }}
    >
      {title ?? 'Panel'}
    </span>
    <div className="flex items-center gap-2">
      {actions}
      <button
        onClick={onClose}
        className="p-1.5 rounded-md transition-colors"
        style={{
          color: 'var(--text-muted)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
        onMouseEnter={(e) => {
          (e.currentTarget as HTMLElement).style.background = 'var(--bg-tertiary)';
          (e.currentTarget as HTMLElement).style.color = 'var(--text-primary)';
        }}
        onMouseLeave={(e) => {
          (e.currentTarget as HTMLElement).style.background = 'transparent';
          (e.currentTarget as HTMLElement).style.color = 'var(--text-muted)';
        }}
        aria-label="Close panel"
      >
        <X size={16} />
      </button>
    </div>
  </div>
);

export default SidePanel;
