/**
 * Corgi Dashboard — Service Worker Registration
 *
 * Registers the SW, handles updates, and manages push subscription.
 */

export interface SWRegistrationCallbacks {
  /** Called when a new SW update is available */
  onUpdateAvailable?: () => void;
  /** Called when SW is ready */
  onReady?: (registration: ServiceWorkerRegistration) => void;
  /** Called on registration error */
  onError?: (error: Error) => void;
}

let registration: ServiceWorkerRegistration | null = null;

/**
 * Register the service worker.
 * Call this once from main.tsx.
 */
export async function registerServiceWorker(
  callbacks: SWRegistrationCallbacks = {},
): Promise<ServiceWorkerRegistration | null> {
  if (!('serviceWorker' in navigator)) {
    console.log('[SW] Service workers not supported');
    return null;
  }

  try {
    registration = await navigator.serviceWorker.register('/service-worker.js', {
      scope: '/',
    });

    // Check for updates
    registration.addEventListener('updatefound', () => {
      const newWorker = registration?.installing;
      if (!newWorker) return;

      newWorker.addEventListener('statechange', () => {
        if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
          // New version available
          console.log('[SW] Update available');
          callbacks.onUpdateAvailable?.();
        }
      });
    });

    // Ready callback
    if (registration.active) {
      callbacks.onReady?.(registration);
    } else {
      navigator.serviceWorker.ready.then((reg) => {
        callbacks.onReady?.(reg);
      });
    }

    console.log('[SW] Registered successfully');
    return registration;
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    console.error('[SW] Registration failed:', err);
    callbacks.onError?.(err);
    return null;
  }
}

/**
 * Apply a waiting service worker update.
 * Call this when the user clicks "Update now".
 */
export function applyUpdate(): void {
  const waiting = registration?.waiting;
  if (waiting) {
    waiting.postMessage({ type: 'SKIP_WAITING' });
    window.location.reload();
  }
}

/**
 * Request notification permission.
 * Returns true if granted.
 */
export async function requestNotificationPermission(): Promise<boolean> {
  if (!('Notification' in window)) return false;
  if (Notification.permission === 'granted') return true;
  if (Notification.permission === 'denied') return false;

  const result = await Notification.requestPermission();
  return result === 'granted';
}

/**
 * Subscribe to push notifications.
 * Returns the PushSubscription or null.
 */
export async function subscribeToPush(
  vapidPublicKey?: string,
): Promise<PushSubscription | null> {
  if (!registration) {
    console.warn('[SW] No registration — cannot subscribe to push');
    return null;
  }

  if (!vapidPublicKey) {
    console.warn('[SW] No VAPID public key — skipping push subscription');
    return null;
  }

  try {
    const existing = await registration.pushManager.getSubscription();
    if (existing) return existing;

    const sub = await registration.pushManager.subscribe({
      userVisibleOnly: true,
      applicationServerKey: urlBase64ToUint8Array(vapidPublicKey) as unknown as ArrayBuffer,
    });

    console.log('[SW] Push subscription created');
    return sub;
  } catch (error) {
    console.error('[SW] Push subscription failed:', error);
    return null;
  }
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function urlBase64ToUint8Array(base64String: string): Uint8Array {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const raw = atob(base64);
  const output = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) {
    output[i] = raw.charCodeAt(i);
  }
  return output;
}
