/**
 * KeyboardShortcuts — Global keyboard shortcut handler.
 *
 * Renders nothing; hooks into keydown events. Platform-aware (⌘ vs Ctrl).
 */
import { useEffect, useCallback } from 'react';

// ─── Types ─────────────────────────────────────────────────────────────────

export interface ShortcutDef {
  id: string;
  keys: string; // e.g. "mod+k", "mod+shift+p", "escape"
  description: string;
  category: 'Chat' | 'Navigation' | 'Panels' | 'General';
  action: () => void;
  enabled?: boolean;
}

export type ShortcutHandler = Omit<ShortcutDef, 'description' | 'category'>;

// ─── Platform helpers ──────────────────────────────────────────────────────

const isMac = typeof navigator !== 'undefined' && /Mac|iPod|iPhone|iPad/.test(navigator.userAgent);

export function formatShortcut(keys: string): string {
  return keys
    .split('+')
    .map((k) => {
      switch (k.toLowerCase()) {
        case 'mod':
          return isMac ? '⌘' : 'Ctrl';
        case 'shift':
          return isMac ? '⇧' : 'Shift';
        case 'alt':
          return isMac ? '⌥' : 'Alt';
        case 'enter':
          return '↵';
        case 'escape':
          return 'Esc';
        default:
          return k.toUpperCase();
      }
    })
    .join(isMac ? '' : '+');
}

// ─── Key matching ──────────────────────────────────────────────────────────

function matchesShortcut(e: KeyboardEvent, keys: string): boolean {
  const parts = keys.toLowerCase().split('+');
  const needMod = parts.includes('mod');
  const needShift = parts.includes('shift');
  const needAlt = parts.includes('alt');
  const key = parts.filter((p) => !['mod', 'shift', 'alt'].includes(p))[0];

  if (!key) return false;

  const modPressed = isMac ? e.metaKey : e.ctrlKey;
  if (needMod && !modPressed) return false;
  if (!needMod && modPressed) return false;
  if (needShift && !e.shiftKey) return false;
  if (!needShift && e.shiftKey && key !== '?') return false;
  if (needAlt && !e.altKey) return false;

  // Special: '?' requires shift on most layouts
  if (key === '?') {
    return e.key === '?' || (e.shiftKey && e.key === '/');
  }

  if (key === 'escape') return e.key === 'Escape';
  if (key === 'enter') return e.key === 'Enter';

  return e.key.toLowerCase() === key;
}

// ─── Default shortcut definitions ──────────────────────────────────────────

export const DEFAULT_SHORTCUTS: Omit<ShortcutDef, 'action'>[] = [
  { id: 'cmd-palette', keys: 'mod+k', description: 'Command palette', category: 'General' },
  { id: 'new-chat', keys: 'mod+n', description: 'New chat', category: 'Chat' },
  { id: 'search-chat', keys: 'mod+f', description: 'Search in chat', category: 'Chat' },
  { id: 'prompt-templates', keys: 'mod+shift+p', description: 'Prompt templates', category: 'Chat' },
  { id: 'toggle-status', keys: 'mod+/', description: 'Toggle status panel', category: 'Panels' },
  { id: 'toggle-sidebar', keys: 'mod+b', description: 'Toggle session sidebar', category: 'Panels' },
  { id: 'toggle-subagent', keys: 'mod+.', description: 'Toggle sub-agent panel', category: 'Panels' },
  { id: 'shortcut-help', keys: 'mod+?', description: 'Keyboard shortcuts help', category: 'General' },
  { id: 'close-panel', keys: 'escape', description: 'Close panel / modal', category: 'General' },
];

// ─── Component ─────────────────────────────────────────────────────────────

interface KeyboardShortcutsProps {
  shortcuts: ShortcutHandler[];
}

/**
 * Mounts a single global keydown listener that dispatches to matched handlers.
 * Renders nothing.
 */
const KeyboardShortcuts: React.FC<KeyboardShortcutsProps> = ({ shortcuts }) => {
  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      // Don't intercept when typing in inputs (except for palette / escape)
      const target = e.target as HTMLElement;
      const isInput =
        target.tagName === 'INPUT' ||
        target.tagName === 'TEXTAREA' ||
        target.isContentEditable;

      for (const s of shortcuts) {
        if (s.enabled === false) continue;
        if (!matchesShortcut(e, s.keys)) continue;

        // Allow escape and cmd+k even inside inputs
        const alwaysAllow = ['mod+k', 'escape'].includes(s.keys.toLowerCase());
        if (isInput && !alwaysAllow) continue;

        e.preventDefault();
        e.stopPropagation();
        s.action();
        return;
      }
    },
    [shortcuts],
  );

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown, true);
    return () => window.removeEventListener('keydown', handleKeyDown, true);
  }, [handleKeyDown]);

  return null;
};

export default KeyboardShortcuts;
