/**
 * Corgi Dashboard — Content Panel State Management
 *
 * React context + Zustand-style hook for managing which content panel
 * is currently open. Only one panel at a time.
 */
import React, { createContext, useCallback, useContext, useState } from 'react';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type PanelType = 'webpage' | 'image-gallery' | 'pdf' | 'canvas' | null;

export interface WebPageContent {
  url: string;
  title?: string;
  content: string;
}

export interface ImageGalleryContent {
  images: Array<{
    src: string;
    alt?: string;
    caption?: string;
  }>;
  initialIndex?: number;
}

export interface PdfContent {
  url?: string;
  title?: string;
  textContent?: string;
}

export interface CanvasContent {
  html: string;
  title?: string;
  allowScripts?: boolean;
}

export type PanelContent = WebPageContent | ImageGalleryContent | PdfContent | CanvasContent;

interface ContentPanelState {
  panelType: PanelType;
  panelContent: PanelContent | null;
  openWebPage: (url: string, content: string, title?: string) => void;
  openImageGallery: (images: ImageGalleryContent['images'], initialIndex?: number) => void;
  openPdf: (urlOrContent: string, title?: string, isText?: boolean) => void;
  openCanvas: (html: string, title?: string, allowScripts?: boolean) => void;
  closePanel: () => void;
}

/* ------------------------------------------------------------------ */
/*  Context                                                            */
/* ------------------------------------------------------------------ */

const ContentPanelContext = createContext<ContentPanelState | null>(null);

/* ------------------------------------------------------------------ */
/*  Provider                                                           */
/* ------------------------------------------------------------------ */

export const ContentPanelProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [panelType, setPanelType] = useState<PanelType>(null);
  const [panelContent, setPanelContent] = useState<PanelContent | null>(null);

  const openWebPage = useCallback((url: string, content: string, title?: string) => {
    setPanelContent({ url, content, title } as WebPageContent);
    setPanelType('webpage');
  }, []);

  const openImageGallery = useCallback(
    (images: ImageGalleryContent['images'], initialIndex?: number) => {
      setPanelContent({ images, initialIndex } as ImageGalleryContent);
      setPanelType('image-gallery');
    },
    [],
  );

  const openPdf = useCallback((urlOrContent: string, title?: string, isText?: boolean) => {
    const content: PdfContent = isText
      ? { textContent: urlOrContent, title }
      : { url: urlOrContent, title };
    setPanelContent(content);
    setPanelType('pdf');
  }, []);

  const openCanvas = useCallback((html: string, title?: string, allowScripts?: boolean) => {
    setPanelContent({ html, title, allowScripts } as CanvasContent);
    setPanelType('canvas');
  }, []);

  const closePanel = useCallback(() => {
    setPanelType(null);
    // Slight delay so exit animation can play before content is cleared
    setTimeout(() => setPanelContent(null), 350);
  }, []);

  return (
    <ContentPanelContext.Provider
      value={{ panelType, panelContent, openWebPage, openImageGallery, openPdf, openCanvas, closePanel }}
    >
      {children}
    </ContentPanelContext.Provider>
  );
};

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

export function useContentPanel(): ContentPanelState {
  const ctx = useContext(ContentPanelContext);
  if (!ctx) {
    throw new Error('useContentPanel must be used within a ContentPanelProvider');
  }
  return ctx;
}

export default ContentPanelProvider;
