/**
 * Corgi Dashboard — TelegramStatus
 * Shows Telegram channel connection status from gateway channels.status.
 */
import React, { useCallback, useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useGateway } from '../../gateway/hooks';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type TelegramConnectionStatus = 'connected' | 'disconnected' | 'unconfigured' | 'loading';

export interface TelegramInfo {
  status: TelegramConnectionStatus;
  botUsername?: string;
  lastMessageAt?: string;
  lastMessageRelative?: string;
}

interface UseTelegramStatusReturn {
  info: TelegramInfo;
  refresh: () => void;
}

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

export function useTelegramStatus(): UseTelegramStatusReturn {
  const { client } = useGateway();
  const [info, setInfo] = useState<TelegramInfo>({ status: 'loading' });

  const fetchStatus = useCallback(async () => {
    if (!client) {
      setInfo({ status: 'loading' });
      return;
    }
    try {
      const res = await client.request<{
        channels?: Record<string, { connected?: boolean; username?: string; lastMessageAt?: string; configured?: boolean }>;
        telegram?: { connected?: boolean; username?: string; lastMessageAt?: string; configured?: boolean };
      }>('channels.status');

      // Support both shapes: { telegram: {...} } or { channels: { telegram: {...} } }
      const tg = res?.telegram ?? res?.channels?.telegram;

      if (!tg) {
        setInfo({ status: 'unconfigured' });
        return;
      }

      if (!tg.configured && !tg.connected) {
        setInfo({ status: 'unconfigured' });
        return;
      }

      const connected = tg.connected ?? false;
      const lastMessageRelative = tg.lastMessageAt
        ? relAgo(Date.now() - new Date(tg.lastMessageAt).getTime())
        : undefined;

      setInfo({
        status: connected ? 'connected' : 'disconnected',
        botUsername: tg.username,
        lastMessageAt: tg.lastMessageAt,
        lastMessageRelative,
      });
    } catch {
      setInfo({ status: 'disconnected' });
    }
  }, [client]);

  useEffect(() => {
    fetchStatus();
    const t = setInterval(fetchStatus, 30_000);
    return () => clearInterval(t);
  }, [fetchStatus]);

  return { info, refresh: fetchStatus };
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function relAgo(ms: number): string {
  const secs = Math.floor(ms / 1000);
  if (secs < 60) return `${secs}s ago`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  return `${hrs}h ago`;
}

const STATUS_DOT: Record<TelegramConnectionStatus, string> = {
  connected: 'var(--info)',
  disconnected: 'var(--error)',
  unconfigured: 'var(--text-muted)',
  loading: 'var(--text-muted)',
};

const STATUS_LABEL: Record<TelegramConnectionStatus, string> = {
  connected: 'TG',
  disconnected: 'TG off',
  unconfigured: 'TG —',
  loading: 'TG…',
};

/* ------------------------------------------------------------------ */
/*  TelegramStatus Component                                           */
/* ------------------------------------------------------------------ */

export interface TelegramStatusProps {
  showTooltip?: boolean;
  compact?: boolean;
  className?: string;
  style?: React.CSSProperties;
}

export const TelegramStatus: React.FC<TelegramStatusProps> = ({
  showTooltip = true,
  compact = false,
  className = '',
  style,
}) => {
  const { info } = useTelegramStatus();
  const [tooltipVisible, setTooltipVisible] = useState(false);
  const dotColor = STATUS_DOT[info.status];
  const label = STATUS_LABEL[info.status];

  return (
    <div
      className={`flex items-center gap-1.5 ${className}`}
      style={{ position: 'relative', userSelect: 'none', cursor: 'default', ...style }}
      onMouseEnter={() => showTooltip && setTooltipVisible(true)}
      onMouseLeave={() => setTooltipVisible(false)}
    >
      {/* Status dot */}
      <motion.div
        style={{
          width: 6,
          height: 6,
          borderRadius: 'var(--radius-full)',
          background: dotColor,
          flexShrink: 0,
        }}
        animate={
          info.status === 'connected'
            ? { scale: [1, 1.3, 1] }
            : info.status === 'loading'
            ? { opacity: [1, 0.3, 1] }
            : {}
        }
        transition={
          info.status === 'connected'
            ? { duration: 3, repeat: Infinity, ease: 'easeInOut' }
            : info.status === 'loading'
            ? { duration: 1, repeat: Infinity }
            : {}
        }
      />

      {/* Label */}
      <span
        style={{
          fontSize: 'var(--text-xs)',
          color:
            info.status === 'connected'
              ? 'var(--info)'
              : info.status === 'disconnected'
              ? 'var(--error)'
              : 'var(--text-muted)',
          whiteSpace: 'nowrap',
        }}
      >
        {compact ? label : info.status === 'connected' && info.botUsername ? `@${info.botUsername}` : label}
      </span>

      {/* Tooltip */}
      <AnimatePresence>
        {tooltipVisible && (
          <motion.div
            initial={{ opacity: 0, y: 4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 4 }}
            transition={{ duration: 0.12 }}
            style={{
              position: 'absolute',
              bottom: 'calc(100% + 6px)',
              left: 0,
              background: 'var(--bg-tertiary)',
              border: '1px solid var(--border-default)',
              borderRadius: 'var(--radius-md)',
              padding: 'var(--space-2) var(--space-3)',
              fontSize: 'var(--text-xs)',
              color: 'var(--text-secondary)',
              whiteSpace: 'nowrap',
              boxShadow: 'var(--shadow-medium)',
              zIndex: 'var(--z-tooltip)',
              pointerEvents: 'none',
              minWidth: 160,
            }}
          >
            <div style={{ fontWeight: 'var(--font-semibold)', color: 'var(--text-primary)', marginBottom: 4 }}>
              Telegram
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
              <div>
                <span style={{ color: 'var(--text-muted)' }}>Status: </span>
                <span style={{ color: dotColor, textTransform: 'capitalize' }}>
                  {info.status === 'unconfigured' ? 'Not configured' : info.status}
                </span>
              </div>
              {info.botUsername && (
                <div>
                  <span style={{ color: 'var(--text-muted)' }}>Bot: </span>
                  <span>@{info.botUsername}</span>
                </div>
              )}
              {info.lastMessageRelative && (
                <div>
                  <span style={{ color: 'var(--text-muted)' }}>Last msg: </span>
                  <span>{info.lastMessageRelative}</span>
                </div>
              )}
              {info.status === 'unconfigured' && (
                <a
                  href="/settings/channels"
                  style={{ color: 'var(--accent-primary)', textDecoration: 'underline', pointerEvents: 'all' }}
                >
                  Configure →
                </a>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default TelegramStatus;
