/**
 * AnsiParser — Parses ANSI escape codes into styled React elements.
 *
 * Supports SGR (Select Graphic Rendition):
 *   - Bold, dim, italic, underline, reset
 *   - 8 standard colors + bright variants (fg & bg)
 */
import React from 'react';

/* ------------------------------------------------------------------ */
/*  Colour tables                                                      */
/* ------------------------------------------------------------------ */

const FG_COLORS: Record<number, string> = {
  30: '#4e4e4e', // black
  31: '#ff5f56', // red
  32: '#5af78e', // green
  33: '#f3f99d', // yellow
  34: '#57c7ff', // blue
  35: '#ff6ac1', // magenta
  36: '#9aedfe', // cyan
  37: '#f1f1f0', // white
  // bright
  90: '#686868',
  91: '#ff6e67',
  92: '#5af78e',
  93: '#f4f99d',
  94: '#6cbeff',
  95: '#ff77d8',
  96: '#9aedfe',
  97: '#ffffff',
};

const BG_COLORS: Record<number, string> = {
  40: '#4e4e4e',
  41: '#ff5f56',
  42: '#5af78e',
  43: '#f3f99d',
  44: '#57c7ff',
  45: '#ff6ac1',
  46: '#9aedfe',
  47: '#f1f1f0',
  100: '#686868',
  101: '#ff6e67',
  102: '#5af78e',
  103: '#f4f99d',
  104: '#6cbeff',
  105: '#ff77d8',
  106: '#9aedfe',
  107: '#ffffff',
};

/* ------------------------------------------------------------------ */
/*  Style state                                                        */
/* ------------------------------------------------------------------ */

interface AnsiStyle {
  bold: boolean;
  dim: boolean;
  italic: boolean;
  underline: boolean;
  color?: string;
  bgColor?: string;
}

function emptyStyle(): AnsiStyle {
  return { bold: false, dim: false, italic: false, underline: false };
}

function applyCode(style: AnsiStyle, code: number): AnsiStyle {
  const s = { ...style };
  if (code === 0) return emptyStyle();
  if (code === 1) s.bold = true;
  else if (code === 2) s.dim = true;
  else if (code === 3) s.italic = true;
  else if (code === 4) s.underline = true;
  else if (code === 22) { s.bold = false; s.dim = false; }
  else if (code === 23) s.italic = false;
  else if (code === 24) s.underline = false;
  else if (code === 39) s.color = undefined;
  else if (code === 49) s.bgColor = undefined;
  else if (FG_COLORS[code]) s.color = FG_COLORS[code];
  else if (BG_COLORS[code]) s.bgColor = BG_COLORS[code];
  return s;
}

function styleToCSS(style: AnsiStyle): React.CSSProperties | undefined {
  const css: React.CSSProperties = {};
  let hasStyle = false;
  if (style.bold) { css.fontWeight = 'bold'; hasStyle = true; }
  if (style.dim) { css.opacity = 0.6; hasStyle = true; }
  if (style.italic) { css.fontStyle = 'italic'; hasStyle = true; }
  if (style.underline) { css.textDecoration = 'underline'; hasStyle = true; }
  if (style.color) { css.color = style.color; hasStyle = true; }
  if (style.bgColor) { css.backgroundColor = style.bgColor; hasStyle = true; }
  return hasStyle ? css : undefined;
}

/* ------------------------------------------------------------------ */
/*  Parser                                                             */
/* ------------------------------------------------------------------ */

// eslint-disable-next-line no-control-regex
const ANSI_RE = /\x1b\[([0-9;]*)m/g;

export interface AnsiSpan {
  text: string;
  style: React.CSSProperties | undefined;
}

/** Parse a raw string with ANSI codes into an array of styled spans. */
export function parseAnsi(raw: string): AnsiSpan[] {
  const spans: AnsiSpan[] = [];
  let style = emptyStyle();
  let lastIndex = 0;

  ANSI_RE.lastIndex = 0;
  let match: RegExpExecArray | null;

  while ((match = ANSI_RE.exec(raw)) !== null) {
    // Text before this escape
    if (match.index > lastIndex) {
      spans.push({ text: raw.slice(lastIndex, match.index), style: styleToCSS(style) });
    }
    // Apply codes
    const codes = match[1].split(';').map(Number);
    for (const code of codes) {
      style = applyCode(style, code);
    }
    lastIndex = ANSI_RE.lastIndex;
  }

  // Remaining text
  if (lastIndex < raw.length) {
    spans.push({ text: raw.slice(lastIndex), style: styleToCSS(style) });
  }

  return spans;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

interface AnsiTextProps {
  text: string;
  className?: string;
}

/** Renders ANSI-escaped text as styled spans. */
const AnsiText: React.FC<AnsiTextProps> = React.memo(({ text, className }) => {
  const spans = parseAnsi(text);

  return (
    <span className={className}>
      {spans.map((span, i) =>
        span.style ? (
          <span key={i} style={span.style}>
            {span.text}
          </span>
        ) : (
          <React.Fragment key={i}>{span.text}</React.Fragment>
        ),
      )}
    </span>
  );
});

AnsiText.displayName = 'AnsiText';

export default AnsiText;
