/**
 * ThinkingToggle — Global toggle for showing/hiding thinking blocks.
 *
 * Provides ThinkingContext that other components consume to decide
 * whether to render thinking/reasoning content.
 */
import {
  createContext,
  useContext,
  useState,
  useCallback,
  useEffect,
  type ReactNode,
} from 'react';
import { Brain } from 'lucide-react';
import * as Tooltip from '@radix-ui/react-tooltip';

// ─── Context ───────────────────────────────────────────────────────────────

interface ThinkingContextValue {
  showThinking: boolean;
  toggleThinking: () => void;
}

const ThinkingContext = createContext<ThinkingContextValue>({
  showThinking: true,
  toggleThinking: () => {},
});

const STORAGE_KEY = 'corgi-show-thinking';

export function ThinkingProvider({ children }: { children: ReactNode }) {
  const [showThinking, setShowThinking] = useState<boolean>(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      return stored !== null ? stored === 'true' : true;
    } catch {
      return true;
    }
  });

  const toggleThinking = useCallback(() => {
    setShowThinking((prev) => {
      const next = !prev;
      try {
        localStorage.setItem(STORAGE_KEY, String(next));
      } catch {
        // Storage full or unavailable
      }
      return next;
    });
  }, []);

  return (
    <ThinkingContext.Provider value={{ showThinking, toggleThinking }}>
      {children}
    </ThinkingContext.Provider>
  );
}

export function useThinkingContext(): ThinkingContextValue {
  return useContext(ThinkingContext);
}

// ─── Toggle Button ─────────────────────────────────────────────────────────

export function ThinkingToggleButton() {
  const { showThinking, toggleThinking } = useThinkingContext();

  return (
    <Tooltip.Provider delayDuration={300}>
      <Tooltip.Root>
        <Tooltip.Trigger asChild>
          <button
            onClick={toggleThinking}
            className="flex items-center justify-center rounded-md p-1.5 transition-all"
            style={{
              width: '32px',
              height: '32px',
              background: showThinking
                ? 'var(--accent-muted)'
                : 'transparent',
              color: showThinking
                ? 'var(--accent-primary)'
                : 'var(--text-muted)',
              border: '1px solid',
              borderColor: showThinking
                ? 'var(--accent-primary)'
                : 'var(--border-subtle)',
              cursor: 'pointer',
              transition: 'all var(--transition-fast)',
            }}
            aria-label={showThinking ? 'Hide reasoning' : 'Show reasoning'}
          >
            <Brain size={16} />
          </button>
        </Tooltip.Trigger>
        <Tooltip.Portal>
          <Tooltip.Content
            side="top"
            sideOffset={6}
            className="rounded-md px-2.5 py-1.5"
            style={{
              backgroundColor: 'var(--bg-tertiary)',
              color: 'var(--text-primary)',
              fontSize: 'var(--text-xs)',
              fontFamily: 'var(--font-sans)',
              border: '1px solid var(--border-subtle)',
              boxShadow: 'var(--shadow-medium)',
              zIndex: 'var(--z-tooltip)',
            }}
          >
            {showThinking ? 'Hide reasoning' : 'Show reasoning'}
            <Tooltip.Arrow
              style={{ fill: 'var(--bg-tertiary)' }}
            />
          </Tooltip.Content>
        </Tooltip.Portal>
      </Tooltip.Root>
    </Tooltip.Provider>
  );
}

export default ThinkingToggleButton;
