/**
 * ScrollToBottom — Floating button that appears when user scrolls up.
 */
import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowDown } from 'lucide-react';

interface ScrollToBottomProps {
  visible: boolean;
  unreadCount?: number;
  onClick: () => void;
}

const ScrollToBottom: React.FC<ScrollToBottomProps> = React.memo(({ visible, unreadCount = 0, onClick }) => {
  return (
    <AnimatePresence>
      {visible && (
        <motion.button
          className="absolute bottom-24 right-6 flex items-center gap-1.5 px-3 py-2 rounded-full shadow-lg transition-colors"
          style={{
            background: 'var(--bg-secondary)',
            border: '1px solid var(--border-default)',
            color: 'var(--text-primary)',
            zIndex: 'var(--z-sticky)',
            boxShadow: 'var(--shadow-medium)',
            transitionDuration: 'var(--duration-normal)',
          }}
          onClick={onClick}
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 20, opacity: 0 }}
          transition={{ duration: 0.2, ease: [0.16, 1, 0.3, 1] }}
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          aria-label="Scroll to bottom"
        >
          <ArrowDown size={16} />
          {unreadCount > 0 && (
            <span
              className="text-xs font-medium px-1.5 py-0.5 rounded-full"
              style={{
                background: 'var(--accent-primary)',
                color: 'var(--text-inverse)',
              }}
            >
              {unreadCount}
            </span>
          )}
        </motion.button>
      )}
    </AnimatePresence>
  );
});

ScrollToBottom.displayName = 'ScrollToBottom';

export default ScrollToBottom;
