/**
 * Corgi Dashboard — AppShell Layout (Wired)
 */
import React, { Suspense, useEffect, useMemo } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { useResponsive } from './ResponsiveProvider';
import { BottomSheet } from './BottomSheet';
import { Header } from './Header';
import { SessionSidebar } from '../sessions/SessionSidebar';
import { ChatContainer } from '../chat';
import { ChatErrorBoundary } from '../chat/ChatErrorBoundary';
import { SubAgentPanel } from '../agents/SubAgentPanel';
import { SubAgentSummary } from '../agents/SubAgentSummary';
import { useSubAgents } from '../agents/useSubAgents';
import { StatusBarEnhanced } from '../dashboard/StatusBarEnhanced';
import { SidePanel } from '../panels/SidePanel';
import { useContentPanel } from '../panels/ContentPanelManager';
const WebPagePanel = React.lazy(() => import('../panels/WebPagePanel'));
const ImageGallery = React.lazy(() => import('../panels/ImageGallery'));
const PdfViewer = React.lazy(() => import('../panels/PdfViewer'));
const CanvasPanel = React.lazy(() => import('../panels/CanvasPanel'));
import CommandPalette from '../productivity/CommandPalette';
import KeyboardShortcuts from '../productivity/KeyboardShortcuts';
import { useCommandPalette } from '../productivity/CommandPaletteProvider';
import ExecApprovalCard from '../chat/tools/ExecApprovalCard';
import SettingsPanel from './SettingsPanel';
import { useGateway, useSessions, useStatus, useApprovals } from '../../gateway';
import { useAppStore } from '../../stores/app-store';
import { applyTheme } from '../../utils/theme';
import type { ShortcutDef } from '../productivity/KeyboardShortcuts';
import { slideInRight } from '../../theme/animations';

/* ------------------------------------------------------------------ */
/*  Content Panel Renderer                                             */
/* ------------------------------------------------------------------ */

const ContentPanelRenderer: React.FC = () => {
  const { panelType, panelContent, closePanel } = useContentPanel();

  if (!panelType || !panelContent) return null;

  const panelTitle =
    panelType === 'webpage' ? 'Web Page' :
    panelType === 'image-gallery' ? 'Images' :
    panelType === 'pdf' ? 'PDF' :
    panelType === 'canvas' ? 'Canvas' : 'Content';

  return (
    <SidePanel open={!!panelType} onClose={closePanel} title={panelTitle}>
      <Suspense fallback={<div style={{ padding: 16, color: 'var(--text-muted)' }}>Loading…</div>}>
        {panelType === 'webpage' && <WebPagePanel />}
        {panelType === 'image-gallery' && <ImageGallery />}
        {panelType === 'pdf' && <PdfViewer />}
        {panelType === 'canvas' && <CanvasPanel />}
      </Suspense>
    </SidePanel>
  );
};

/* ------------------------------------------------------------------ */
/*  Inner Shell (needs responsive context)                             */
/* ------------------------------------------------------------------ */

interface AppShellInnerProps {
  children?: React.ReactNode;
}

const AppShellInner: React.FC<AppShellInnerProps> = ({ children }) => {
  const { isMobile } = useResponsive();
  const { theme, cycleTheme, sidebarOpen, setSidebarOpen, settingsOpen, setSettingsOpen } = useAppStore();

  // Gateway
  const { connectionStatus, connect } = useGateway();
  const { activeSessionKey, sessions } = useSessions();
  const { status } = useStatus();

  // Sub-agents
  const subAgents = useSubAgents();

  // Exec approvals
  const { approvals, resolve: resolveApproval } = useApprovals();

  // Command palette
  const { open: openPalette } = useCommandPalette();

  // Apply theme reactively
  useEffect(() => { applyTheme(theme); }, [theme]);

  // Auto-connect on mount
  useEffect(() => {
    const { gatewayUrl, gatewayToken } = useAppStore.getState();
    if (gatewayUrl && connectionStatus === 'disconnected') {
      connect(gatewayUrl, { token: gatewayToken || undefined });
    }
  }, [connect, connectionStatus]);

  // Derive session key
  const sessionKey = activeSessionKey ?? sessions[0]?.key ?? 'default';
  const activeSession = sessions.find((s) => s.key === sessionKey);
  const modelName = status?.version ?? 'claude-opus-4';

  // Keyboard shortcuts
  const shortcuts = useMemo<ShortcutDef[]>(() => [
    { id: 'palette', keys: 'mod+k', description: 'Command palette', category: 'General', action: openPalette },
    { id: 'sidebar', keys: 'mod+b', description: 'Toggle sidebar', category: 'Navigation', action: () => setSidebarOpen(!sidebarOpen) },
    { id: 'settings', keys: 'mod+,', description: 'Settings', category: 'General', action: () => setSettingsOpen(true) },
  ], [openPalette, sidebarOpen, setSidebarOpen, setSettingsOpen]);

  // Connection status for header
  const headerConnectionStatus =
    connectionStatus === 'connected' ? 'connected' as const :
    connectionStatus === 'connecting' || connectionStatus === 'reconnecting' ? 'reconnecting' as const :
    'disconnected' as const;

  return (
    <div
      style={{
        display: 'grid',
        gridTemplateRows: 'var(--header-height, 48px) 1fr var(--statusbar-height, 28px)',
        width: '100vw',
        height: '100vh',
        overflow: 'hidden',
        background: 'var(--bg-primary)',
        color: 'var(--text-primary)',
      }}
    >
      {/* Row 1: Header */}
      <Header
        connectionStatus={headerConnectionStatus}
        sessionName={activeSession?.label ?? activeSession?.derivedTitle ?? activeSession?.key ?? 'Main Session'}
        theme={theme}
        onThemeToggle={cycleTheme}
        onSessionPickerClick={() => setSidebarOpen(!sidebarOpen)}
        onSettingsClick={() => setSettingsOpen(true)}
      />

      {/* Row 2: Main content area */}
      <div style={{ display: 'flex', overflow: 'hidden', position: 'relative' }}>
        {/* Desktop: fixed always-visible sidebar */}
        {!isMobile && (
          <SessionSidebar
            variant="fixed"
            onNewChat={undefined}
          />
        )}

        {/* Mobile: slide-in overlay via bottom sheet */}
        {isMobile && (
          <BottomSheet
            open={sidebarOpen}
            onClose={() => setSidebarOpen(false)}
            title="Chats"
          >
            <SessionSidebar
              variant="overlay"
              isOpen={sidebarOpen}
              onClose={() => setSidebarOpen(false)}
            />
          </BottomSheet>
        )}

        {/* Chat area */}
        <main className="flex-1 overflow-hidden flex flex-col" style={{ minWidth: 0 }}>
          {/* Sub-agent summary bar */}
          {subAgents.totalCount > 0 && (
            <SubAgentSummary
              totalCount={subAgents.totalCount}
              runningCount={subAgents.runningCount}
              completedCount={subAgents.completedCount}
              failedCount={subAgents.failedCount}
              pendingCount={subAgents.pendingCount}
              onClick={subAgents.toggle}
            />
          )}

          {children ?? (
            <ChatErrorBoundary sessionKey={sessionKey}>
              <ChatContainer sessionKey={sessionKey} modelName={modelName} />
            </ChatErrorBoundary>
          )}
        </main>

        {/* Sub-agent panel (right side, desktop) */}
        <AnimatePresence>
          {subAgents.isVisible && !isMobile && (
            <motion.aside
              key="subagent-panel"
              variants={slideInRight}
              initial="hidden"
              animate="visible"
              exit="exit"
              style={{
                width: 'clamp(280px, 25vw, 420px)',
                background: 'var(--bg-secondary)',
                borderLeft: '1px solid var(--border-subtle)',
                overflow: 'hidden',
                display: 'flex',
                flexDirection: 'column',
              }}
            >
              <SubAgentPanel state={subAgents} />
            </motion.aside>
          )}
        </AnimatePresence>

        {/* Sub-agent panel (mobile: bottom sheet) */}
        {isMobile && subAgents.isVisible && (
          <BottomSheet
            open={subAgents.isVisible}
            onClose={subAgents.toggle}
            title="Sub-agents"
          >
            <SubAgentPanel state={subAgents} />
          </BottomSheet>
        )}

        {/* Content panel (side panel for webpages, images, PDFs) */}
        <ContentPanelRenderer />
      </div>

      {/* Row 3: Enhanced Status Bar */}
      <StatusBarEnhanced modelName={modelName} />

      {/* Settings panel overlay */}
      <AnimatePresence>
        {settingsOpen && (
          <>
            {/* Backdrop */}
            <motion.div
              key="settings-backdrop"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setSettingsOpen(false)}
              style={{
                position: 'fixed',
                inset: 0,
                background: 'rgba(0,0,0,0.5)',
                zIndex: 70,
              }}
            />
            {/* Panel */}
            <motion.div
              key="settings-panel"
              initial={{ x: '100%' }}
              animate={{ x: 0 }}
              exit={{ x: '100%' }}
              transition={{ type: 'spring', damping: 30, stiffness: 300 }}
              style={{
                position: 'fixed',
                top: 0,
                right: 0,
                bottom: 0,
                width: isMobile ? '100%' : 'clamp(360px, 30vw, 480px)',
                background: 'var(--bg-primary)',
                borderLeft: '1px solid var(--border-subtle)',
                zIndex: 71,
                display: 'flex',
                flexDirection: 'column',
                overflow: 'hidden',
              }}
            >
              <SettingsPanel onClose={() => setSettingsOpen(false)} />
            </motion.div>
          </>
        )}
      </AnimatePresence>

      {/* Floating elements */}
      <CommandPalette />
      <KeyboardShortcuts shortcuts={shortcuts} />

      {/* Exec approval overlay — fixed bottom-right */}
      {approvals.length > 0 && (
        <div
          style={{
            position: 'fixed',
            bottom: 40,
            right: 16,
            zIndex: 60,
            display: 'flex',
            flexDirection: 'column',
            gap: 8,
            maxWidth: 420,
            width: '100%',
          }}
        >
          {approvals.map((a) => (
            <ExecApprovalCard
              key={a.id}
              approval={a}
              onResolve={(id, decision) => resolveApproval(id, decision)}
            />
          ))}
        </div>
      )}
    </div>
  );
};

/* ------------------------------------------------------------------ */
/*  Public AppShell                                                    */
/* ------------------------------------------------------------------ */

export const AppShell: React.FC<{ children?: React.ReactNode }> = ({ children }) => (
  <AppShellInner>{children}</AppShellInner>
);

export default AppShell;
