import type { ChatMessage, ChatContent } from './types';

/**
 * Generate a UUID v4. Uses crypto.randomUUID where available,
 * falls back to a Math.random polyfill.
 */
export function generateUUID(): string {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  // RFC 4122 v4 fallback
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

/**
 * Extract all text from a ChatMessage's content blocks.
 */
export function extractText(message: ChatMessage): string {
  if (typeof message.content === 'string') return message.content;
  if (!Array.isArray(message.content)) return '';
  return message.content
    .filter((b): b is { type: 'text'; text: string } => b.type === 'text')
    .map((b) => b.text)
    .join('');
}

/**
 * Extract thinking text from a ChatMessage's content blocks.
 */
export function extractThinking(message: ChatMessage): string {
  if (typeof message.content === 'string') return '';
  if (!Array.isArray(message.content)) return '';
  return message.content
    .filter((b): b is { type: 'thinking'; thinking: string } => b.type === 'thinking')
    .map((b) => b.thinking)
    .join('');
}

const NO_REPLY_PATTERN = /^\s*NO[_\-\s]?REPLY\s*$/i;

/**
 * Check if a text is a silent NO_REPLY message.
 */
export function isSilentReply(text: string): boolean {
  return NO_REPLY_PATTERN.test(text.trim());
}

const MAX_TOOL_OUTPUT_LENGTH = 120_000;

/**
 * Format a tool result value for display, truncating at 120K chars.
 */
export function formatToolOutput(value: unknown): string {
  if (value === undefined || value === null) return '';
  const str = typeof value === 'string' ? value : JSON.stringify(value, null, 2);
  if (str.length > MAX_TOOL_OUTPUT_LENGTH) {
    return str.slice(0, MAX_TOOL_OUTPUT_LENGTH) + '\n… [truncated]';
  }
  return str;
}

/**
 * Detect sub-agent sessions by key pattern.
 */
export function isSubAgentSession(sessionKey: string): boolean {
  return sessionKey.includes('subagent:');
}

/**
 * Parse an incoming WebSocket message into a typed frame, or null on failure.
 */
export function parseFrame(data: string): { type: string; [key: string]: unknown } | null {
  try {
    const parsed = JSON.parse(data);
    if (parsed && typeof parsed === 'object' && typeof parsed.type === 'string') {
      return parsed;
    }
    return null;
  } catch {
    return null;
  }
}

/**
 * Normalise ChatMessage content to always be an array of content blocks.
 */
export function normaliseContent(content: ChatContent[] | string): ChatContent[] {
  if (typeof content === 'string') {
    return [{ type: 'text', text: content }];
  }
  return content;
}
