/**
 * Corgi Dashboard — AgentCard
 *
 * Detail card for a single sub-agent. Shows status, timing, tokens,
 * and a steering input for running agents.
 */
import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { staggerItem } from '../../theme/animations';
import type { SubAgentInfo, AgentStatus } from './SubAgentFilter';
import { AgentSteering } from './AgentSteering';

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

const STATUS_CONFIG: Record<AgentStatus, { icon: string; label: string; color: string }> = {
  pending: { icon: '⏳', label: 'Pending', color: 'var(--text-muted)' },
  running: { icon: '🔄', label: 'Running', color: 'var(--status-warning)' },
  complete: { icon: '✅', label: 'Complete', color: 'var(--status-success)' },
  failed: { icon: '❌', label: 'Failed', color: 'var(--status-error)' },
};

const BORDER_COLORS: Record<AgentStatus, string> = {
  pending: 'var(--border-subtle)',
  running: 'var(--status-warning)',
  complete: 'var(--status-success)',
  failed: 'var(--status-error)',
};

function formatElapsed(ms: number): string {
  if (ms < 1000) return '<1s';
  const totalSec = Math.floor(ms / 1000);
  if (totalSec < 60) return `${totalSec}s`;
  const min = Math.floor(totalSec / 60);
  const sec = totalSec % 60;
  if (min < 60) return `${min}m ${sec}s`;
  const hr = Math.floor(min / 60);
  return `${hr}h ${min % 60}m`;
}

function formatTime(ts: number): string {
  return new Date(ts).toLocaleTimeString(undefined, {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });
}

/* ------------------------------------------------------------------ */
/*  Props                                                              */
/* ------------------------------------------------------------------ */

interface AgentCardProps {
  agent: SubAgentInfo;
  onClose?: () => void;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const AgentCard: React.FC<AgentCardProps> = ({ agent, onClose }) => {
  const { session, status, label, startedAt, elapsedMs } = agent;
  const cfg = STATUS_CONFIG[status];

  // Live elapsed timer for running agents
  const [liveElapsed, setLiveElapsed] = useState(elapsedMs);

  useEffect(() => {
    if (status !== 'running' || !startedAt) {
      setLiveElapsed(elapsedMs);
      return;
    }

    const tick = () => setLiveElapsed(Date.now() - startedAt);
    tick();
    const interval = setInterval(tick, 1000);
    return () => clearInterval(interval);
  }, [status, startedAt, elapsedMs]);

  return (
    <motion.div
      variants={staggerItem}
      initial="hidden"
      animate="visible"
      style={{
        background: 'var(--bg-tertiary)',
        borderRadius: 'var(--radius-lg)',
        borderLeft: `3px solid ${BORDER_COLORS[status]}`,
        padding: 'var(--space-3)',
        display: 'flex',
        flexDirection: 'column',
        gap: 'var(--space-2)',
      }}
    >
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)' }}>
          <span style={{ fontSize: 'var(--text-base)' }}>{cfg.icon}</span>
          <span
            style={{
              fontSize: 'var(--text-sm)',
              fontWeight: 'var(--font-semibold)',
              color: 'var(--text-primary)',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap',
              maxWidth: 180,
            }}
          >
            {label}
          </span>
        </div>
        {onClose && (
          <button
            onClick={onClose}
            style={{
              background: 'none',
              border: 'none',
              color: 'var(--text-muted)',
              cursor: 'pointer',
              fontSize: 'var(--text-sm)',
              padding: 'var(--space-1)',
              lineHeight: 1,
            }}
            aria-label="Close detail"
          >
            ✕
          </button>
        )}
      </div>

      {/* Status badge */}
      <div
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: 'var(--space-1)',
          padding: '2px var(--space-2)',
          borderRadius: 'var(--radius-full)',
          background: 'var(--bg-secondary)',
          fontSize: 'var(--text-xs)',
          color: cfg.color,
          fontWeight: 'var(--font-medium)',
          width: 'fit-content',
        }}
      >
        {cfg.label}
      </div>

      {/* Info rows */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-1)' }}>
        {/* Model */}
        {session.agentId && (
          <InfoRow label="Agent" value={session.agentId} />
        )}

        {/* Timing */}
        {startedAt && (
          <InfoRow label="Started" value={formatTime(startedAt)} />
        )}
        {liveElapsed != null && liveElapsed > 0 && (
          <InfoRow
            label={status === 'running' ? 'Elapsed' : 'Duration'}
            value={formatElapsed(liveElapsed)}
          />
        )}

        {/* Messages */}
        {session.messageCount != null && session.messageCount > 0 && (
          <InfoRow label="Messages" value={String(session.messageCount)} />
        )}

        {/* Thinking level */}
        {session.thinkingLevel && (
          <InfoRow label="Thinking" value={session.thinkingLevel} />
        )}
      </div>

      {/* Activity snippet */}
      {session.derivedTitle && (
        <div
          style={{
            fontSize: 'var(--text-xs)',
            color: 'var(--text-muted)',
            fontStyle: 'italic',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
          }}
        >
          "{session.derivedTitle}"
        </div>
      )}

      {/* Steering input for running agents */}
      {status === 'running' && (
        <div style={{ marginTop: 'var(--space-1)' }}>
          <AgentSteering sessionKey={session.key} />
        </div>
      )}
    </motion.div>
  );
};

/* ------------------------------------------------------------------ */
/*  InfoRow                                                            */
/* ------------------------------------------------------------------ */

const InfoRow: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div
    style={{
      display: 'flex',
      justifyContent: 'space-between',
      fontSize: 'var(--text-xs)',
    }}
  >
    <span style={{ color: 'var(--text-muted)' }}>{label}</span>
    <span style={{ color: 'var(--text-secondary)', fontFamily: 'var(--font-mono)' }}>{value}</span>
  </div>
);

export default AgentCard;
