/**
 * Corgi Dashboard — SubAgentPanel
 *
 * Main panel container for the sub-agent visualization.
 * Renders the AgentTree + AgentCard detail view.
 * Designed to be passed as `subAgentPanel` prop to AppShell.
 */
import React, { useCallback, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { staggerChildren } from '../../theme/animations';
import { AgentTree } from './AgentTree';
import { AgentCard } from './AgentCard';
import type { UseSubAgentsReturn } from './useSubAgents';

/* ------------------------------------------------------------------ */
/*  Props                                                              */
/* ------------------------------------------------------------------ */

interface SubAgentPanelProps {
  /** The return value of useSubAgents() — passed down from the parent. */
  state: UseSubAgentsReturn;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const SubAgentPanel: React.FC<SubAgentPanelProps> = ({ state }) => {
  const {
    subAgents,
    hasActive,
    totalCount,
    runningCount,
    completedCount,
    failedCount,
    pendingCount,
    selectedAgent,
    selectAgent,
    hide,
  } = state;

  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        gap: 'var(--space-3)',
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          flexShrink: 0,
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)' }}>
          <span style={{ fontSize: 'var(--text-base)' }}>🌳</span>
          <span
            style={{
              fontSize: 'var(--text-sm)',
              fontWeight: 'var(--font-semibold)',
              color: 'var(--text-primary)',
            }}
          >
            Agents
          </span>
          {totalCount > 0 && (
            <span
              style={{
                fontSize: 'var(--text-xs)',
                color: 'var(--text-muted)',
                background: 'var(--bg-primary)',
                padding: '1px 6px',
                borderRadius: 'var(--radius-full)',
              }}
            >
              {totalCount}
            </span>
          )}
        </div>
        <button
          onClick={hide}
          style={{
            background: 'none',
            border: 'none',
            color: 'var(--text-muted)',
            cursor: 'pointer',
            fontSize: 'var(--text-sm)',
            padding: 'var(--space-1)',
            lineHeight: 1,
            borderRadius: 'var(--radius-sm)',
            transition: 'color 0.15s',
          }}
          onMouseEnter={(e) => { e.currentTarget.style.color = 'var(--text-primary)'; }}
          onMouseLeave={(e) => { e.currentTarget.style.color = 'var(--text-muted)'; }}
          aria-label="Close panel"
        >
          ✕
        </button>
      </div>

      {/* Status summary */}
      <div
        style={{
          display: 'flex',
          gap: 'var(--space-3)',
          fontSize: 'var(--text-xs)',
          color: 'var(--text-muted)',
          flexWrap: 'wrap',
        }}
      >
        {runningCount > 0 && (
          <StatusDot color="#f59e0b" label={`${runningCount} running`} />
        )}
        {pendingCount > 0 && (
          <StatusDot color="#6b7280" label={`${pendingCount} pending`} />
        )}
        {completedCount > 0 && (
          <StatusDot color="#10b981" label={`${completedCount} done`} />
        )}
        {failedCount > 0 && (
          <StatusDot color="#ef4444" label={`${failedCount} failed`} />
        )}
      </div>

      {/* Agent tree */}
      <div style={{ flexShrink: 0 }}>
        <AgentTree
          agents={subAgents}
          selectedKey={selectedAgent?.session.key ?? null}
          onSelect={(key) =>
            selectAgent(key === selectedAgent?.session.key ? null : key)
          }
        />
      </div>

      {/* Selected agent detail */}
      <AnimatePresence mode="wait">
        {selectedAgent && (
          <motion.div
            key={selectedAgent.session.key}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -8 }}
            transition={{ duration: 0.2 }}
          >
            <AgentCard
              agent={selectedAgent}
              onClose={() => selectAgent(null)}
            />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Empty state */}
      {totalCount === 0 && (
        <div
          style={{
            flex: 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: 'var(--text-muted)',
            fontSize: 'var(--text-sm)',
            textAlign: 'center',
            padding: 'var(--space-4)',
          }}
        >
          <div>
            <div style={{ fontSize: 'var(--text-lg)', marginBottom: 'var(--space-2)' }}>🪨</div>
            <div>No sub-agents active</div>
            <div style={{ fontSize: 'var(--text-xs)', marginTop: 'var(--space-1)' }}>
              They'll appear here when Brock delegates work
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ------------------------------------------------------------------ */
/*  StatusDot                                                          */
/* ------------------------------------------------------------------ */

const StatusDot: React.FC<{ color: string; label: string }> = ({ color, label }) => (
  <span style={{ display: 'flex', alignItems: 'center', gap: 3 }}>
    <span
      style={{
        width: 6,
        height: 6,
        borderRadius: '50%',
        background: color,
        display: 'inline-block',
      }}
    />
    {label}
  </span>
);

export default SubAgentPanel;
