/**
 * Corgi Dashboard — AgentSteering
 *
 * Compact input for sending steering messages to a running sub-agent.
 */
import React, { useCallback, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useChat } from '../../gateway/hooks';

/* ------------------------------------------------------------------ */
/*  Props                                                              */
/* ------------------------------------------------------------------ */

interface AgentSteeringProps {
  sessionKey: string;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const AgentSteering: React.FC<AgentSteeringProps> = ({ sessionKey }) => {
  const { send } = useChat(sessionKey);
  const [text, setText] = useState('');
  const [sending, setSending] = useState(false);
  const [flash, setFlash] = useState(false);

  const handleSend = useCallback(async () => {
    const trimmed = text.trim();
    if (!trimmed || sending) return;

    setSending(true);
    try {
      await send(trimmed);
      setText('');
      setFlash(true);
      setTimeout(() => setFlash(false), 1200);
    } catch (err) {
      console.error('[AgentSteering] send failed:', err);
    } finally {
      setSending(false);
    }
  }, [text, sending, send]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend],
  );

  return (
    <div style={{ position: 'relative' }}>
      <div
        style={{
          display: 'flex',
          gap: 'var(--space-2)',
          alignItems: 'center',
        }}
      >
        <input
          type="text"
          value={text}
          onChange={(e) => setText(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Steer this agent…"
          disabled={sending}
          style={{
            flex: 1,
            padding: 'var(--space-1) var(--space-2)',
            fontSize: 'var(--text-xs)',
            background: 'var(--bg-primary)',
            color: 'var(--text-primary)',
            border: '1px solid var(--border-subtle)',
            borderRadius: 'var(--radius-md)',
            outline: 'none',
            minWidth: 0,
            transition: 'border-color 0.15s',
          }}
          onFocus={(e) => {
            e.currentTarget.style.borderColor = 'var(--border-active)';
          }}
          onBlur={(e) => {
            e.currentTarget.style.borderColor = 'var(--border-subtle)';
          }}
        />
        <button
          onClick={handleSend}
          disabled={sending || !text.trim()}
          style={{
            padding: 'var(--space-1) var(--space-2)',
            fontSize: 'var(--text-xs)',
            fontWeight: 'var(--font-medium)',
            background: sending ? 'var(--bg-tertiary)' : 'var(--accent-primary)',
            color: sending ? 'var(--text-muted)' : 'var(--text-on-accent)',
            border: 'none',
            borderRadius: 'var(--radius-md)',
            cursor: sending ? 'not-allowed' : 'pointer',
            whiteSpace: 'nowrap',
            transition: 'background 0.15s, color 0.15s',
            opacity: !text.trim() ? 0.5 : 1,
          }}
        >
          {sending ? '…' : 'Send'}
        </button>
      </div>

      {/* Confirmation flash */}
      <AnimatePresence>
        {flash && (
          <motion.div
            initial={{ opacity: 0, y: 4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -4 }}
            transition={{ duration: 0.2 }}
            style={{
              position: 'absolute',
              top: -20,
              right: 0,
              fontSize: 'var(--text-xs)',
              color: 'var(--status-success)',
            }}
          >
            ✓ Sent
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AgentSteering;
