/**
 * Corgi Dashboard — Root App Component
 *
 * Wires all providers and renders the main layout.
 * All routes render inside AppShell for consistent header/sidebar/statusbar.
 */
import React, { Suspense } from 'react';
import { BrowserRouter, Routes, Route, useOutlet } from 'react-router-dom';
import { ResponsiveProvider } from './components/layout/ResponsiveProvider';
import { CommandPaletteProvider } from './components/productivity/CommandPaletteProvider';
import { ThinkingProvider } from './components/chat/ThinkingToggle';
import { ContentPanelProvider } from './components/panels/ContentPanelManager';
import { ContextInjectionProvider } from './components/chat/ContextInjection';
import { AppShell } from './components/layout/AppShell';
import { Skeleton } from './theme/skeleton';

// ─── Lazy-loaded route components ──────────────────────────────────────────
const DashboardView = React.lazy(() => import('./components/layout/DashboardView'));
const SettingsPanel = React.lazy(() => import('./components/layout/SettingsPanel'));

// Heavy components are lazy-loaded via React.lazy in their respective call sites
// (AppShell for panels, productivity components are modals triggered on demand)

/** Layout route wrapper — renders AppShell with child route content (or null for chat default) */
function AppLayout() {
  const outlet = useOutlet();
  return <AppShell>{outlet}</AppShell>;
}

function App() {
  return (
    <ResponsiveProvider>
      <CommandPaletteProvider>
        <ThinkingProvider>
          <ContentPanelProvider>
            <ContextInjectionProvider>
              <BrowserRouter>
                <Routes>
                  <Route path="/*" element={<AppLayout />}>
                    <Route index element={null} />
                    <Route
                      path="dashboard"
                      element={
                        <Suspense fallback={<Skeleton className="w-full h-64" />}>
                          <DashboardView />
                        </Suspense>
                      }
                    />
                    <Route
                      path="settings"
                      element={
                        <Suspense fallback={<Skeleton className="w-full h-64" />}>
                          <SettingsPanel onClose={() => window.history.back()} />
                        </Suspense>
                      }
                    />
                    
                  </Route>
                </Routes>
              </BrowserRouter>
            </ContextInjectionProvider>
          </ContentPanelProvider>
        </ThinkingProvider>
      </CommandPaletteProvider>
    </ResponsiveProvider>
  );
}

export default App;
