/**
 * Corgi Dashboard — HeartbeatIndicator
 * Pulsing dot + text. Derives state from useStatus() presence/health data.
 */
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useStatus } from '../../gateway/hooks';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type HeartbeatState = 'ok' | 'checking' | 'missed';

export interface HeartbeatIndicatorProps {
  /** Show tooltip with recent heartbeat times */
  showTooltip?: boolean;
  /** Override heartbeat interval in ms (default 120_000 = 2min) */
  intervalMs?: number;
  className?: string;
  style?: React.CSSProperties;
}

/* ------------------------------------------------------------------ */
/*  Relative time                                                      */
/* ------------------------------------------------------------------ */

function relAgo(ms: number): string {
  const secs = Math.floor(ms / 1000);
  if (secs < 60) return `${secs}s ago`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  return `${hrs}h ago`;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const HeartbeatIndicator: React.FC<HeartbeatIndicatorProps> = ({
  showTooltip = true,
  intervalMs = 120_000,
  className = '',
  style,
}) => {
  const { status, health, refreshStatus } = useStatus();
  const [now, setNow] = useState(Date.now());
  const [tooltipVisible, setTooltipVisible] = useState(false);

  // Tick every 15s to keep relative time fresh
  useEffect(() => {
    const t = setInterval(() => setNow(Date.now()), 15_000);
    return () => clearInterval(t);
  }, []);

  // Poll status every intervalMs
  useEffect(() => {
    refreshStatus();
    const t = setInterval(refreshStatus, intervalMs);
    return () => clearInterval(t);
  }, [refreshStatus, intervalMs]);

  // Determine last-seen time from status/health
  const lastSeenMs = useMemo<number | null>(() => {
    // Try to extract from health or status
    if (health?.lastHeartbeat) return new Date(health.lastHeartbeat as string).getTime();
    if (status?.lastHeartbeat) return new Date(status.lastHeartbeat as string).getTime();
    // Fallback: if we got a response at all, we're alive — approximate with now
    if (status || health) return now;
    return null;
  }, [status, health, now]);

  const diffMs = lastSeenMs ? now - lastSeenMs : null;

  const heartbeatState: HeartbeatState = useMemo(() => {
    if (!lastSeenMs) return 'checking';
    const diff = now - lastSeenMs;
    if (diff < intervalMs * 2) return 'ok';
    if (diff < intervalMs * 4) return 'checking';
    return 'missed';
  }, [lastSeenMs, now, intervalMs]);

  const dotColor =
    heartbeatState === 'ok'
      ? 'var(--success)'
      : heartbeatState === 'checking'
      ? 'var(--warning)'
      : 'var(--error)';

  const label =
    heartbeatState === 'ok'
      ? `Heartbeat OK${diffMs ? ` · ${relAgo(diffMs)}` : ''}`
      : heartbeatState === 'checking'
      ? `Checking${diffMs ? ` · ${relAgo(diffMs)}` : ''}…`
      : `MISSED${diffMs ? ` · ${relAgo(diffMs)}` : ''}`;

  return (
    <div
      className={`flex items-center gap-1.5 ${className}`}
      style={{ position: 'relative', userSelect: 'none', ...style }}
      onMouseEnter={() => showTooltip && setTooltipVisible(true)}
      onMouseLeave={() => setTooltipVisible(false)}
    >
      {/* Pulsing dot */}
      <motion.div
        style={{
          width: 6,
          height: 6,
          borderRadius: 'var(--radius-full)',
          background: dotColor,
          flexShrink: 0,
        }}
        animate={
          heartbeatState === 'ok'
            ? {
                scale: [1, 1.4, 1],
                boxShadow: [
                  `0 0 0 0 ${dotColor}66`,
                  `0 0 0 5px transparent`,
                  `0 0 0 0 transparent`,
                ],
              }
            : heartbeatState === 'checking'
            ? { opacity: [1, 0.4, 1] }
            : {}
        }
        transition={
          heartbeatState === 'ok'
            ? { duration: 2, repeat: Infinity, ease: 'easeInOut' }
            : heartbeatState === 'checking'
            ? { duration: 1.2, repeat: Infinity, ease: 'easeInOut' }
            : {}
        }
      />

      {/* Label */}
      <span
        style={{
          fontSize: 'var(--text-xs)',
          color: heartbeatState === 'missed' ? 'var(--error)' : 'var(--text-muted)',
          fontWeight: heartbeatState === 'missed' ? 'var(--font-semibold)' : 'var(--font-normal)',
          whiteSpace: 'nowrap',
        }}
      >
        {label}
      </span>

      {/* Tooltip */}
      <AnimatePresence>
        {tooltipVisible && (
          <motion.div
            initial={{ opacity: 0, y: 4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 4 }}
            transition={{ duration: 0.12 }}
            style={{
              position: 'absolute',
              bottom: 'calc(100% + 6px)',
              left: 0,
              background: 'var(--bg-tertiary)',
              border: '1px solid var(--border-default)',
              borderRadius: 'var(--radius-md)',
              padding: 'var(--space-2) var(--space-3)',
              fontSize: 'var(--text-xs)',
              color: 'var(--text-secondary)',
              whiteSpace: 'nowrap',
              boxShadow: 'var(--shadow-medium)',
              zIndex: 'var(--z-tooltip)',
              pointerEvents: 'none',
              minWidth: 160,
            }}
          >
            <div style={{ fontWeight: 'var(--font-semibold)', color: 'var(--text-primary)', marginBottom: 4 }}>
              Gateway status
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
              <div>
                <span style={{ color: 'var(--text-muted)' }}>State: </span>
                <span style={{ color: dotColor }}>{heartbeatState.toUpperCase()}</span>
              </div>
              {diffMs !== null && (
                <div>
                  <span style={{ color: 'var(--text-muted)' }}>Last seen: </span>
                  <span>{relAgo(diffMs)}</span>
                </div>
              )}
              {status?.version && (
                <div>
                  <span style={{ color: 'var(--text-muted)' }}>Version: </span>
                  <span style={{ fontFamily: 'var(--font-mono)' }}>{status.version as string}</span>
                </div>
              )}
              {status?.uptime && (
                <div>
                  <span style={{ color: 'var(--text-muted)' }}>Uptime: </span>
                  <span>{Math.floor((status.uptime as number) / 60)}m</span>
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default HeartbeatIndicator;
