/**
 * ExecApprovalCard — Inline approval card for exec commands requiring authorisation.
 *
 * Shows command, working directory, agent ID.
 * Action buttons: Allow Once, Allow Always, Deny.
 * Countdown timer + resolution status.
 */
import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Shield, ShieldCheck, ShieldX, Clock, Terminal } from 'lucide-react';
import { scaleIn } from '@/theme';
import type { ExecApprovalRequest } from '@/gateway/types';

/* ------------------------------------------------------------------ */
/*  Countdown hook                                                     */
/* ------------------------------------------------------------------ */

function useCountdown(expiresAtMs: number): { remaining: number; expired: boolean } {
  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    const id = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(id);
  }, []);

  const remaining = Math.max(0, Math.ceil((expiresAtMs - now) / 1000));
  return { remaining, expired: remaining <= 0 };
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

interface ExecApprovalCardProps {
  approval: ExecApprovalRequest;
  onResolve: (id: string, decision: 'allow-once' | 'allow-always' | 'deny') => void;
}

const ExecApprovalCard: React.FC<ExecApprovalCardProps> = React.memo(
  ({ approval, onResolve }) => {
    const { remaining, expired } = useCountdown(approval.expiresAtMs);
    const [resolved, setResolved] = useState<string | null>(null);

    const handleDecision = useCallback(
      (decision: 'allow-once' | 'allow-always' | 'deny') => {
        setResolved(
          decision === 'deny'
            ? 'Denied'
            : decision === 'allow-always'
              ? 'Allowed (always)'
              : 'Approved by you',
        );
        onResolve(approval.id, decision);
      },
      [approval.id, onResolve],
    );

    // If expired and not resolved, mark as expired
    const showExpired = expired && !resolved;

    return (
      <AnimatePresence>
        {!resolved ? (
          <motion.div
            variants={scaleIn}
            initial="hidden"
            animate="visible"
            exit="exit"
            className="rounded-lg overflow-hidden my-2"
            style={{
              background: 'var(--bg-secondary)',
              border: '1px solid var(--warning)',
              borderLeft: '3px solid var(--warning)',
            }}
          >
            {/* Header */}
            <div
              className="flex items-center gap-2 px-3 py-2"
              style={{ borderBottom: '1px solid var(--border-subtle)' }}
            >
              <Shield size={16} style={{ color: 'var(--warning)', flexShrink: 0 }} />
              <span
                className="font-semibold text-sm"
                style={{ color: 'var(--warning)' }}
              >
                Exec Approval Required
              </span>
              <span className="flex-1" />
              <span className="flex items-center gap-1 text-xs font-mono" style={{ color: expired ? 'var(--error)' : 'var(--text-muted)' }}>
                <Clock size={12} />
                {showExpired ? 'Expired' : `${remaining}s`}
              </span>
            </div>

            {/* Command */}
            <div className="px-3 py-2 space-y-2">
              <div
                className="rounded px-2.5 py-2 font-mono text-sm"
                style={{
                  background: '#0d0d14',
                  border: '1px solid var(--border-subtle)',
                  fontFamily: 'var(--font-mono)',
                  fontSize: 'var(--text-sm)',
                  color: 'var(--text-primary)',
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-all',
                }}
              >
                <span style={{ color: 'var(--success)' }}>$</span>{' '}
                {approval.request.command}
              </div>

              {/* Meta */}
              <div className="flex flex-wrap gap-x-4 gap-y-1 text-xs" style={{ color: 'var(--text-muted)' }}>
                {approval.request.cwd && (
                  <span className="flex items-center gap-1">
                    <Terminal size={11} />
                    {approval.request.cwd}
                  </span>
                )}
                {approval.request.agentId && (
                  <span>agent: {approval.request.agentId}</span>
                )}
              </div>

              {/* Actions */}
              {!showExpired && (
                <div className="flex items-center gap-2 pt-1">
                  <button
                    onClick={() => handleDecision('allow-once')}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-semibold transition-colors"
                    style={{
                      background: 'var(--success-muted)',
                      color: 'var(--success)',
                      border: '1px solid var(--success)',
                    }}
                  >
                    <ShieldCheck size={13} />
                    Allow Once
                  </button>
                  <button
                    onClick={() => handleDecision('allow-always')}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-semibold transition-colors"
                    style={{
                      background: 'var(--info-muted)',
                      color: 'var(--info)',
                      border: '1px solid var(--info)',
                    }}
                  >
                    <Shield size={13} />
                    Allow Always
                  </button>
                  <button
                    onClick={() => handleDecision('deny')}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-semibold transition-colors"
                    style={{
                      background: 'var(--error-muted)',
                      color: 'var(--error)',
                      border: '1px solid var(--error)',
                    }}
                  >
                    <ShieldX size={13} />
                    Deny
                  </button>
                </div>
              )}

              {showExpired && (
                <div className="text-xs font-medium pt-1" style={{ color: 'var(--error)' }}>
                  This approval request has expired.
                </div>
              )}
            </div>
          </motion.div>
        ) : (
          <motion.div
            key="resolved"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95, transition: { delay: 1.5 } }}
            className="flex items-center gap-2 px-3 py-1.5 rounded my-1 text-xs font-medium"
            style={{
              background: resolved.includes('Denied')
                ? 'var(--error-muted)'
                : 'var(--success-muted)',
              color: resolved.includes('Denied')
                ? 'var(--error)'
                : 'var(--success)',
            }}
          >
            {resolved.includes('Denied') ? <ShieldX size={13} /> : <ShieldCheck size={13} />}
            {resolved}
          </motion.div>
        )}
      </AnimatePresence>
    );
  },
);

ExecApprovalCard.displayName = 'ExecApprovalCard';

export default ExecApprovalCard;
