/**
 * Corgi Dashboard — AgentTree
 *
 * SVG-based org chart showing the orchestrator at top
 * with sub-agent child nodes connected by curved paths.
 * Switches to compact vertical list for >6 agents.
 */
import React, { useEffect, useMemo, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { staggerChildren, staggerItem, pulseGlow } from '../../theme/animations';
import type { SubAgentInfo, AgentStatus } from './SubAgentFilter';

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const NODE_WIDTH = 140;
const NODE_HEIGHT = 56;
const ROOT_Y = 16;
const CHILD_Y = 100;
const H_GAP = 12;
const COMPACT_THRESHOLD = 6;

const STATUS_COLORS: Record<AgentStatus, string> = {
  pending: '#6b7280',   // gray
  running: '#f59e0b',   // orange/amber
  complete: '#10b981',  // green
  failed: '#ef4444',    // red
};

const STATUS_ICONS: Record<AgentStatus, string> = {
  pending: '⏳',
  running: '🔄',
  complete: '✅',
  failed: '❌',
};

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function formatElapsed(ms: number): string {
  if (ms < 1000) return '<1s';
  const s = Math.floor(ms / 1000);
  if (s < 60) return `${s}s`;
  const m = Math.floor(s / 60);
  return `${m}m ${s % 60}s`;
}

/* ------------------------------------------------------------------ */
/*  TreeNode (SVG foreign-object based)                                */
/* ------------------------------------------------------------------ */

interface TreeNodeProps {
  x: number;
  y: number;
  label: string;
  status: AgentStatus;
  elapsed?: number | null;
  isRoot?: boolean;
  selected?: boolean;
  onClick?: () => void;
}

const TreeNode: React.FC<TreeNodeProps> = ({
  x, y, label, status, elapsed, isRoot, selected, onClick,
}) => {
  const color = STATUS_COLORS[status];
  const icon = isRoot ? '🪨' : STATUS_ICONS[status];

  return (
    <g onClick={onClick} style={{ cursor: onClick ? 'pointer' : 'default' }}>
      <foreignObject x={x} y={y} width={NODE_WIDTH} height={NODE_HEIGHT}>
        <div
          style={{
            width: '100%',
            height: '100%',
            background: 'var(--bg-tertiary)',
            border: `2px solid ${selected ? 'var(--accent-primary)' : color}`,
            borderRadius: 'var(--radius-md)',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '4px 8px',
            boxShadow: status === 'running' && !isRoot
              ? `0 0 8px 2px ${color}40`
              : selected
                ? '0 0 6px 1px var(--accent-primary)'
                : 'none',
            transition: 'border-color 0.2s, box-shadow 0.3s',
            animation: status === 'running' && !isRoot ? 'subtlePulse 2s ease-in-out infinite' : 'none',
          }}
        >
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 4,
              fontSize: 'var(--text-xs)',
              fontWeight: 'var(--font-semibold)',
              color: 'var(--text-primary)',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap',
              maxWidth: NODE_WIDTH - 20,
            }}
          >
            <span>{icon}</span>
            <span style={{ overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {isRoot ? 'Brock' : label}
            </span>
          </div>
          <div
            style={{
              fontSize: 10,
              color: 'var(--text-muted)',
              marginTop: 2,
            }}
          >
            {isRoot ? 'Orchestrator' : (
              elapsed != null && elapsed > 0 ? formatElapsed(elapsed) : STATUS_ICONS[status] + ' ' + status
            )}
          </div>
        </div>
      </foreignObject>
    </g>
  );
};

/* ------------------------------------------------------------------ */
/*  Curved connector                                                   */
/* ------------------------------------------------------------------ */

const Connector: React.FC<{ x1: number; y1: number; x2: number; y2: number }> = ({
  x1, y1, x2, y2,
}) => {
  const midY = (y1 + y2) / 2;
  const d = `M ${x1} ${y1} C ${x1} ${midY}, ${x2} ${midY}, ${x2} ${y2}`;

  return (
    <path
      d={d}
      fill="none"
      stroke="var(--border-subtle)"
      strokeWidth={1.5}
      strokeLinecap="round"
    />
  );
};

/* ------------------------------------------------------------------ */
/*  CompactList (for >6 agents)                                        */
/* ------------------------------------------------------------------ */

interface CompactListProps {
  agents: SubAgentInfo[];
  selectedKey: string | null;
  onSelect: (key: string) => void;
}

const CompactList: React.FC<CompactListProps> = ({ agents, selectedKey, onSelect }) => {
  // Live elapsed ticking
  const [, setTick] = useState(0);
  useEffect(() => {
    const hasRunning = agents.some((a) => a.status === 'running');
    if (!hasRunning) return;
    const iv = setInterval(() => setTick((t) => t + 1), 1000);
    return () => clearInterval(iv);
  }, [agents]);

  return (
    <motion.div
      variants={staggerChildren}
      initial="hidden"
      animate="visible"
      style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-1)' }}
    >
      {/* Root */}
      <motion.div
        variants={staggerItem}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--space-2)',
          padding: 'var(--space-2)',
          background: 'var(--bg-tertiary)',
          borderRadius: 'var(--radius-md)',
          borderLeft: '3px solid var(--accent-primary)',
          fontSize: 'var(--text-xs)',
          fontWeight: 'var(--font-semibold)',
          color: 'var(--text-primary)',
        }}
      >
        <span>🪨</span>
        <span>Brock (Orchestrator)</span>
      </motion.div>

      {/* Children */}
      {agents.map((agent) => {
        const color = STATUS_COLORS[agent.status];
        const isSelected = agent.session.key === selectedKey;
        const elapsed =
          agent.status === 'running' && agent.startedAt
            ? Date.now() - agent.startedAt
            : agent.elapsedMs;

        return (
          <motion.div
            key={agent.session.key}
            variants={staggerItem}
            onClick={() => onSelect(agent.session.key)}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 'var(--space-2)',
              padding: 'var(--space-2)',
              paddingLeft: 'var(--space-4)',
              background: isSelected ? 'var(--bg-secondary)' : 'var(--bg-tertiary)',
              borderRadius: 'var(--radius-md)',
              borderLeft: `3px solid ${color}`,
              fontSize: 'var(--text-xs)',
              color: 'var(--text-primary)',
              cursor: 'pointer',
              transition: 'background 0.15s',
            }}
          >
            <span>{STATUS_ICONS[agent.status]}</span>
            <span
              style={{
                flex: 1,
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
            >
              {agent.label}
            </span>
            {elapsed != null && elapsed > 0 && (
              <span style={{ color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>
                {formatElapsed(elapsed)}
              </span>
            )}
          </motion.div>
        );
      })}
    </motion.div>
  );
};

/* ------------------------------------------------------------------ */
/*  Main AgentTree                                                     */
/* ------------------------------------------------------------------ */

interface AgentTreeProps {
  agents: SubAgentInfo[];
  selectedKey: string | null;
  onSelect: (key: string) => void;
}

export const AgentTree: React.FC<AgentTreeProps> = ({ agents, selectedKey, onSelect }) => {
  // Live elapsed ticking for SVG view
  const [, setTick] = useState(0);
  useEffect(() => {
    const hasRunning = agents.some((a) => a.status === 'running');
    if (!hasRunning) return;
    const iv = setInterval(() => setTick((t) => t + 1), 1000);
    return () => clearInterval(iv);
  }, [agents]);

  // Use compact list for many agents
  if (agents.length > COMPACT_THRESHOLD) {
    return <CompactList agents={agents} selectedKey={selectedKey} onSelect={onSelect} />;
  }

  // ── SVG layout calculations ─────────────────────────────

  const totalChildWidth = agents.length * NODE_WIDTH + Math.max(0, agents.length - 1) * H_GAP;
  const svgWidth = Math.max(totalChildWidth + 24, NODE_WIDTH + 24);
  const svgHeight = agents.length > 0 ? CHILD_Y + NODE_HEIGHT + 16 : ROOT_Y + NODE_HEIGHT + 16;

  const rootX = (svgWidth - NODE_WIDTH) / 2;
  const rootCenterX = rootX + NODE_WIDTH / 2;
  const rootBottomY = ROOT_Y + NODE_HEIGHT;

  const childStartX = (svgWidth - totalChildWidth) / 2;

  return (
    <div style={{ width: '100%', overflowX: 'auto', overflowY: 'hidden' }}>
      {/* Inject pulse keyframe */}
      <style>{`
        @keyframes subtlePulse {
          0%, 100% { box-shadow: 0 0 4px 1px rgba(245, 158, 11, 0.2); }
          50% { box-shadow: 0 0 10px 3px rgba(245, 158, 11, 0.35); }
        }
      `}</style>

      <svg
        width={svgWidth}
        height={svgHeight}
        viewBox={`0 0 ${svgWidth} ${svgHeight}`}
        style={{ display: 'block', margin: '0 auto' }}
      >
        {/* Connectors */}
        {agents.map((agent, i) => {
          const cx = childStartX + i * (NODE_WIDTH + H_GAP) + NODE_WIDTH / 2;
          return (
            <Connector
              key={`conn-${agent.session.key}`}
              x1={rootCenterX}
              y1={rootBottomY}
              x2={cx}
              y2={CHILD_Y}
            />
          );
        })}

        {/* Root node */}
        <TreeNode
          x={rootX}
          y={ROOT_Y}
          label="Brock"
          status="running"
          isRoot
        />

        {/* Child nodes */}
        {agents.map((agent, i) => {
          const cx = childStartX + i * (NODE_WIDTH + H_GAP);
          const elapsed =
            agent.status === 'running' && agent.startedAt
              ? Date.now() - agent.startedAt
              : agent.elapsedMs;

          return (
            <TreeNode
              key={agent.session.key}
              x={cx}
              y={CHILD_Y}
              label={agent.label}
              status={agent.status}
              elapsed={elapsed}
              selected={agent.session.key === selectedKey}
              onClick={() => onSelect(agent.session.key)}
            />
          );
        })}
      </svg>
    </div>
  );
};

export default AgentTree;
