/**
 * ToolCard — Placeholder tool call/result renderer.
 * Other agents will enhance this; we just render a basic card.
 */
import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { ChevronDown, ChevronRight } from 'lucide-react';
import { getToolMeta, toolCardExpand } from '@/theme';

interface ToolCardProps {
  name: string;
  args?: unknown;
  result?: unknown;
  phase?: 'start' | 'update' | 'result';
}

const ToolCard: React.FC<ToolCardProps> = React.memo(({ name, args, result, phase }) => {
  const [expanded, setExpanded] = useState(false);
  const { icon: Icon, color } = getToolMeta(name);
  const isComplete = phase === 'result';

  return (
    <div
      className="rounded-lg overflow-hidden my-1.5 text-sm"
      style={{
        background: 'var(--bg-tertiary)',
        border: '1px solid var(--border-subtle)',
      }}
    >
      {/* Header */}
      <button
        className="w-full flex items-center gap-2 px-3 py-2 text-left transition-colors"
        style={{ transitionDuration: 'var(--duration-normal)' }}
        onClick={() => setExpanded(!expanded)}
      >
        <Icon size={14} style={{ color }} />
        <span className="font-medium" style={{ color: 'var(--text-primary)' }}>
          {name}
        </span>
        {!isComplete && (
          <span
            className="ml-auto text-xs animate-pulse"
            style={{ color: 'var(--text-muted)' }}
          >
            running…
          </span>
        )}
        {isComplete && (
          <span className="ml-auto" style={{ color: 'var(--text-muted)' }}>
            {expanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </span>
        )}
      </button>

      {/* Expandable body */}
      {expanded && (
        <motion.div
          className="px-3 pb-2 overflow-hidden"
          variants={toolCardExpand}
          initial="collapsed"
          animate="expanded"
          exit="collapsed"
        >
          {args != null && (
            <div className="mb-2">
              <span className="text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
                Arguments
              </span>
              <pre
                className="mt-1 p-2 rounded text-xs overflow-x-auto"
                style={{
                  background: 'var(--bg-primary)',
                  color: 'var(--text-secondary)',
                  fontFamily: 'var(--font-mono)',
                  maxHeight: '200px',
                }}
              >
                {typeof args === 'string' ? args : JSON.stringify(args, null, 2)}
              </pre>
            </div>
          )}
          {result !== undefined && (
            <div>
              <span className="text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
                Result
              </span>
              <pre
                className="mt-1 p-2 rounded text-xs overflow-x-auto"
                style={{
                  background: 'var(--bg-primary)',
                  color: 'var(--text-secondary)',
                  fontFamily: 'var(--font-mono)',
                  maxHeight: '300px',
                }}
              >
                {typeof result === 'string' ? result : JSON.stringify(result, null, 2)}
              </pre>
            </div>
          )}
        </motion.div>
      )}
    </div>
  );
});

ToolCard.displayName = 'ToolCard';

export default ToolCard;
