/**
 * CodeBlock — Enhanced code block with syntax highlighting, copy, line numbers, collapse.
 */
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Check, Copy, ChevronDown, ChevronUp } from 'lucide-react';

interface CodeBlockProps {
  children: string;
  language?: string;
  /** Pre-highlighted HTML from rehype-highlight */
  html?: string;
}

const COLLAPSE_THRESHOLD = 30;
const COLLAPSE_PREVIEW_LINES = 15;
const LINE_NUMBER_THRESHOLD = 10;

const CodeBlock: React.FC<CodeBlockProps> = React.memo(({ children, language, html }) => {
  const [copied, setCopied] = useState(false);
  const [collapsed, setCollapsed] = useState(true);
  const codeRef = useRef<HTMLPreElement>(null);

  const lines = children.split('\n');
  const lineCount = lines.length;
  const isLong = lineCount > COLLAPSE_THRESHOLD;
  const showLineNumbers = lineCount > LINE_NUMBER_THRESHOLD;

  const displayLines = isLong && collapsed ? lines.slice(0, COLLAPSE_PREVIEW_LINES) : lines;
  const hiddenCount = isLong && collapsed ? lineCount - COLLAPSE_PREVIEW_LINES : 0;

  const handleCopy = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(children);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback
      const ta = document.createElement('textarea');
      ta.value = children;
      document.body.appendChild(ta);
      ta.select();
      document.execCommand('copy');
      document.body.removeChild(ta);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  }, [children]);

  const langLabel = language && language !== 'plaintext' ? language : null;

  return (
    <div
      className="group/code relative rounded-lg overflow-hidden my-2"
      style={{
        background: 'var(--bg-primary)',
        border: '1px solid var(--border-subtle)',
      }}
    >
      {/* Header bar */}
      {(langLabel || true) && (
        <div
          className="flex items-center justify-between px-3 py-1.5"
          style={{
            background: 'var(--bg-tertiary)',
            borderBottom: '1px solid var(--border-subtle)',
          }}
        >
          <span
            className="text-xs font-medium uppercase tracking-wide"
            style={{ color: 'var(--text-muted)' }}
          >
            {langLabel ?? 'code'}
          </span>
          <button
            onClick={handleCopy}
            className="flex items-center gap-1 px-2 py-0.5 rounded text-xs opacity-0 group-hover/code:opacity-100 transition-opacity"
            style={{
              color: copied ? 'var(--success)' : 'var(--text-secondary)',
              background: 'var(--bg-secondary)',
              transitionDuration: 'var(--duration-normal)',
            }}
            title="Copy code"
          >
            {copied ? <Check size={12} /> : <Copy size={12} />}
            {copied ? 'Copied' : 'Copy'}
          </button>
        </div>
      )}

      {/* Code body */}
      <div className="overflow-x-auto" style={{ maxHeight: '600px' }}>
        <pre
          ref={codeRef}
          className="p-3 m-0"
          style={{
            fontFamily: 'var(--font-mono)',
            fontSize: 'var(--text-sm)',
            lineHeight: 'var(--leading-snug)',
            color: 'var(--text-primary)',
          }}
        >
          {html ? (
            <code
              className={language ? `hljs language-${language}` : 'hljs'}
              dangerouslySetInnerHTML={{ __html: html }}
            />
          ) : (
            <code className={language ? `language-${language}` : ''}>
              {showLineNumbers ? (
                <table className="border-collapse w-full">
                  <tbody>
                    {displayLines.map((line, i) => (
                      <tr key={i}>
                        <td
                          className="select-none text-right pr-3 align-top"
                          style={{
                            color: 'var(--text-muted)',
                            width: '1%',
                            whiteSpace: 'nowrap',
                            userSelect: 'none',
                          }}
                        >
                          {i + 1}
                        </td>
                        <td className="pl-0" style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}>
                          {line}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              ) : (
                displayLines.join('\n')
              )}
            </code>
          )}
        </pre>
      </div>

      {/* Collapse toggle */}
      {isLong && (
        <button
          onClick={() => setCollapsed(!collapsed)}
          className="w-full flex items-center justify-center gap-1 py-1.5 text-xs font-medium transition-colors"
          style={{
            color: 'var(--accent-primary)',
            background: 'var(--bg-tertiary)',
            borderTop: '1px solid var(--border-subtle)',
            transitionDuration: 'var(--duration-normal)',
          }}
        >
          {collapsed ? (
            <>
              <ChevronDown size={14} />
              Show {hiddenCount} more lines
            </>
          ) : (
            <>
              <ChevronUp size={14} />
              Collapse
            </>
          )}
        </button>
      )}
    </div>
  );
});

CodeBlock.displayName = 'CodeBlock';

export default CodeBlock;
