/**
 * ToolArgDisplay — Renders tool arguments in a human-readable way based on tool type.
 */
import React from 'react';
import { ExternalLink } from 'lucide-react';

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function asRecord(args: unknown): Record<string, unknown> {
  if (args && typeof args === 'object' && !Array.isArray(args)) {
    return args as Record<string, unknown>;
  }
  return {};
}

function str(v: unknown): string {
  if (typeof v === 'string') return v;
  if (v == null) return '';
  return JSON.stringify(v);
}

function truncate(s: string, max: number): string {
  return s.length > max ? s.slice(0, max) + '…' : s;
}

/* ------------------------------------------------------------------ */
/*  Per-tool renderers                                                 */
/* ------------------------------------------------------------------ */

const ExecArgs: React.FC<{ args: Record<string, unknown> }> = ({ args }) => (
  <div className="space-y-1">
    {args.command != null && (
      <div
        className="px-2.5 py-1.5 rounded font-mono text-sm"
        style={{
          background: 'var(--bg-primary)',
          color: 'var(--text-primary)',
          border: '1px solid var(--border-subtle)',
          fontSize: 'var(--text-sm)',
          fontFamily: 'var(--font-mono)',
        }}
      >
        <span style={{ color: 'var(--success)' }}>$</span>{' '}
        {str(args.command)}
      </div>
    )}
    {args.workdir != null && (
      <div className="text-xs" style={{ color: 'var(--text-muted)' }}>
        in {str(args.workdir)}
      </div>
    )}
  </div>
);

const SearchArgs: React.FC<{ args: Record<string, unknown> }> = ({ args }) => (
  <div className="flex items-center gap-1.5">
    <span>🔍</span>
    <span
      className="font-medium"
      style={{ color: 'var(--text-primary)', fontSize: 'var(--text-sm)' }}
    >
      &ldquo;{str(args.query)}&rdquo;
    </span>
  </div>
);

const WebFetchArgs: React.FC<{ args: Record<string, unknown> }> = ({ args }) => (
  <div className="flex items-center gap-1.5">
    <span>🌐</span>
    <a
      href={str(args.url)}
      target="_blank"
      rel="noopener noreferrer"
      className="flex items-center gap-1 hover:underline"
      style={{ color: 'var(--info)', fontSize: 'var(--text-sm)', fontFamily: 'var(--font-mono)' }}
    >
      {truncate(str(args.url), 80)}
      <ExternalLink size={12} />
    </a>
  </div>
);

const FileArgs: React.FC<{ args: Record<string, unknown>; toolName: string }> = ({ args, toolName }) => {
  const path = str(args.file_path || args.path || args.file);
  return (
    <div className="space-y-1">
      {path && (
        <div className="flex items-center gap-1.5">
          <span>📁</span>
          <span
            className="font-mono"
            style={{ color: 'var(--text-primary)', fontSize: 'var(--text-sm)' }}
          >
            {path}
          </span>
        </div>
      )}
      {toolName === 'edit' && args.old_string != null && (
        <div
          className="mt-1.5 rounded overflow-hidden text-xs font-mono"
          style={{ border: '1px solid var(--border-subtle)' }}
        >
          <div
            className="px-2.5 py-1.5"
            style={{ background: 'rgba(255, 71, 87, 0.08)', color: '#ff6e67' }}
          >
            <span className="select-none mr-1" style={{ opacity: 0.5 }}>−</span>
            {truncate(str(args.old_string), 200)}
          </div>
          {args.new_string != null && (
            <div
              className="px-2.5 py-1.5"
              style={{
                background: 'rgba(0, 214, 143, 0.08)',
                color: '#5af78e',
                borderTop: '1px solid var(--border-subtle)',
              }}
            >
              <span className="select-none mr-1" style={{ opacity: 0.5 }}>+</span>
              {truncate(str(args.new_string), 200)}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

const BrowserArgs: React.FC<{ args: Record<string, unknown> }> = ({ args }) => (
  <div className="space-y-1">
    <div className="flex items-center gap-2" style={{ fontSize: 'var(--text-sm)' }}>
      <span
        className="px-1.5 py-0.5 rounded text-xs font-semibold uppercase"
        style={{ background: 'var(--accent-muted)', color: 'var(--accent-primary)' }}
      >
        {str(args.action || 'browse')}
      </span>
      {args.url != null && (
        <span className="font-mono" style={{ color: 'var(--text-secondary)' }}>
          {truncate(str(args.url), 60)}
        </span>
      )}
    </div>
    {args.element != null && (
      <div className="text-xs" style={{ color: 'var(--text-muted)' }}>
        element: {truncate(str(args.element), 80)}
      </div>
    )}
  </div>
);

const MessageArgs: React.FC<{ args: Record<string, unknown> }> = ({ args }) => (
  <div className="space-y-1" style={{ fontSize: 'var(--text-sm)' }}>
    <div className="flex items-center gap-1.5">
      <span>💬</span>
      {args.target != null && (
        <span className="font-medium" style={{ color: 'var(--text-primary)' }}>
          {str(args.target)}
        </span>
      )}
      {args.channel != null && (
        <span style={{ color: 'var(--text-muted)' }}>
          ({str(args.channel)})
        </span>
      )}
    </div>
    {args.message != null && (
      <div
        className="text-xs pl-5"
        style={{ color: 'var(--text-secondary)' }}
      >
        {truncate(str(args.message), 120)}
      </div>
    )}
  </div>
);

const SessionSpawnArgs: React.FC<{ args: Record<string, unknown> }> = ({ args }) => (
  <div className="space-y-1" style={{ fontSize: 'var(--text-sm)' }}>
    {args.task != null && (
      <div style={{ color: 'var(--text-primary)' }}>
        {truncate(str(args.task), 200)}
      </div>
    )}
    <div className="flex gap-3 text-xs" style={{ color: 'var(--text-muted)' }}>
      {args.model != null && <span>model: {str(args.model)}</span>}
      {args.mode != null && <span>mode: {str(args.mode)}</span>}
    </div>
  </div>
);

/* ------------------------------------------------------------------ */
/*  Generic fallback: key-value pairs                                  */
/* ------------------------------------------------------------------ */

const GenericArgs: React.FC<{ args: Record<string, unknown> }> = ({ args }) => {
  const entries = Object.entries(args).filter(
    ([, v]) => v !== undefined && v !== null,
  );
  if (entries.length === 0) return null;

  return (
    <div className="space-y-0.5" style={{ fontSize: 'var(--text-sm)' }}>
      {entries.slice(0, 8).map(([key, value]) => (
        <div key={key} className="flex gap-2">
          <span
            className="shrink-0 font-mono"
            style={{ color: 'var(--text-muted)', minWidth: '6rem' }}
          >
            {key}
          </span>
          <span
            className="truncate"
            style={{ color: 'var(--text-secondary)' }}
          >
            {typeof value === 'string' ? truncate(value, 120) : JSON.stringify(value)}
          </span>
        </div>
      ))}
      {entries.length > 8 && (
        <div className="text-xs" style={{ color: 'var(--text-muted)' }}>
          +{entries.length - 8} more
        </div>
      )}
    </div>
  );
};

/* ------------------------------------------------------------------ */
/*  Main component                                                     */
/* ------------------------------------------------------------------ */

interface ToolArgDisplayProps {
  toolName: string;
  args: unknown;
}

const ToolArgDisplay: React.FC<ToolArgDisplayProps> = React.memo(
  ({ toolName, args }) => {
    const a = asRecord(args);

    switch (toolName) {
      case 'exec':
      case 'process':
        return <ExecArgs args={a} />;
      case 'web_search':
        return <SearchArgs args={a} />;
      case 'web_fetch':
        return <WebFetchArgs args={a} />;
      case 'read':
      case 'write':
      case 'edit':
        return <FileArgs args={a} toolName={toolName} />;
      case 'browser':
        return <BrowserArgs args={a} />;
      case 'message':
        return <MessageArgs args={a} />;
      case 'sessions_spawn':
      case 'subagents':
        return <SessionSpawnArgs args={a} />;
      default:
        return <GenericArgs args={a} />;
    }
  },
);

ToolArgDisplay.displayName = 'ToolArgDisplay';

export default ToolArgDisplay;
