/**
 * TerminalOutput — Terminal-style display for exec tool output.
 *
 * Dark background, monospace font, ANSI colour support, command header,
 * exit-code indicator, scrollable + copy button.
 */
import React, { useState, useCallback, useRef } from 'react';
import { Check, Copy, ChevronDown, ChevronUp } from 'lucide-react';
import AnsiText from './AnsiParser';

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const MAX_LINES_COLLAPSED = 25;

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

interface TerminalOutputProps {
  command?: string;
  output: string;
  exitCode?: number | null;
}

const TerminalOutput: React.FC<TerminalOutputProps> = React.memo(
  ({ command, output, exitCode }) => {
    const [copied, setCopied] = useState(false);
    const [expanded, setExpanded] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    const lines = output.split('\n');
    const isLong = lines.length > MAX_LINES_COLLAPSED;
    const displayText =
      isLong && !expanded
        ? lines.slice(0, MAX_LINES_COLLAPSED).join('\n')
        : output;
    const hiddenCount = isLong && !expanded ? lines.length - MAX_LINES_COLLAPSED : 0;

    const handleCopy = useCallback(async () => {
      try {
        await navigator.clipboard.writeText(output);
      } catch {
        /* fallback */
        const ta = document.createElement('textarea');
        ta.value = output;
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
      }
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }, [output]);

    const exitOk = exitCode === 0 || exitCode == null;

    return (
      <div
        className="rounded-lg overflow-hidden my-1.5 group/term"
        style={{
          background: '#0d0d14',
          border: '1px solid var(--border-subtle)',
        }}
      >
        {/* Header: command + copy */}
        {(command || exitCode != null) && (
          <div
            className="flex items-center justify-between px-3 py-1.5 gap-2"
            style={{
              background: '#09090f',
              borderBottom: '1px solid var(--border-subtle)',
            }}
          >
            <div
              className="flex items-center gap-2 truncate min-w-0"
              style={{ fontFamily: 'var(--font-mono)', fontSize: 'var(--text-sm)' }}
            >
              {command && (
                <>
                  <span style={{ color: 'var(--success)' }}>$</span>
                  <span
                    className="truncate"
                    style={{ color: 'var(--text-primary)' }}
                  >
                    {command}
                  </span>
                </>
              )}
            </div>

            <div className="flex items-center gap-2 shrink-0">
              {exitCode != null && (
                <span
                  className="text-xs font-mono px-1.5 py-0.5 rounded"
                  style={{
                    color: exitOk ? 'var(--success)' : 'var(--error)',
                    background: exitOk
                      ? 'var(--success-muted)'
                      : 'var(--error-muted)',
                  }}
                >
                  exit {exitCode}
                </span>
              )}
              <button
                onClick={handleCopy}
                className="flex items-center gap-1 px-1.5 py-0.5 rounded text-xs opacity-0 group-hover/term:opacity-100 transition-opacity"
                style={{
                  color: copied ? 'var(--success)' : 'var(--text-secondary)',
                  transitionDuration: 'var(--duration-normal)',
                }}
                title="Copy output"
              >
                {copied ? <Check size={12} /> : <Copy size={12} />}
              </button>
            </div>
          </div>
        )}

        {/* Output body */}
        <div
          ref={scrollRef}
          className="overflow-x-auto px-3 py-2"
          style={{ maxHeight: expanded ? '600px' : '400px', overflowY: 'auto' }}
        >
          <pre
            className="m-0 whitespace-pre-wrap break-words"
            style={{
              fontFamily: 'var(--font-mono)',
              fontSize: 'var(--text-sm)',
              lineHeight: 'var(--leading-snug)',
              color: 'var(--text-primary)',
            }}
          >
            <AnsiText text={displayText} />
          </pre>
        </div>

        {/* Show more / less */}
        {isLong && (
          <button
            onClick={() => setExpanded(!expanded)}
            className="w-full flex items-center justify-center gap-1 py-1 text-xs font-medium transition-colors"
            style={{
              color: 'var(--accent-primary)',
              background: '#09090f',
              borderTop: '1px solid var(--border-subtle)',
              transitionDuration: 'var(--duration-normal)',
            }}
          >
            {expanded ? (
              <>
                <ChevronUp size={14} /> Collapse
              </>
            ) : (
              <>
                <ChevronDown size={14} /> Show {hiddenCount} more lines
              </>
            )}
          </button>
        )}
      </div>
    );
  },
);

TerminalOutput.displayName = 'TerminalOutput';

export default TerminalOutput;
