/**
 * ChatContainer — Main chat view: message list + input bar + scroll management.
 */
import React, { useRef, useCallback, useEffect, useState } from 'react';
import { useChat, useGateway } from '@/gateway';
import { MessageSkeleton } from '@/theme';
import MessageList from './MessageList';
import ChatInput from './ChatInput';
import EmptyState from './EmptyState';
import WelcomeBanner from './WelcomeBanner';
import ScrollToBottom from './ScrollToBottom';

interface ChatContainerProps {
  sessionKey: string;
  modelName?: string;
  thinkingLevel?: string;
}

const SCROLL_THRESHOLD = 200;

const ChatContainer: React.FC<ChatContainerProps> = ({ sessionKey, modelName, thinkingLevel }) => {
  const { messages, streamingText, segments, toolStream, isLoading, send, abort, loadHistory } =
    useChat(sessionKey);
  const { connectionStatus } = useGateway();

  const scrollRef = useRef<HTMLDivElement>(null);
  const [isNearBottom, setIsNearBottom] = useState(true);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);
  const prevMessageCount = useRef(messages.length);

  const isConnected = connectionStatus === 'connected';
  const isStreaming = isLoading || !!streamingText;
  const isEmpty = messages.length === 0 && !streamingText && segments.length === 0;

  // Load history on mount / session change
  useEffect(() => {
    loadHistory();
  }, [sessionKey, loadHistory]);

  // Check scroll position
  const handleScroll = useCallback(() => {
    const el = scrollRef.current;
    if (!el) return;
    const distanceFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
    const nearBottom = distanceFromBottom < SCROLL_THRESHOLD;
    setIsNearBottom(nearBottom);
    setShowScrollBtn(!nearBottom);
    if (nearBottom) setUnreadCount(0);
  }, []);

  // Auto-scroll when near bottom
  useEffect(() => {
    if (isNearBottom && scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth',
      });
    }
  }, [messages.length, streamingText, segments.length, toolStream.length, isNearBottom]);

  // Track unread messages when scrolled up
  useEffect(() => {
    if (!isNearBottom && messages.length > prevMessageCount.current) {
      setUnreadCount((c) => c + (messages.length - prevMessageCount.current));
    }
    prevMessageCount.current = messages.length;
  }, [messages.length, isNearBottom]);

  const scrollToBottom = useCallback(() => {
    scrollRef.current?.scrollTo({
      top: scrollRef.current.scrollHeight,
      behavior: 'smooth',
    });
    setUnreadCount(0);
  }, []);

  const handleSend = useCallback(
    (text: string, attachments?: Array<{ type: string; name?: string; data?: string; media_type?: string }>) => {
      send(text, attachments);
      // Scroll to bottom on send
      setTimeout(() => {
        scrollRef.current?.scrollTo({
          top: scrollRef.current.scrollHeight,
          behavior: 'smooth',
        });
      }, 50);
    },
    [send],
  );

  return (
    <div
      className="flex flex-col h-full relative"
      style={{ background: 'var(--bg-primary)' }}
    >
      {/* Welcome banner */}
      {isEmpty && (
        <WelcomeBanner
          modelName={modelName}
          sessionKey={sessionKey}
          thinkingLevel={thinkingLevel}
        />
      )}

      {/* Scrollable message area */}
      <div
        ref={scrollRef}
        className="flex-1 overflow-y-auto overflow-x-hidden"
        onScroll={handleScroll}
        style={{
          scrollbarColor: 'var(--scrollbar-thumb) var(--scrollbar-track)',
          scrollbarWidth: 'thin',
        }}
      >
        {/* Loading skeleton */}
        {isLoading && messages.length === 0 && !streamingText && (
          <div className="p-4 space-y-4">
            <MessageSkeleton />
            <MessageSkeleton />
            <MessageSkeleton />
          </div>
        )}

        {/* Empty state */}
        {isEmpty && !isLoading && <EmptyState onSendMessage={(t) => handleSend(t)} />}

        {/* Message list */}
        {!isEmpty && (
          <div style={{ maxWidth: 'var(--content-max-width)', margin: '0 auto', width: '100%' }}>
            <MessageList
              messages={messages}
              segments={segments}
              toolStream={toolStream}
              streamingText={streamingText}
              isStreaming={isStreaming}
            />
          </div>
        )}

        {/* Bottom spacer */}
        <div className="h-4" />
      </div>

      {/* Scroll to bottom button */}
      <ScrollToBottom
        visible={showScrollBtn}
        unreadCount={unreadCount}
        onClick={scrollToBottom}
      />

      {/* Input */}
      <div style={{ maxWidth: 'var(--content-max-width)', margin: '0 auto', width: '100%' }}>
        <ChatInput
          onSend={handleSend}
          onAbort={abort}
          isStreaming={isStreaming}
          isConnected={isConnected}
        />
      </div>
    </div>
  );
};

export default ChatContainer;
