/**
 * ChatErrorBoundary — Catches rendering errors in the chat area.
 * Shows a user-friendly error message instead of a blank/black screen.
 */
import React from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface State {
  hasError: boolean;
  error: Error | null;
}

interface Props {
  children: React.ReactNode;
  sessionKey?: string;
}

export class ChatErrorBoundary extends React.Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: React.ErrorInfo) {
    console.error('[ChatErrorBoundary] Caught error:', error, info);
  }

  componentDidUpdate(prevProps: Props) {
    // Reset when session changes
    if (prevProps.sessionKey !== this.props.sessionKey && this.state.hasError) {
      this.setState({ hasError: false, error: null });
    }
  }

  handleRetry = () => {
    this.setState({ hasError: false, error: null });
  };

  render() {
    if (!this.state.hasError) {
      return this.props.children;
    }

    return (
      <div
        className="flex flex-col items-center justify-center h-full gap-4 p-8"
        style={{ background: 'var(--bg-primary)', color: 'var(--text-primary)' }}
      >
        <div
          className="flex items-center justify-center w-14 h-14 rounded-full"
          style={{ background: 'var(--bg-tertiary)', border: '1px solid var(--border-subtle)' }}
        >
          <AlertTriangle size={24} style={{ color: 'var(--warning, #f59e0b)' }} />
        </div>

        <div className="text-center max-w-sm">
          <h3
            className="font-semibold mb-1"
            style={{ fontSize: 'var(--text-base)', color: 'var(--text-primary)' }}
          >
            Chat failed to render
          </h3>
          <p
            className="text-sm"
            style={{ color: 'var(--text-muted)', lineHeight: 'var(--leading-relaxed)' }}
          >
            Something went wrong displaying this conversation. This is likely caused by an unexpected
            message format.
          </p>
          {this.state.error && (
            <pre
              className="mt-3 p-3 rounded-lg text-xs text-left overflow-auto max-h-32"
              style={{
                background: 'var(--bg-secondary)',
                border: '1px solid var(--border-subtle)',
                color: 'var(--text-muted)',
                fontFamily: 'var(--font-mono)',
              }}
            >
              {this.state.error.message}
            </pre>
          )}
        </div>

        <button
          onClick={this.handleRetry}
          className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-opacity hover:opacity-80"
          style={{
            background: 'var(--accent-primary)',
            color: 'var(--text-inverse)',
            border: 'none',
            cursor: 'pointer',
          }}
        >
          <RefreshCw size={14} />
          Try again
        </button>
      </div>
    );
  }
}

export default ChatErrorBoundary;
