/**
 * Corgi Dashboard — useSubAgents Hook
 *
 * Reads from useSessions(), filters sub-agent sessions,
 * polls for updates, and derives status/labels/elapsed times.
 */
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useSessions } from '../../gateway/hooks';
import {
  getSubAgentSessions,
  enrichSubAgent,
  sortAgentsByStatus,
  type SubAgentInfo,
  type AgentStatus,
} from './SubAgentFilter';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface UseSubAgentsReturn {
  /** Enriched sub-agent list, sorted by status (running first). */
  subAgents: SubAgentInfo[];
  /** Whether any sub-agents are currently running or pending. */
  hasActive: boolean;
  /** Total sub-agent count. */
  totalCount: number;
  /** Count by status. */
  runningCount: number;
  pendingCount: number;
  completedCount: number;
  failedCount: number;
  /** Whether the panel should be visible. */
  isVisible: boolean;
  /** Manually show the panel. */
  show: () => void;
  /** Manually hide the panel. */
  hide: () => void;
  /** Toggle panel visibility. */
  toggle: () => void;
  /** Currently selected agent (for detail view). */
  selectedAgent: SubAgentInfo | null;
  /** Select an agent to view details. */
  selectAgent: (key: string | null) => void;
}

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const POLL_INTERVAL_MS = 5_000;
const AUTO_HIDE_DELAY_MS = 5_000;

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

export function useSubAgents(): UseSubAgentsReturn {
  const { sessions, refresh } = useSessions();

  const [manualVisible, setManualVisible] = useState<boolean | null>(null);
  const [selectedKey, setSelectedKey] = useState<string | null>(null);
  const autoHideTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const prevHadActive = useRef(false);

  // ── Derive sub-agent info ──────────────────────────────────

  const subAgents = useMemo(() => {
    const raw = getSubAgentSessions(sessions);
    const enriched = raw.map(enrichSubAgent);
    return sortAgentsByStatus(enriched);
  }, [sessions]);

  const counts = useMemo(() => {
    const c = { running: 0, pending: 0, complete: 0, failed: 0 };
    for (const a of subAgents) {
      c[a.status]++;
    }
    return c;
  }, [subAgents]);

  const hasActive = counts.running > 0 || counts.pending > 0;

  // ── Auto-show / auto-hide logic ───────────────────────────

  useEffect(() => {
    // Auto-show when sub-agents first appear
    if (hasActive && !prevHadActive.current) {
      setManualVisible(null); // Reset manual override → auto-show
      if (autoHideTimer.current) {
        clearTimeout(autoHideTimer.current);
        autoHideTimer.current = null;
      }
    }

    // Auto-hide after all agents complete (with delay)
    if (!hasActive && prevHadActive.current && subAgents.length > 0) {
      autoHideTimer.current = setTimeout(() => {
        setManualVisible(false);
        autoHideTimer.current = null;
      }, AUTO_HIDE_DELAY_MS);
    }

    prevHadActive.current = hasActive;

    return () => {
      if (autoHideTimer.current) clearTimeout(autoHideTimer.current);
    };
  }, [hasActive, subAgents.length]);

  // ── Polling while active ──────────────────────────────────

  useEffect(() => {
    if (!hasActive) return;

    const interval = setInterval(() => {
      refresh();
    }, POLL_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [hasActive, refresh]);

  // ── Visibility ────────────────────────────────────────────

  const isVisible = useMemo(() => {
    if (manualVisible !== null) return manualVisible;
    return subAgents.length > 0;
  }, [manualVisible, subAgents.length]);

  const show = useCallback(() => setManualVisible(true), []);
  const hide = useCallback(() => setManualVisible(false), []);
  const toggle = useCallback(() => setManualVisible((prev) => !(prev ?? true)), []);

  // ── Selection ─────────────────────────────────────────────

  const selectedAgent = useMemo(
    () => subAgents.find((a) => a.session.key === selectedKey) ?? null,
    [subAgents, selectedKey],
  );

  const selectAgent = useCallback((key: string | null) => {
    setSelectedKey(key);
  }, []);

  return {
    subAgents,
    hasActive,
    totalCount: subAgents.length,
    runningCount: counts.running,
    pendingCount: counts.pending,
    completedCount: counts.complete,
    failedCount: counts.failed,
    isVisible,
    show,
    hide,
    toggle,
    selectedAgent,
    selectAgent,
  };
}
