/**
 * ThinkingBlock — Collapsible thinking/reasoning display
 *
 * Renders thinking content from `{ type: 'thinking', thinking: string }` blocks.
 * Collapsed by default after streaming ends; expandable via Radix Collapsible.
 *
 * Supports two usage modes:
 * - Simple: `<ThinkingBlock thinking="..." />`  (used by MessageBubble)
 * - Batched: `<ThinkingBlock thinkingBlocks={["...", "..."]} />` (multiple blocks combined)
 */
import { useState, useMemo } from 'react';
import * as Collapsible from '@radix-ui/react-collapsible';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronRight, Brain } from 'lucide-react';
import { useThinkingContext } from './ThinkingToggle';

export interface ThinkingBlockProps {
  /** Single thinking string (from MessageBubble) */
  thinking?: string;
  /** Multiple thinking strings to combine */
  thinkingBlocks?: string[];
  /** Whether the parent message is still streaming */
  isStreaming?: boolean;
}

export function ThinkingBlock({ thinking, thinkingBlocks, isStreaming = false }: ThinkingBlockProps) {
  const thinkingCtx = useThinkingContext();
  // Open by default while streaming, collapsed after
  const [open, setOpen] = useState(isStreaming);

  const combinedText = useMemo(() => {
    if (thinkingBlocks?.length) {
      return thinkingBlocks.filter(Boolean).join('\n\n');
    }
    return thinking ?? '';
  }, [thinking, thinkingBlocks]);

  // If global toggle says hide, render nothing
  if (!thinkingCtx.showThinking || !combinedText) return null;

  return (
    <Collapsible.Root
      open={open}
      onOpenChange={setOpen}
      className="my-2 rounded-xl overflow-hidden"
      style={{
        border: '1px solid color-mix(in srgb, var(--accent-primary) 25%, transparent)',
        background: 'linear-gradient(135deg, color-mix(in srgb, var(--accent-primary) 6%, var(--bg-tertiary)) 0%, var(--bg-tertiary) 100%)',
      }}
    >
      <Collapsible.Trigger asChild>
        <button
          className="flex w-full items-center gap-2 px-3 py-2.5 text-left hover:opacity-80 transition-opacity"
          style={{
            color: 'var(--text-secondary)',
            fontSize: 'var(--text-sm)',
            fontWeight: 'var(--font-medium)',
            fontFamily: 'var(--font-sans)',
            cursor: 'pointer',
            background: 'none',
            border: 'none',
          }}
        >
          <Brain size={13} style={{ color: 'var(--accent-primary)', flexShrink: 0 }} />
          <span style={{ color: 'var(--accent-primary)', fontWeight: 600 }}>Thinking</span>
          {!open && (
            <span
              className="ml-1 truncate max-w-[200px]"
              style={{ color: 'var(--text-muted)', fontStyle: 'italic', fontWeight: 400 }}
            >
              — click to expand
            </span>
          )}
          <motion.span
            animate={{ rotate: open ? 90 : 0 }}
            transition={{ duration: 0.15 }}
            className="ml-auto shrink-0"
            style={{ color: 'var(--text-muted)' }}
          >
            <ChevronRight size={13} />
          </motion.span>
        </button>
      </Collapsible.Trigger>

      <AnimatePresence initial={false}>
        {open && (
          <Collapsible.Content forceMount asChild>
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              transition={{ duration: 0.25, ease: [0.16, 1, 0.3, 1] }}
              style={{ overflow: 'hidden' }}
            >
              <div
                className="px-3 pb-3"
                style={{
                  color: 'var(--text-muted)',
                  fontSize: 'var(--text-sm)',
                  fontStyle: 'italic',
                  lineHeight: 'var(--leading-relaxed)',
                  fontFamily: 'var(--font-sans)',
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-word',
                  maxHeight: '320px',
                  overflowY: 'auto',
                  borderTop: '1px solid color-mix(in srgb, var(--accent-primary) 15%, transparent)',
                  paddingTop: '8px',
                  scrollbarWidth: 'thin',
                  scrollbarColor: 'var(--scrollbar-thumb) transparent',
                }}
              >
                {combinedText}
              </div>
            </motion.div>
          </Collapsible.Content>
        )}
      </AnimatePresence>
    </Collapsible.Root>
  );
}

export default ThinkingBlock;
