/**
 * SettingsPanel — App-level settings view.
 */
import React, { useState } from 'react';
import { X, Moon, Sun, Monitor, Save } from 'lucide-react';
import { useAppStore } from '../../stores/app-store';
import type { ThemeMode } from '../../utils/theme';

interface SettingsPanelProps {
  onClose: () => void;
}

const themeOptions: { value: ThemeMode; label: string; icon: React.ReactNode }[] = [
  { value: 'dark', label: 'Dark', icon: <Moon size={16} /> },
  { value: 'light', label: 'Light', icon: <Sun size={16} /> },
  { value: 'auto', label: 'System', icon: <Monitor size={16} /> },
];

const SettingsPanel: React.FC<SettingsPanelProps> = ({ onClose }) => {
  const { theme, setTheme, gatewayUrl, gatewayToken, setGatewayUrl, setGatewayToken } = useAppStore();
  const [localUrl, setLocalUrl] = useState(gatewayUrl);
  const [localToken, setLocalToken] = useState(gatewayToken);
  const [saved, setSaved] = useState(false);

  const handleSaveGateway = () => {
    setGatewayUrl(localUrl);
    setGatewayToken(localToken);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  return (
    <div
      className="flex-1 overflow-y-auto p-6"
      style={{ background: 'var(--bg-primary)', color: 'var(--text-primary)' }}
    >
      <div className="flex items-center justify-between mb-6">
        <h1 style={{ fontSize: 'var(--text-xl)', fontWeight: 'var(--font-bold)' }}>Settings</h1>
        <button
          onClick={onClose}
          style={{ background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' }}
        >
          <X size={20} />
        </button>
      </div>

      {/* Theme */}
      <section className="mb-8">
        <h2
          className="mb-3"
          style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.05em' }}
        >
          Theme
        </h2>
        <div className="flex gap-2">
          {themeOptions.map((opt) => (
            <button
              key={opt.value}
              onClick={() => setTheme(opt.value)}
              className="flex items-center gap-2 px-4 py-2 rounded-lg transition-colors"
              style={{
                background: theme === opt.value ? 'var(--accent-muted)' : 'var(--bg-tertiary)',
                border: `1px solid ${theme === opt.value ? 'var(--accent-primary)' : 'var(--border-subtle)'}`,
                color: theme === opt.value ? 'var(--accent-primary)' : 'var(--text-secondary)',
                cursor: 'pointer',
                fontSize: 'var(--text-sm)',
              }}
            >
              {opt.icon}
              {opt.label}
            </button>
          ))}
        </div>
      </section>

      {/* Gateway */}
      <section className="mb-8">
        <h2
          className="mb-3"
          style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.05em' }}
        >
          Gateway Connection
        </h2>
        <div className="flex flex-col gap-3">
          <div>
            <label
              className="block mb-1"
              style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)' }}
            >
              WebSocket URL
            </label>
            <input
              type="text"
              value={localUrl}
              onChange={(e) => setLocalUrl(e.target.value)}
              placeholder="ws://localhost:8000/ws"
              className="w-full px-3 py-2 rounded-lg"
              style={{
                background: 'var(--bg-tertiary)',
                border: '1px solid var(--border-default)',
                color: 'var(--text-primary)',
                fontSize: 'var(--text-sm)',
                outline: 'none',
              }}
            />
          </div>
          <div>
            <label
              className="block mb-1"
              style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)' }}
            >
              Auth Token
            </label>
            <input
              type="password"
              value={localToken}
              onChange={(e) => setLocalToken(e.target.value)}
              placeholder="Bearer token or password"
              className="w-full px-3 py-2 rounded-lg"
              style={{
                background: 'var(--bg-tertiary)',
                border: '1px solid var(--border-default)',
                color: 'var(--text-primary)',
                fontSize: 'var(--text-sm)',
                outline: 'none',
              }}
            />
          </div>
          <button
            onClick={handleSaveGateway}
            className="flex items-center gap-2 px-4 py-2 rounded-lg self-start transition-colors"
            style={{
              background: saved ? 'var(--success)' : 'var(--accent-primary)',
              border: 'none',
              color: '#fff',
              cursor: 'pointer',
              fontSize: 'var(--text-sm)',
              fontWeight: 'var(--font-medium)',
            }}
          >
            <Save size={14} />
            {saved ? 'Saved!' : 'Save & Reconnect'}
          </button>
        </div>
      </section>
    </div>
  );
};

export default SettingsPanel;
