/**
 * StreamingIndicator — Animated typing indicator for when the assistant is generating.
 * Shows bouncing dots with a "Brock is thinking..." label.
 */
import React from 'react';
import { motion } from 'framer-motion';
import { typingContainer, typingDot } from '@/theme';

const StreamingIndicator: React.FC = React.memo(() => {
  return (
    <div className="flex items-start gap-3 px-4 py-2">
      {/* Avatar */}
      <div
        className="w-7 h-7 rounded-full flex items-center justify-center shrink-0 text-sm font-medium"
        style={{ background: 'var(--accent-muted)', color: 'var(--accent-primary)' }}
      >
        C
      </div>

      {/* Bubble with text + dots */}
      <div
        className="flex items-center gap-2.5 px-4 py-3 rounded-2xl rounded-tl-sm"
        style={{
          background: 'var(--bg-secondary)',
          border: '1px solid var(--border-subtle)',
        }}
      >
        {/* Label */}
        <span
          className="text-sm"
          style={{ color: 'var(--text-muted)', fontStyle: 'italic' }}
        >
          Brock is thinking
        </span>

        {/* Bouncing dots */}
        <motion.div
          className="flex gap-1 items-center"
          variants={typingContainer}
          initial="idle"
          animate="bounce"
        >
          {[0, 1, 2].map((i) => (
            <motion.span
              key={i}
              className="block w-1.5 h-1.5 rounded-full"
              style={{ background: 'var(--accent-primary)', opacity: 0.7 }}
              variants={typingDot}
            />
          ))}
        </motion.div>
      </div>
    </div>
  );
});

StreamingIndicator.displayName = 'StreamingIndicator';

export default StreamingIndicator;
