/**
 * Corgi Dashboard — Sub-Agent Filtering Utilities
 *
 * Pure functions for filtering, sorting, and deriving sub-agent data
 * from gateway session lists.
 */
import type { SessionRow } from '../../gateway/types';
import { isSubAgentSession } from '../../gateway/utils';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type AgentStatus = 'pending' | 'running' | 'complete' | 'failed';

export interface SubAgentInfo {
  session: SessionRow;
  status: AgentStatus;
  label: string;
  startedAt: number | null;
  elapsedMs: number | null;
}

/* ------------------------------------------------------------------ */
/*  Filtering                                                          */
/* ------------------------------------------------------------------ */

/**
 * Return only sub-agent sessions from the full sessions list.
 */
export function getSubAgentSessions(sessions: SessionRow[]): SessionRow[] {
  return sessions.filter((s) => isSubAgentSession(s.key));
}

/**
 * Return the orchestrator (current) session — the one without "subagent:" in the key.
 */
export function getOrchestratorSession(
  sessions: SessionRow[],
  currentKey: string,
): SessionRow | undefined {
  return sessions.find((s) => s.key === currentKey && !isSubAgentSession(s.key));
}

/**
 * Check if a message belongs to a sub-agent session.
 */
export function isSubAgentMessage(
  messageSessionKey: string,
  subAgentKeys: Set<string>,
): boolean {
  return subAgentKeys.has(messageSessionKey);
}

/* ------------------------------------------------------------------ */
/*  Status derivation                                                  */
/* ------------------------------------------------------------------ */

/**
 * Derive agent status from session metadata.
 *
 * Heuristics:
 * - If session has no updatedAt → pending
 * - If session has updatedAt within last 60s → running
 * - If derivedTitle contains "error" or "failed" → failed
 * - Otherwise → complete
 */
export function getAgentStatus(session: SessionRow): AgentStatus {
  const title = (session.derivedTitle ?? session.label ?? '').toLowerCase();

  // Check for failure indicators
  if (title.includes('error') || title.includes('failed') || title.includes('crashed')) {
    return 'failed';
  }

  if (!session.updatedAt && !session.lastMessageAt) {
    return 'pending';
  }

  // Check recency — if updated within last 90 seconds, likely still running
  const lastActivity = session.lastMessageAt ?? session.updatedAt;
  if (lastActivity) {
    const ts = new Date(lastActivity).getTime();
    const ageMs = Date.now() - ts;
    if (ageMs < 90_000) return 'running';
  }

  return 'complete';
}

/* ------------------------------------------------------------------ */
/*  Label extraction                                                   */
/* ------------------------------------------------------------------ */

/**
 * Extract a clean, human-readable label from a sub-agent session.
 *
 * Priority: derivedTitle → label → cleaned key segment
 */
export function getAgentLabel(session: SessionRow): string {
  if (session.derivedTitle) return session.derivedTitle;
  if (session.label) return session.label;

  // Extract from key: "agent:josh:subagent:abc-123" → "abc-123"
  const parts = session.key.split('subagent:');
  if (parts.length > 1) {
    const id = parts[1].replace(/^:/, '');
    // Truncate long UUIDs
    return id.length > 20 ? id.slice(0, 8) + '…' : id;
  }

  return 'Sub-agent';
}

/* ------------------------------------------------------------------ */
/*  Sorting                                                            */
/* ------------------------------------------------------------------ */

const statusOrder: Record<AgentStatus, number> = {
  running: 0,
  pending: 1,
  failed: 2,
  complete: 3,
};

/**
 * Sort agents: running first, then pending, then failed, then complete.
 */
export function sortAgentsByStatus(agents: SubAgentInfo[]): SubAgentInfo[] {
  return [...agents].sort((a, b) => statusOrder[a.status] - statusOrder[b.status]);
}

/* ------------------------------------------------------------------ */
/*  Enrichment                                                         */
/* ------------------------------------------------------------------ */

/**
 * Convert a raw SessionRow to a SubAgentInfo with derived fields.
 */
export function enrichSubAgent(session: SessionRow): SubAgentInfo {
  const status = getAgentStatus(session);
  const label = getAgentLabel(session);

  const createdTs = session.createdAt ? new Date(session.createdAt).getTime() : null;
  const updatedTs = session.updatedAt ? new Date(session.updatedAt).getTime() : null;

  let elapsedMs: number | null = null;
  if (createdTs) {
    const endTs = status === 'running' ? Date.now() : (updatedTs ?? Date.now());
    elapsedMs = endTs - createdTs;
  }

  return {
    session,
    status,
    label,
    startedAt: createdTs,
    elapsedMs,
  };
}
