/**
 * WelcomeBanner — Compact session info banner at top of new sessions.
 */
import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Cpu, Key, Brain } from 'lucide-react';
import { slideDown } from '@/theme';

interface WelcomeBannerProps {
  modelName?: string;
  sessionKey?: string;
  thinkingLevel?: string;
}

const WelcomeBanner: React.FC<WelcomeBannerProps> = React.memo(
  ({ modelName, sessionKey, thinkingLevel }) => {
    const [dismissed, setDismissed] = useState(false);

    if (dismissed || (!modelName && !sessionKey)) return null;

    return (
      <AnimatePresence>
        {!dismissed && (
          <motion.div
            className="flex items-center gap-4 px-4 py-2 mx-4 mt-2 rounded-lg text-xs"
            style={{
              background: 'var(--bg-secondary)',
              border: '1px solid var(--border-subtle)',
              color: 'var(--text-secondary)',
            }}
            variants={slideDown}
            initial="hidden"
            animate="visible"
            exit="exit"
          >
            {modelName && (
              <span className="flex items-center gap-1.5">
                <Cpu size={12} style={{ color: 'var(--accent-primary)' }} />
                {modelName}
              </span>
            )}
            {sessionKey && (
              <span className="flex items-center gap-1.5">
                <Key size={12} style={{ color: 'var(--text-muted)' }} />
                <span className="font-mono truncate max-w-[200px]">{sessionKey}</span>
              </span>
            )}
            {thinkingLevel && (
              <span className="flex items-center gap-1.5">
                <Brain size={12} style={{ color: 'var(--info)' }} />
                {thinkingLevel}
              </span>
            )}
            <button
              className="ml-auto p-1 rounded transition-colors"
              style={{
                color: 'var(--text-muted)',
                transitionDuration: 'var(--duration-normal)',
              }}
              onClick={() => setDismissed(true)}
              aria-label="Dismiss"
            >
              <X size={14} />
            </button>
          </motion.div>
        )}
      </AnimatePresence>
    );
  },
);

WelcomeBanner.displayName = 'WelcomeBanner';

export default WelcomeBanner;
