// ─── useApprovals ──────────────────────────────────────────────────────────

export interface UseApprovalsReturn {
  approvals: ExecApprovalRequest[];
  resolve: (id: string, decision: 'allow-once' | 'allow-always' | 'deny') => Promise<void>;
  approve: (id: string) => Promise<void>;
  deny: (id: string) => Promise<void>;
}

export function useApprovals(): UseApprovalsReturn {
  const approvals = useGatewayStore((s) => s.approvals);

  const resolve = useCallback(async (id: string, decision: string) => {
    if (!globalClient) return;
    try {
      await globalClient.request('exec.approval.resolve', { id, decision });
      useGatewayStore.getState().removeApproval(id);
    } catch (err) {
      console.error('[Gateway] exec.approval.resolve failed:', err);
    }
  }, []);

  const approve = useCallback((id: string) => resolve(id, 'allow-once'), [resolve]);
  const deny = useCallback((id: string) => resolve(id, 'deny'), [resolve]);

  return {
    approvals,
    resolve,
    approve,
    deny,
  };
}

