// ─── useAgents ─────────────────────────────────────────────────────────────

export interface UseAgentsReturn {
  agents: AgentsListResponse['agents'];
  defaultAgentId: string | null;
  identities: Record<string, AgentIdentity>;
  refresh: () => Promise<void>;
  fetchIdentity: (agentId: string) => Promise<AgentIdentity | null>;
  listFiles: (agentId: string) => Promise<AgentFilesListResponse | null>;
  getFile: (agentId: string, name: string) => Promise<AgentFilesGetResponse | null>;
  setFile: (agentId: string, name: string, content: string) => Promise<void>;
}

export function useAgents(): UseAgentsReturn {
  const agents = useGatewayStore((s) => s.agents);
  const defaultAgentId = useGatewayStore((s) => s.defaultAgentId);
  const agentIdentities = useGatewayStore((s) => s.agentIdentities);

  const refresh = useCallback(async () => {
    if (!globalClient) return;
    try {
      const res = await globalClient.request<AgentsListResponse>('agents.list');
      if (res) useGatewayStore.getState().setAgents(res.agents, res.defaultId);
    } catch (err) {
      console.error('[Gateway] agents.list failed:', err);
    }
  }, []);

  const fetchIdentity = useCallback(async (agentId: string) => {
    if (!globalClient) return null;
    try {
      const res = await globalClient.request<AgentIdentity>('agent.identity.get', { agentId });
      if (res) useGatewayStore.getState().setAgentIdentity(agentId, res);
      return res;
    } catch (err) {
      console.error('[Gateway] agent.identity.get failed:', err);
      return null;
    }
  }, []);

  const listFiles = useCallback(async (agentId: string) => {
    if (!globalClient) return null;
    try {
      return await globalClient.request<AgentFilesListResponse>('agents.files.list', { agentId });
    } catch (err) {
      console.error('[Gateway] agents.files.list failed:', err);
      return null;
    }
  }, []);

  const getFile = useCallback(async (agentId: string, name: string) => {
    if (!globalClient) return null;
    try {
      return await globalClient.request<AgentFilesGetResponse>('agents.files.get', { agentId, name });
    } catch (err) {
      console.error('[Gateway] agents.files.get failed:', err);
      return null;
    }
  }, []);

  const setFile = useCallback(async (agentId: string, name: string, content: string) => {
    if (!globalClient) return;
    try {
      await globalClient.request('agents.files.set', { agentId, name, content });
    } catch (err) {
      console.error('[Gateway] agents.files.set failed:', err);
    }
  }, []);

  return {
    agents,
    defaultAgentId,
    identities: agentIdentities,
    refresh,
    fetchIdentity,
    listFiles,
    getFile,
    setFile,
  };
}

