/**
 * Corgi Dashboard — Framer Motion Animation Presets
 */
import type { Variants, Transition } from 'framer-motion';

/* ------------------------------------------------------------------ */
/*  Shared transitions                                                 */
/* ------------------------------------------------------------------ */

export const transitionFast: Transition = {
  duration: 0.15,
  ease: [0.16, 1, 0.3, 1],
};

export const transitionNormal: Transition = {
  duration: 0.25,
  ease: [0.16, 1, 0.3, 1],
};

export const transitionSlow: Transition = {
  duration: 0.35,
  ease: [0.16, 1, 0.3, 1],
};

export const transitionSpring: Transition = {
  type: 'spring',
  stiffness: 400,
  damping: 30,
};

export const transitionLayout: Transition = {
  duration: 0.3,
  ease: [0.65, 0, 0.35, 1],
};

/* ------------------------------------------------------------------ */
/*  Fade                                                               */
/* ------------------------------------------------------------------ */

export const fadeIn: Variants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: transitionNormal },
};

export const fadeOut: Variants = {
  visible: { opacity: 1 },
  hidden: { opacity: 0, transition: transitionNormal },
};

/* ------------------------------------------------------------------ */
/*  Slide                                                              */
/* ------------------------------------------------------------------ */

export const slideInRight: Variants = {
  hidden: { x: '100%', opacity: 0 },
  visible: { x: 0, opacity: 1, transition: transitionSlow },
  exit: { x: '100%', opacity: 0, transition: transitionSlow },
};

export const slideOutRight: Variants = {
  visible: { x: 0, opacity: 1 },
  exit: { x: '100%', opacity: 0, transition: transitionSlow },
};

export const slideInLeft: Variants = {
  hidden: { x: '-100%', opacity: 0 },
  visible: { x: 0, opacity: 1, transition: transitionSlow },
  exit: { x: '-100%', opacity: 0, transition: transitionSlow },
};

export const slideOutLeft: Variants = {
  visible: { x: 0, opacity: 1 },
  exit: { x: '-100%', opacity: 0, transition: transitionSlow },
};

export const slideUp: Variants = {
  hidden: { y: 20, opacity: 0 },
  visible: { y: 0, opacity: 1, transition: transitionNormal },
  exit: { y: -20, opacity: 0, transition: transitionFast },
};

export const slideDown: Variants = {
  hidden: { y: -20, opacity: 0 },
  visible: { y: 0, opacity: 1, transition: transitionNormal },
  exit: { y: 20, opacity: 0, transition: transitionFast },
};

/* ------------------------------------------------------------------ */
/*  Scale                                                              */
/* ------------------------------------------------------------------ */

export const scaleIn: Variants = {
  hidden: { scale: 0.92, opacity: 0 },
  visible: {
    scale: 1,
    opacity: 1,
    transition: { duration: 0.2, ease: [0.16, 1, 0.3, 1] },
  },
  exit: {
    scale: 0.92,
    opacity: 0,
    transition: { duration: 0.15, ease: [0.7, 0, 0.84, 0] },
  },
};

/* ------------------------------------------------------------------ */
/*  Stagger                                                            */
/* ------------------------------------------------------------------ */

export const staggerChildren: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05,
      delayChildren: 0.02,
    },
  },
};

export const staggerItem: Variants = {
  hidden: { y: 8, opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: transitionNormal,
  },
};

/* ------------------------------------------------------------------ */
/*  Pulse / Glow (heartbeat indicator)                                 */
/* ------------------------------------------------------------------ */

export const pulseGlow: Variants = {
  idle: {
    scale: 1,
    boxShadow: '0 0 0 0 rgba(255, 92, 0, 0.4)',
  },
  pulse: {
    scale: [1, 1.15, 1],
    boxShadow: [
      '0 0 0 0 rgba(255, 92, 0, 0.4)',
      '0 0 0 8px rgba(255, 92, 0, 0)',
      '0 0 0 0 rgba(255, 92, 0, 0)',
    ],
    transition: {
      duration: 1.5,
      repeat: Infinity,
      ease: 'easeInOut',
    },
  },
};

/* ------------------------------------------------------------------ */
/*  Shimmer (skeleton loading)                                         */
/* ------------------------------------------------------------------ */

export const shimmer: Variants = {
  initial: { backgroundPosition: '-200% 0' },
  animate: {
    backgroundPosition: '200% 0',
    transition: {
      duration: 1.5,
      repeat: Infinity,
      ease: 'linear',
    },
  },
};

/* ------------------------------------------------------------------ */
/*  Tool card expand / collapse                                        */
/* ------------------------------------------------------------------ */

export const toolCardExpand: Variants = {
  collapsed: {
    height: 0,
    opacity: 0,
    overflow: 'hidden',
  },
  expanded: {
    height: 'auto',
    opacity: 1,
    overflow: 'hidden',
    transition: { duration: 0.25, ease: [0.16, 1, 0.3, 1] },
  },
};

export const toolCardCollapse: Variants = {
  expanded: {
    height: 'auto',
    opacity: 1,
  },
  collapsed: {
    height: 0,
    opacity: 0,
    transition: { duration: 0.2, ease: [0.7, 0, 0.84, 0] },
  },
};

/* ------------------------------------------------------------------ */
/*  Panel resize                                                       */
/* ------------------------------------------------------------------ */

export const panelResize: Variants = {
  closed: { width: 0, opacity: 0, overflow: 'hidden' },
  open: {
    width: 'var(--panel-width, 20%)',
    opacity: 1,
    overflow: 'visible',
    transition: transitionLayout,
  },
};

/* ------------------------------------------------------------------ */
/*  Message appear                                                     */
/* ------------------------------------------------------------------ */

export const messageAppear: Variants = {
  hidden: { y: 6, opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: { duration: 0.2, ease: [0.16, 1, 0.3, 1] },
  },
};

