/**
 * MessageBubble — Individual message bubble.
 * THE critical component for clean, non-duplicated message rendering.
 */
import React, { useState, useCallback, useMemo } from 'react';
import { motion } from 'framer-motion';
import { Copy, Check } from 'lucide-react';
import { messageAppear } from '@/theme';
import type { ChatMessage, ChatContent } from '@/gateway';
import { extractText } from '@/gateway';
import MarkdownRenderer from './MarkdownRenderer';
import ImageViewer from './ImageViewer';
import ToolCard from './tools/ToolCard';
import ThinkingBlock from './ThinkingBlock';
import type { ToolStreamEntry } from '@/gateway';

interface MessageBubbleProps {
  message: ChatMessage;
  /** If true, hides the avatar (grouped with previous same-role message) */
  hideAvatar?: boolean;
  /** If true, this bubble is rendering live streaming text */
  isStreaming?: boolean;
  /** User initial for user avatar */
  userInitial?: string;
}

/** Normalize content to array form */
function getContentBlocks(content: ChatContent[] | string): ChatContent[] {
  if (typeof content === 'string') {
    return content ? [{ type: 'text' as const, text: content }] : [];
  }
  return content ?? [];
}

/** Extract full copyable text from content blocks */
function getCopyText(content: ChatContent[] | string): string {
  if (typeof content === 'string') return content;
  return (content ?? [])
    .filter((b): b is { type: 'text'; text: string } => b.type === 'text')
    .map((b) => b.text)
    .join('');
}

const MessageBubble: React.FC<MessageBubbleProps> = React.memo(
  ({ message, hideAvatar = false, isStreaming = false, userInitial = 'J' }) => {
    const [copied, setCopied] = useState(false);
    const [showTimestamp, setShowTimestamp] = useState(false);

    const isUser = message.role === 'user';
    const isAssistant = message.role === 'assistant';

    const blocks = useMemo(() => getContentBlocks(message.content), [message.content]);
    const copyText = useMemo(() => getCopyText(message.content), [message.content]);

    const handleCopy = useCallback(async () => {
      if (!copyText) return;
      try {
        await navigator.clipboard.writeText(copyText);
      } catch {
        const ta = document.createElement('textarea');
        ta.value = copyText;
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
      }
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }, [copyText]);

    const timestamp = message.ts
      ? new Date(message.ts).toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' })
      : null;

    return (
      <motion.div
        className={`group flex gap-3 px-4 py-1.5 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}
        variants={messageAppear}
        initial="hidden"
        animate="visible"
        onMouseEnter={() => setShowTimestamp(true)}
        onMouseLeave={() => setShowTimestamp(false)}
      >
        {/* Avatar */}
        <div className="w-7 h-7 shrink-0 mt-0.5">
          {!hideAvatar ? (
            <div
              className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-medium"
              style={{
                background: isUser ? 'var(--accent-muted)' : 'var(--bg-tertiary)',
                color: isUser ? 'var(--accent-primary)' : 'var(--text-secondary)',
              }}
            >
              {isUser ? userInitial : 'C'}
            </div>
          ) : (
            <div className="w-7 h-7" />
          )}
        </div>

        {/* Bubble */}
        <div
          className={`relative max-w-[80%] min-w-0 ${isUser ? 'items-end' : 'items-start'}`}
          style={{ display: 'flex', flexDirection: 'column', alignItems: isUser ? 'flex-end' : 'flex-start' }}
        >
          <div
            className={`rounded-2xl px-4 py-2.5 ${
              isUser ? 'rounded-tr-sm' : 'rounded-tl-sm'
            } ${isStreaming ? 'streaming-bubble' : ''}`}
            style={{
              background: isUser ? 'var(--accent-primary)' : 'var(--bg-secondary)',
              color: isUser ? 'var(--text-inverse)' : 'var(--text-primary)',
              border: isUser ? 'none' : '1px solid var(--border-subtle)',
              boxShadow: 'var(--shadow-subtle)',
              ...(isStreaming
                ? {
                    borderColor: 'var(--accent-muted)',
                    boxShadow: 'var(--shadow-glow)',
                  }
                : {}),
              wordBreak: 'break-word',
              overflowWrap: 'break-word',
            }}
          >
            {blocks.map((block, i) => (
              <ContentBlock key={i} block={block} isUser={isUser} />
            ))}
          </div>

          {/* Hover actions */}
          <div
            className={`flex items-center gap-2 mt-0.5 h-5 ${
              isUser ? 'flex-row-reverse' : 'flex-row'
            }`}
          >
            {/* Copy button */}
            {copyText && (
              <button
                className="opacity-0 group-hover:opacity-100 transition-opacity p-0.5 rounded"
                style={{
                  color: copied ? 'var(--success)' : 'var(--text-muted)',
                  transitionDuration: 'var(--duration-normal)',
                }}
                onClick={handleCopy}
                title="Copy message"
              >
                {copied ? <Check size={12} /> : <Copy size={12} />}
              </button>
            )}

            {/* Timestamp */}
            {showTimestamp && timestamp && (
              <span className="text-xs" style={{ color: 'var(--text-muted)' }}>
                {timestamp}
              </span>
            )}
          </div>
        </div>
      </motion.div>
    );
  },
);

MessageBubble.displayName = 'MessageBubble';

// ─── Content Block Renderer ────────────────────────────────────────────────

interface ContentBlockProps {
  block: ChatContent;
  isUser: boolean;
}

const ContentBlock: React.FC<ContentBlockProps> = React.memo(({ block, isUser }) => {
  switch (block.type) {
    case 'text':
      if (!block.text) return null;
      // User messages: render as plain text (no markdown)
      if (isUser) {
        return (
          <p className="whitespace-pre-wrap leading-relaxed" style={{ fontSize: 'var(--text-base)' }}>
            {block.text}
          </p>
        );
      }
      return <MarkdownRenderer content={block.text} />;

    case 'thinking':
      return <ThinkingBlock thinking={block.thinking} />;

    case 'image':
      if (!block.source?.data) return null;
      return (
        <ImageViewer
          src={block.source.data}
          mediaType={block.source.media_type}
        />
      );

    case 'tool_call':
      return (
        <ToolCard
          entry={{
            toolCallId: block.toolCallId ?? `tc-${Date.now()}`,
            name: block.name,
            phase: 'start',
            args: block.args,
            ts: Date.now(),
            runId: '',
          } satisfies ToolStreamEntry}
        />
      );

    case 'tool_result':
      return (
        <ToolCard
          entry={{
            toolCallId: block.toolCallId ?? `tr-${Date.now()}`,
            name: 'result',
            phase: 'result',
            result: block.result,
            ts: Date.now(),
            runId: '',
          } satisfies ToolStreamEntry}
        />
      );

    default: {
      // Unknown content type — render nothing rather than crashing
      return null;
    }
  }
});

ContentBlock.displayName = 'ContentBlock';

export default MessageBubble;
