/**
 * Corgi Dashboard — Responsive Context Provider
 *
 * Provides breakpoint / orientation info to the entire app
 * using ResizeObserver for performance.
 */
import React, { createContext, useContext, useEffect, useMemo, useRef, useState } from 'react';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

type Breakpoint = 'mobile' | 'tablet' | 'laptop' | 'desktop';
type Orientation = 'portrait' | 'landscape';

interface ResponsiveState {
  breakpoint: Breakpoint;
  orientation: Orientation;
  width: number;
  height: number;
  isMobile: boolean;
  isTablet: boolean;
  isDesktop: boolean;
  isLaptop: boolean;
}

const breakpoints = {
  mobile: 0,
  tablet: 640,
  laptop: 1024,
  desktop: 1440,
} as const;

function resolveBreakpoint(width: number): Breakpoint {
  if (width >= breakpoints.desktop) return 'desktop';
  if (width >= breakpoints.laptop) return 'laptop';
  if (width >= breakpoints.tablet) return 'tablet';
  return 'mobile';
}

/* ------------------------------------------------------------------ */
/*  Context                                                            */
/* ------------------------------------------------------------------ */

const defaultState: ResponsiveState = {
  breakpoint: 'desktop',
  orientation: 'landscape',
  width: 1440,
  height: 900,
  isMobile: false,
  isTablet: false,
  isLaptop: false,
  isDesktop: true,
};

const ResponsiveContext = createContext<ResponsiveState>(defaultState);

/* ------------------------------------------------------------------ */
/*  Provider                                                           */
/* ------------------------------------------------------------------ */

export const ResponsiveProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<ResponsiveState>(() => {
    if (typeof window === 'undefined') return defaultState;
    const w = window.innerWidth;
    const h = window.innerHeight;
    const bp = resolveBreakpoint(w);
    return {
      breakpoint: bp,
      orientation: w >= h ? 'landscape' : 'portrait',
      width: w,
      height: h,
      isMobile: bp === 'mobile',
      isTablet: bp === 'tablet',
      isLaptop: bp === 'laptop',
      isDesktop: bp === 'desktop',
    };
  });

  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width: w, height: h } = entry.contentRect;
        const bp = resolveBreakpoint(w);
        setState({
          breakpoint: bp,
          orientation: w >= h ? 'landscape' : 'portrait',
          width: w,
          height: h,
          isMobile: bp === 'mobile',
          isTablet: bp === 'tablet',
          isLaptop: bp === 'laptop',
          isDesktop: bp === 'desktop',
        });
      }
    });

    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  return (
    <ResponsiveContext.Provider value={state}>
      <div ref={ref} style={{ width: '100%', height: '100%' }}>
        {children}
      </div>
    </ResponsiveContext.Provider>
  );
};

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

export function useResponsive(): ResponsiveState {
  return useContext(ResponsiveContext);
}

export { breakpoints };
export type { Breakpoint, Orientation, ResponsiveState };
