/* ------------------------------------------------------------------ */
/*  Tool category → accent color                                       */
/* ------------------------------------------------------------------ */

type ToolCategory =
  | 'search'
  | 'file'
  | 'exec'
  | 'browser'
  | 'media'
  | 'communication'
  | 'scheduling'
  | 'memory'
  | 'infra'
  | 'session'
  | 'agent'
  | 'default';

const toolCategoryMap: Record<string, ToolCategory> = {
  web_search: 'search',
  web_fetch: 'search',
  read: 'file',
  write: 'file',
  edit: 'file',
  exec: 'exec',
  process: 'exec',
  browser: 'browser',
  image: 'media',
  pdf: 'media',
  tts: 'media',
  message: 'communication',
  cron: 'scheduling',
  memory_search: 'memory',
  memory_get: 'memory',
  gateway: 'infra',
  canvas: 'infra',
  nodes: 'infra',
  sessions_spawn: 'session',
  sessions_send: 'session',
  sessions_list: 'session',
  sessions_history: 'session',
  session_status: 'session',
  subagents: 'agent',
  agents_list: 'agent',
};

const categoryColors: Record<ToolCategory, string> = {
  search: '#4DA6FF',       // info blue
  file: '#00D68F',         // success green
  exec: '#FF5C00',         // accent orange
  browser: '#A855F7',      // purple
  media: '#F472B6',        // pink
  communication: '#FFB800', // warning yellow
  scheduling: '#8888a0',   // muted
  memory: '#C084FC',       // light purple
  infra: '#4DA6FF',        // info blue
  session: '#00D68F',      // success green
  agent: '#FF7A2E',        // orange hover
  default: '#8888a0',      // muted
};

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

/**
 * Returns the Lucide icon component for a given tool name.
 * Falls back to `Zap` for unknown tools.
 */
export function getToolIcon(toolName: string): LucideIcon {
  return toolIconMap[toolName] ?? Zap;
}

/**
 * Returns the accent colour string for a given tool name.
 */
export function getToolColor(toolName: string): string {
  const category = toolCategoryMap[toolName] ?? 'default';
  return categoryColors[category];
}

/**
 * Returns both icon + color for convenience.
 */
export function getToolMeta(toolName: string): { icon: LucideIcon; color: string } {
  return {
    icon: getToolIcon(toolName),
    color: getToolColor(toolName),
  };
}

export { toolIconMap, categoryColors, toolCategoryMap };
