/**
 * ImageViewer — Inline image display with lightbox overlay.
 */
import React, { useState, useCallback, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X } from 'lucide-react';
import { fadeIn } from '@/theme';

interface ImageViewerProps {
  src: string;
  alt?: string;
  mediaType?: string;
}

const ImageViewer: React.FC<ImageViewerProps> = React.memo(({ src, alt, mediaType }) => {
  const [lightboxOpen, setLightboxOpen] = useState(false);

  const imageSrc = src.startsWith('data:') ? src : mediaType ? `data:${mediaType};base64,${src}` : src;

  const open = useCallback(() => setLightboxOpen(true), []);
  const close = useCallback(() => setLightboxOpen(false), []);

  // Close on Escape
  useEffect(() => {
    if (!lightboxOpen) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') close();
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [lightboxOpen, close]);

  return (
    <>
      {/* Inline preview */}
      <img
        src={imageSrc}
        alt={alt ?? 'Image'}
        className="rounded-lg cursor-pointer hover:opacity-90 transition-opacity my-2"
        style={{
          maxWidth: '400px',
          maxHeight: '300px',
          objectFit: 'contain',
          transitionDuration: 'var(--duration-normal)',
        }}
        onClick={open}
        loading="lazy"
      />

      {/* Lightbox */}
      <AnimatePresence>
        {lightboxOpen && (
          <motion.div
            className="fixed inset-0 flex items-center justify-center p-4"
            style={{
              background: 'rgba(0, 0, 0, 0.85)',
              zIndex: 'var(--z-modal)',
              cursor: 'pointer',
            }}
            variants={fadeIn}
            initial="hidden"
            animate="visible"
            exit="hidden"
            onClick={close}
          >
            <button
              className="absolute top-4 right-4 p-2 rounded-full transition-colors"
              style={{
                background: 'var(--bg-tertiary)',
                color: 'var(--text-primary)',
                transitionDuration: 'var(--duration-normal)',
              }}
              onClick={close}
              aria-label="Close lightbox"
            >
              <X size={20} />
            </button>

            <motion.img
              src={imageSrc}
              alt={alt ?? 'Image'}
              className="rounded-lg"
              style={{
                maxWidth: '90vw',
                maxHeight: '90vh',
                objectFit: 'contain',
                cursor: 'default',
              }}
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              transition={{ duration: 0.2 }}
              onClick={(e) => e.stopPropagation()}
            />
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
});

ImageViewer.displayName = 'ImageViewer';

export default ImageViewer;
