/**
 * CommandPaletteProvider — Context for registering commands + controlling open state.
 */
import React, { createContext, useContext, useCallback, useRef, useState, useEffect } from 'react';

// ─── Types ─────────────────────────────────────────────────────────────────

export interface PaletteCommand {
  id: string;
  label: string;
  icon?: React.ReactNode;
  shortcut?: string;
  group: string;
  action: () => void;
  keywords?: string[];
}

interface CommandPaletteContextValue {
  open: () => void;
  close: () => void;
  toggle: () => void;
  isOpen: boolean;
  registerCommand: (cmd: PaletteCommand) => void;
  unregisterCommand: (id: string) => void;
  commands: PaletteCommand[];
}

const CommandPaletteContext = createContext<CommandPaletteContextValue | null>(null);

// ─── Provider ──────────────────────────────────────────────────────────────

export const CommandPaletteProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isOpen, setIsOpen] = useState(false);
  const commandsRef = useRef<Map<string, PaletteCommand>>(new Map());
  const [commands, setCommands] = useState<PaletteCommand[]>([]);

  const open = useCallback(() => setIsOpen(true), []);
  const close = useCallback(() => setIsOpen(false), []);
  const toggle = useCallback(() => setIsOpen((v) => !v), []);

  const registerCommand = useCallback((cmd: PaletteCommand) => {
    commandsRef.current.set(cmd.id, cmd);
    setCommands(Array.from(commandsRef.current.values()));
  }, []);

  const unregisterCommand = useCallback((id: string) => {
    commandsRef.current.delete(id);
    setCommands(Array.from(commandsRef.current.values()));
  }, []);

  return (
    <CommandPaletteContext.Provider
      value={{ open, close, toggle, isOpen, registerCommand, unregisterCommand, commands }}
    >
      {children}
    </CommandPaletteContext.Provider>
  );
};

// ─── Hooks ─────────────────────────────────────────────────────────────────

export function useCommandPalette() {
  const ctx = useContext(CommandPaletteContext);
  if (!ctx) throw new Error('useCommandPalette must be used within CommandPaletteProvider');
  return ctx;
}

/**
 * Register a command on mount, unregister on unmount.
 */
export function useRegisterCommand(id: string, command: Omit<PaletteCommand, 'id'>) {
  const { registerCommand, unregisterCommand } = useCommandPalette();

  useEffect(() => {
    registerCommand({ id, ...command });
    return () => unregisterCommand(id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [id]);
}

export default CommandPaletteProvider;
