/**
 * ContextInjection — Attach large text blocks as hidden context
 *
 * Opens a panel/modal for pasting documentation, error logs, etc.
 * Text is prepended to the next message as context, not sent as a message.
 */
import { useState, useCallback, useMemo, createContext, useContext, type ReactNode } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import { motion, AnimatePresence } from 'framer-motion';
import { Paperclip, X, FileText, Trash2 } from 'lucide-react';
import * as Tooltip from '@radix-ui/react-tooltip';

// ─── Context for injected content ──────────────────────────────────────────

interface ContextInjectionState {
  /** The text to prepend as context */
  contextText: string;
  /** Set context text */
  setContextText: (text: string) => void;
  /** Clear injected context */
  clearContext: () => void;
  /** Whether there's pending context */
  hasContext: boolean;
  /** Consume and return the context (clears it) */
  consumeContext: () => string;
}

const ContextInjectionContext = createContext<ContextInjectionState>({
  contextText: '',
  setContextText: () => {},
  clearContext: () => {},
  hasContext: false,
  consumeContext: () => '',
});

export function useContextInjection() {
  return useContext(ContextInjectionContext);
}

export function ContextInjectionProvider({ children }: { children: ReactNode }) {
  const [contextText, setContextText] = useState('');

  const clearContext = useCallback(() => setContextText(''), []);
  const hasContext = contextText.length > 0;

  const consumeContext = useCallback(() => {
    const text = contextText;
    setContextText('');
    return text;
  }, [contextText]);

  return (
    <ContextInjectionContext.Provider
      value={{ contextText, setContextText, clearContext, hasContext, consumeContext }}
    >
      {children}
    </ContextInjectionContext.Provider>
  );
}

// ─── Trigger Button ────────────────────────────────────────────────────────

export function ContextInjectionButton() {
  const { hasContext } = useContextInjection();
  const [open, setOpen] = useState(false);

  return (
    <Dialog.Root open={open} onOpenChange={setOpen}>
      <Tooltip.Provider delayDuration={300}>
        <Tooltip.Root>
          <Tooltip.Trigger asChild>
            <Dialog.Trigger asChild>
              <button
                className="relative flex items-center justify-center rounded-md p-1.5 transition-all"
                style={{
                  width: '32px',
                  height: '32px',
                  color: hasContext ? 'var(--accent-primary)' : 'var(--text-muted)',
                  background: hasContext ? 'var(--accent-muted)' : 'transparent',
                  border: '1px solid',
                  borderColor: hasContext ? 'var(--accent-primary)' : 'var(--border-subtle)',
                  cursor: 'pointer',
                  transition: 'all var(--transition-fast)',
                }}
              >
                <Paperclip size={16} />
                {hasContext && (
                  <span
                    className="absolute -top-1 -right-1 rounded-full"
                    style={{
                      width: '8px',
                      height: '8px',
                      backgroundColor: 'var(--accent-primary)',
                    }}
                  />
                )}
              </button>
            </Dialog.Trigger>
          </Tooltip.Trigger>
          <Tooltip.Portal>
            <Tooltip.Content
              side="top"
              sideOffset={6}
              className="rounded-md px-2.5 py-1.5"
              style={{
                backgroundColor: 'var(--bg-tertiary)',
                color: 'var(--text-primary)',
                fontSize: 'var(--text-xs)',
                fontFamily: 'var(--font-sans)',
                border: '1px solid var(--border-subtle)',
                boxShadow: 'var(--shadow-medium)',
                zIndex: 'var(--z-tooltip)',
              }}
            >
              {hasContext ? 'Edit attached context' : 'Attach context'}
              <Tooltip.Arrow style={{ fill: 'var(--bg-tertiary)' }} />
            </Tooltip.Content>
          </Tooltip.Portal>
        </Tooltip.Root>
      </Tooltip.Provider>

      <AnimatePresence>
        {open && (
          <Dialog.Portal forceMount>
            <Dialog.Overlay asChild>
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                style={{
                  position: 'fixed',
                  inset: 0,
                  backgroundColor: 'var(--bg-overlay)',
                  zIndex: 'var(--z-modal)',
                }}
              />
            </Dialog.Overlay>
            <Dialog.Content asChild>
              <motion.div
                initial={{ opacity: 0, scale: 0.95, y: 10 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95, y: 10 }}
                transition={{ duration: 0.2, ease: [0.16, 1, 0.3, 1] }}
                className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-lg rounded-xl p-6"
                style={{
                  backgroundColor: 'var(--bg-secondary)',
                  border: '1px solid var(--border-default)',
                  boxShadow: 'var(--shadow-large)',
                  zIndex: 'var(--z-modal)',
                  maxHeight: '80vh',
                  display: 'flex',
                  flexDirection: 'column',
                }}
              >
                <ContextInjectionPanelContent onClose={() => setOpen(false)} />
              </motion.div>
            </Dialog.Content>
          </Dialog.Portal>
        )}
      </AnimatePresence>
    </Dialog.Root>
  );
}

// ─── Panel Content ─────────────────────────────────────────────────────────

function ContextInjectionPanelContent({ onClose }: { onClose: () => void }) {
  const { contextText, setContextText, clearContext } = useContextInjection();
  const [localText, setLocalText] = useState(contextText);

  const stats = useMemo(() => {
    const chars = localText.length;
    const tokens = Math.ceil(chars / 4);
    return { chars, tokens };
  }, [localText]);

  const handleAttach = useCallback(() => {
    setContextText(localText);
    onClose();
  }, [localText, setContextText, onClose]);

  const handleClear = useCallback(() => {
    setLocalText('');
    clearContext();
  }, [clearContext]);

  return (
    <>
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <FileText size={18} style={{ color: 'var(--accent-primary)' }} />
          <Dialog.Title
            style={{
              fontSize: 'var(--text-lg)',
              fontWeight: 'var(--font-semibold)',
              color: 'var(--text-primary)',
              fontFamily: 'var(--font-sans)',
              margin: 0,
            }}
          >
            Attach Context
          </Dialog.Title>
        </div>
        <Dialog.Close asChild>
          <button
            style={{
              color: 'var(--text-muted)',
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              padding: '4px',
            }}
          >
            <X size={18} />
          </button>
        </Dialog.Close>
      </div>

      <Dialog.Description
        style={{
          fontSize: 'var(--text-sm)',
          color: 'var(--text-secondary)',
          fontFamily: 'var(--font-sans)',
          marginBottom: 'var(--space-3)',
        }}
      >
        Paste documentation, error logs, or any text to include as context
        with your next message. This won't be sent as a visible message.
      </Dialog.Description>

      {/* Textarea */}
      <textarea
        value={localText}
        onChange={(e) => setLocalText(e.target.value)}
        placeholder="Paste your context here…"
        className="flex-1 min-h-[200px] w-full rounded-lg p-3 resize-y outline-none"
        style={{
          backgroundColor: 'var(--bg-input)',
          color: 'var(--text-primary)',
          fontSize: 'var(--text-sm)',
          fontFamily: 'var(--font-mono)',
          lineHeight: 'var(--leading-normal)',
          border: '1px solid var(--border-default)',
          transition: 'border-color var(--transition-fast)',
        }}
        onFocus={(e) => {
          e.currentTarget.style.borderColor = 'var(--border-focus)';
        }}
        onBlur={(e) => {
          e.currentTarget.style.borderColor = 'var(--border-default)';
        }}
      />

      {/* Stats */}
      <div
        className="flex items-center justify-between mt-3"
        style={{
          fontSize: 'var(--text-xs)',
          color: 'var(--text-muted)',
          fontFamily: 'var(--font-sans)',
        }}
      >
        <span>
          {stats.chars.toLocaleString()} chars · ~{stats.tokens.toLocaleString()} tokens
        </span>
        {localText && (
          <button
            onClick={handleClear}
            className="flex items-center gap-1 transition-colors"
            style={{
              color: 'var(--error)',
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              fontSize: 'var(--text-xs)',
            }}
          >
            <Trash2 size={12} />
            Clear
          </button>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center justify-end gap-2 mt-4">
        <button
          onClick={onClose}
          className="rounded-lg px-4 py-2 transition-colors"
          style={{
            fontSize: 'var(--text-sm)',
            fontFamily: 'var(--font-sans)',
            fontWeight: 'var(--font-medium)',
            color: 'var(--text-secondary)',
            backgroundColor: 'var(--bg-tertiary)',
            border: '1px solid var(--border-subtle)',
            cursor: 'pointer',
          }}
        >
          Cancel
        </button>
        <button
          onClick={handleAttach}
          disabled={!localText.trim()}
          className="rounded-lg px-4 py-2 transition-colors"
          style={{
            fontSize: 'var(--text-sm)',
            fontFamily: 'var(--font-sans)',
            fontWeight: 'var(--font-medium)',
            color: 'var(--text-inverse)',
            backgroundColor: localText.trim()
              ? 'var(--accent-primary)'
              : 'var(--bg-tertiary)',
            border: 'none',
            cursor: localText.trim() ? 'pointer' : 'default',
            opacity: localText.trim() ? 1 : 0.5,
          }}
        >
          Attach as context
        </button>
      </div>
    </>
  );
}

export default ContextInjectionButton;
