/**
 * Corgi Dashboard — SubAgentSummary
 *
 * Compact summary bar showing agent counts with status dots.
 * Click to open the full panel. Only visible when sub-agents exist.
 */
import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { fadeIn } from '../../theme/animations';

/* ------------------------------------------------------------------ */
/*  Props                                                              */
/* ------------------------------------------------------------------ */

interface SubAgentSummaryProps {
  totalCount: number;
  runningCount: number;
  completedCount: number;
  failedCount: number;
  pendingCount: number;
  onClick: () => void;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const SubAgentSummary: React.FC<SubAgentSummaryProps> = ({
  totalCount,
  runningCount,
  completedCount,
  failedCount,
  pendingCount,
  onClick,
}) => {
  if (totalCount === 0) return null;

  const segments: Array<{ count: number; color: string; label: string }> = [];
  if (runningCount > 0) segments.push({ count: runningCount, color: '#f59e0b', label: 'running' });
  if (pendingCount > 0) segments.push({ count: pendingCount, color: '#6b7280', label: 'pending' });
  if (completedCount > 0) segments.push({ count: completedCount, color: '#10b981', label: 'done' });
  if (failedCount > 0) segments.push({ count: failedCount, color: '#ef4444', label: 'failed' });

  return (
    <AnimatePresence>
      <motion.button
        variants={fadeIn}
        initial="hidden"
        animate="visible"
        exit="hidden"
        onClick={onClick}
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: 'var(--space-2)',
          padding: 'var(--space-1) var(--space-3)',
          background: 'var(--bg-secondary)',
          border: '1px solid var(--border-subtle)',
          borderRadius: 'var(--radius-full)',
          cursor: 'pointer',
          fontSize: 'var(--text-xs)',
          color: 'var(--text-secondary)',
          fontWeight: 'var(--font-medium)',
          transition: 'background 0.15s, border-color 0.15s',
          whiteSpace: 'nowrap',
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = 'var(--bg-tertiary)';
          e.currentTarget.style.borderColor = 'var(--border-default)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = 'var(--bg-secondary)';
          e.currentTarget.style.borderColor = 'var(--border-subtle)';
        }}
      >
        <span>🌳</span>
        <span>
          {totalCount} agent{totalCount !== 1 ? 's' : ''}
        </span>
        <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          {segments.map((seg) => (
            <span
              key={seg.label}
              style={{ display: 'flex', alignItems: 'center', gap: 2 }}
            >
              <span
                style={{
                  width: 6,
                  height: 6,
                  borderRadius: '50%',
                  background: seg.color,
                  display: 'inline-block',
                }}
              />
              <span>{seg.count} {seg.label}</span>
            </span>
          ))}
        </span>
      </motion.button>
    </AnimatePresence>
  );
};

export default SubAgentSummary;
