/**
 * Global app state — Zustand store with localStorage persistence.
 */
import { create } from 'zustand';
import type { ThemeMode } from '../utils/theme';

export type ActiveTab = 'chat' | 'sessions' | 'dashboard' | 'settings';

interface AppState {
  // Theme
  theme: ThemeMode;
  setTheme: (t: ThemeMode) => void;
  cycleTheme: () => void;

  // Sidebar
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
  toggleSidebar: () => void;

  // Active tab (mobile navigation)
  activeTab: ActiveTab;
  setActiveTab: (tab: ActiveTab) => void;

  // Gateway config
  gatewayUrl: string;
  gatewayToken: string;
  setGatewayUrl: (url: string) => void;
  setGatewayToken: (token: string) => void;

  // Settings panel
  settingsOpen: boolean;
  setSettingsOpen: (open: boolean) => void;

  // Cheat sheet
  cheatSheetOpen: boolean;
  setCheatSheetOpen: (open: boolean) => void;
}

function load<T>(key: string, fallback: T): T {
  try {
    const v = localStorage.getItem(key);
    return v !== null ? JSON.parse(v) : fallback;
  } catch {
    return fallback;
  }
}

function save(key: string, value: unknown): void {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch { /* ignore */ }
}

export const useAppStore = create<AppState>((set) => ({
  theme: load<ThemeMode>('corgi-theme', 'dark'),
  setTheme: (t) => { save('corgi-theme', t); set({ theme: t }); },
  cycleTheme: () => set((s) => {
    const next: ThemeMode = s.theme === 'dark' ? 'light' : s.theme === 'light' ? 'auto' : 'dark';
    save('corgi-theme', next);
    return { theme: next };
  }),

  sidebarOpen: load('corgi-sidebar', false),
  setSidebarOpen: (open) => { save('corgi-sidebar', open); set({ sidebarOpen: open }); },
  toggleSidebar: () => set((s) => { const next = !s.sidebarOpen; save('corgi-sidebar', next); return { sidebarOpen: next }; }),

  activeTab: 'chat',
  setActiveTab: (tab) => set({ activeTab: tab }),

  gatewayUrl: load('corgi-gw-url-v2', 'wss://relay-production-aea3.up.railway.app/ws'),
  gatewayToken: load('corgi-gw-token-v2', '005e16c53e33cf367a68b720deca73ec'),
  setGatewayUrl: (url) => { save('corgi-gw-url-v2', url); set({ gatewayUrl: url }); },
  setGatewayToken: (token) => { save('corgi-gw-token-v2', token); set({ gatewayToken: token }); },

  settingsOpen: false,
  setSettingsOpen: (open) => set({ settingsOpen: open }),

  cheatSheetOpen: false,
  setCheatSheetOpen: (open) => set({ cheatSheetOpen: open }),
}));
