/**
 * Corgi Dashboard — CronOverview
 * Compact cron jobs summary. Expandable job list.
 * Fetches via gateway: cron.status + cron.list
 */
import React, { useCallback, useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Clock, ChevronDown, CheckCircle, XCircle, Timer } from 'lucide-react';
import { useGateway } from '../../gateway/hooks';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface CronJob {
  id: string;
  name: string;
  schedule: string;
  lastRun?: string;
  lastRunStatus?: 'ok' | 'error' | 'skipped';
  nextRun?: string;
  nextRunRelative?: string;
  lastRunRelative?: string;
}

interface CronStatusResponse {
  active?: number;
  total?: number;
  nextRunAt?: string;
  jobs?: CronJob[];
}

interface UseCronOverviewReturn {
  jobs: CronJob[];
  activeCount: number;
  nextRunRelative: string | null;
  loading: boolean;
  error: string | null;
  refresh: () => void;
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function relAgo(ms: number): string {
  const secs = Math.floor(Math.abs(ms) / 1000);
  const future = ms < 0;
  if (secs < 60) return future ? 'in <1m' : `${secs}s ago`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return future ? `in ${mins}m` : `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  return future ? `in ${hrs}h` : `${hrs}h ago`;
}

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

export function useCronOverview(): UseCronOverviewReturn {
  const { client } = useGateway();
  const [jobs, setJobs] = useState<CronJob[]>([]);
  const [activeCount, setActiveCount] = useState(0);
  const [nextRunRelative, setNextRunRelative] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchCron = useCallback(async () => {
    if (!client) return;
    setLoading(true);
    setError(null);
    try {
      // Try cron.list first; fall back to cron.status
      let cronJobs: CronJob[] = [];
      let active = 0;
      let nextAt: string | undefined;

      try {
        const listRes = await client.request<{ jobs?: CronJob[]; count?: number }>('cron.list');
        if (listRes?.jobs) {
          cronJobs = listRes.jobs;
        }
      } catch { /* cron.list may not exist */ }

      try {
        const statusRes = await client.request<CronStatusResponse>('cron.status');
        if (statusRes) {
          active = statusRes.active ?? cronJobs.filter((j) => j.lastRunStatus !== 'error').length;
          nextAt = statusRes.nextRunAt;
          // Merge job data if not already populated
          if (!cronJobs.length && statusRes.jobs) {
            cronJobs = statusRes.jobs;
          }
        }
      } catch { /* cron.status may not exist */ }

      // Enrich relative times
      const enriched = cronJobs.map((j) => ({
        ...j,
        lastRunRelative: j.lastRun ? relAgo(Date.now() - new Date(j.lastRun).getTime()) : undefined,
        nextRunRelative: j.nextRun ? relAgo(Date.now() - new Date(j.nextRun).getTime()) : undefined,
      }));

      setJobs(enriched);
      setActiveCount(active || enriched.length);
      setNextRunRelative(nextAt ? relAgo(Date.now() - new Date(nextAt).getTime()) : null);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Cron unavailable');
    } finally {
      setLoading(false);
    }
  }, [client]);

  useEffect(() => {
    fetchCron();
    const t = setInterval(fetchCron, 60_000);
    return () => clearInterval(t);
  }, [fetchCron]);

  return { jobs, activeCount, nextRunRelative, loading, error, refresh: fetchCron };
}

/* ------------------------------------------------------------------ */
/*  CronOverview (compact + expandable)                                */
/* ------------------------------------------------------------------ */

export interface CronOverviewProps {
  /** Force compact inline mode (used in StatusBar) */
  compact?: boolean;
  className?: string;
  style?: React.CSSProperties;
}

export const CronOverview: React.FC<CronOverviewProps> = ({ compact = false, className = '', style }) => {
  const { jobs, activeCount, nextRunRelative, loading, error } = useCronOverview();
  const [expanded, setExpanded] = useState(false);

  if (compact) {
    // Inline status bar mode
    if (error || (!loading && jobs.length === 0)) {
      return (
        <span style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: 4, ...style }}>
          <Timer size={10} />
          <span>—</span>
        </span>
      );
    }
    return (
      <span
        className={className}
        style={{
          fontSize: 'var(--text-xs)',
          color: 'var(--text-muted)',
          display: 'flex',
          alignItems: 'center',
          gap: 4,
          cursor: 'default',
          userSelect: 'none',
          ...style,
        }}
        title={nextRunRelative ? `Next: ${nextRunRelative}` : undefined}
      >
        <Timer size={10} style={{ flexShrink: 0 }} />
        <span>
          {activeCount} job{activeCount !== 1 ? 's' : ''}
          {nextRunRelative && ` · next ${nextRunRelative}`}
        </span>
      </span>
    );
  }

  // Full section mode
  return (
    <div
      className={className}
      style={{
        background: 'var(--bg-secondary)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 'var(--radius-lg)',
        overflow: 'hidden',
        ...style,
      }}
    >
      {/* Header */}
      <button
        onClick={() => setExpanded((v) => !v)}
        style={{
          width: '100%',
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--space-2)',
          padding: 'var(--space-2) var(--space-3)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
          color: 'var(--text-secondary)',
          fontSize: 'var(--text-xs)',
        }}
      >
        <Clock size={12} style={{ flexShrink: 0 }} />
        <span style={{ color: 'var(--text-primary)', fontWeight: 'var(--font-semibold)' }}>Cron</span>

        {loading ? (
          <span style={{ color: 'var(--text-muted)' }}>loading…</span>
        ) : error ? (
          <span style={{ color: 'var(--text-muted)' }}>unavailable</span>
        ) : (
          <span style={{ color: 'var(--text-muted)' }}>
            {activeCount} active{nextRunRelative ? ` · next ${nextRunRelative}` : ''}
          </span>
        )}

        <span style={{ flex: 1 }} />
        <motion.span
          animate={{ rotate: expanded ? 180 : 0 }}
          transition={{ duration: 0.2 }}
          style={{ display: 'flex' }}
        >
          <ChevronDown size={12} />
        </motion.span>
      </button>

      <AnimatePresence initial={false}>
        {expanded && (
          <motion.div
            key="cron-body"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.22, ease: [0.16, 1, 0.3, 1] }}
            style={{ overflow: 'hidden' }}
          >
            <div
              style={{
                borderTop: '1px solid var(--border-subtle)',
                padding: 'var(--space-2) var(--space-3)',
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--space-1)',
              }}
            >
              {jobs.length === 0 && (
                <p style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)', textAlign: 'center', padding: 'var(--space-2)' }}>
                  No cron jobs configured.
                </p>
              )}
              {jobs.map((job) => (
                <div
                  key={job.id}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 'var(--space-2)',
                    padding: 'var(--space-1_5) var(--space-2)',
                    background: 'var(--bg-tertiary)',
                    borderRadius: 'var(--radius-md)',
                    fontSize: 'var(--text-xs)',
                  }}
                >
                  {/* Status icon */}
                  <span>
                    {job.lastRunStatus === 'ok' ? (
                      <CheckCircle size={11} style={{ color: 'var(--success)' }} />
                    ) : job.lastRunStatus === 'error' ? (
                      <XCircle size={11} style={{ color: 'var(--error)' }} />
                    ) : (
                      <Clock size={11} style={{ color: 'var(--text-muted)' }} />
                    )}
                  </span>

                  {/* Name */}
                  <span
                    style={{
                      flex: 1,
                      color: 'var(--text-primary)',
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                    title={job.name}
                  >
                    {job.name}
                  </span>

                  {/* Schedule */}
                  <span
                    style={{
                      fontFamily: 'var(--font-mono)',
                      color: 'var(--text-muted)',
                      fontSize: '0.625rem',
                      flexShrink: 0,
                    }}
                  >
                    {job.schedule}
                  </span>

                  {/* Next run */}
                  {job.nextRunRelative && (
                    <span style={{ color: 'var(--info)', flexShrink: 0 }}>
                      {job.nextRunRelative}
                    </span>
                  )}
                </div>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default CronOverview;
