/**
 * ToolCard — Primary tool invocation card for the chat stream.
 *
 * Header: icon + label + status + elapsed time.
 * Body (collapsible): args display + result.
 * Left border coloured by tool category.
 */
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronRight, Loader2, CheckCircle2, XCircle, ChevronDown } from 'lucide-react';
import { getToolIcon, getToolColor, toolCardExpand, toolCardCollapse } from '@/theme';
import type { ToolStreamEntry } from '@/gateway/types';
import ToolArgDisplay from './ToolArgDisplay';
import TerminalOutput from './TerminalOutput';
import FileViewer from './FileViewer';

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function humanLabel(name: string): string {
  return name
    .replace(/_/g, ' ')
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

function formatElapsed(ms: number): string {
  if (ms < 1000) return `${Math.round(ms)}ms`;
  return `${(ms / 1000).toFixed(1)}s`;
}

function isError(entry: ToolStreamEntry): boolean {
  if (!entry.result) return false;
  const r = typeof entry.result === 'string' ? entry.result : JSON.stringify(entry.result);
  return /error|failed|exception/i.test(r.slice(0, 200));
}

function resultToString(result: unknown): string {
  if (typeof result === 'string') return result;
  if (result == null) return '';
  try {
    return JSON.stringify(result, null, 2);
  } catch {
    return String(result);
  }
}

function asRecord(v: unknown): Record<string, unknown> {
  if (v && typeof v === 'object' && !Array.isArray(v)) return v as Record<string, unknown>;
  return {};
}

/* ------------------------------------------------------------------ */
/*  Elapsed timer hook                                                 */
/* ------------------------------------------------------------------ */

function useElapsed(startedAt: number, isRunning: boolean): number {
  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    if (!isRunning) return;
    const id = setInterval(() => setNow(Date.now()), 100);
    return () => clearInterval(id);
  }, [isRunning]);

  return isRunning ? now - startedAt : 0;
}

/* ------------------------------------------------------------------ */
/*  Result renderer                                                    */
/* ------------------------------------------------------------------ */

const RESULT_PREVIEW_LEN = 500;

const ResultDisplay: React.FC<{ entry: ToolStreamEntry }> = React.memo(({ entry }) => {
  const [showFull, setShowFull] = useState(false);
  const text = resultToString(entry.result);
  const errored = isError(entry);
  const isLong = text.length > RESULT_PREVIEW_LEN;
  const display = isLong && !showFull ? text.slice(0, RESULT_PREVIEW_LEN) : text;

  // Special renderers
  if (entry.name === 'exec' || entry.name === 'process') {
    const args = asRecord(entry.args);
    // Try to extract exit code from result
    const resultObj = asRecord(entry.result);
    const exitCode = typeof resultObj.exitCode === 'number' ? resultObj.exitCode : null;
    const output = typeof resultObj.stdout === 'string'
      ? resultObj.stdout
      : text;
    return (
      <TerminalOutput
        command={typeof args.command === 'string' ? args.command : undefined}
        output={output}
        exitCode={exitCode}
      />
    );
  }

  if (
    (entry.name === 'read' || entry.name === 'write') &&
    text.length > 0
  ) {
    const args = asRecord(entry.args);
    const filePath =
      String(args.file_path || args.path || args.file || 'file');
    return <FileViewer filePath={filePath} content={text} />;
  }

  if (entry.name === 'edit') {
    const args = asRecord(entry.args);
    const filePath =
      String(args.file_path || args.path || args.file || 'file');
    if (args.old_string && args.new_string) {
      return (
        <FileViewer
          filePath={filePath}
          content={text}
          oldText={String(args.old_string)}
          newText={String(args.new_string)}
        />
      );
    }
  }

  if (!text) return null;

  return (
    <div
      className="rounded px-3 py-2 text-sm"
      style={{
        background: errored ? 'var(--error-muted)' : 'var(--bg-primary)',
        border: '1px solid var(--border-subtle)',
        fontFamily: 'var(--font-mono)',
        fontSize: 'var(--text-sm)',
        lineHeight: 'var(--leading-snug)',
        color: errored ? 'var(--error)' : 'var(--text-secondary)',
        whiteSpace: 'pre-wrap',
        wordBreak: 'break-word',
      }}
    >
      {display}
      {isLong && (
        <button
          onClick={() => setShowFull(!showFull)}
          className="block mt-1 text-xs font-medium"
          style={{ color: 'var(--accent-primary)' }}
        >
          {showFull ? 'Show less' : `Show more (${text.length.toLocaleString()} chars)`}
        </button>
      )}
    </div>
  );
});

ResultDisplay.displayName = 'ResultDisplay';

/* ------------------------------------------------------------------ */
/*  ToolCard                                                           */
/* ------------------------------------------------------------------ */

export interface ToolCardProps {
  entry: ToolStreamEntry;
  /** Start collapsed after completion */
  defaultCollapsed?: boolean;
}

const ToolCard: React.FC<ToolCardProps> = React.memo(({ entry, defaultCollapsed = true }) => {
  const isRunning = entry.phase !== 'result';
  const errored = !isRunning && isError(entry);
  const elapsed = useElapsed(entry.ts, isRunning);
  const finalElapsed = !isRunning && entry.result ? entry.ts - entry.ts : 0; // fallback

  // Auto-collapse after result arrives
  const [expanded, setExpanded] = useState(!defaultCollapsed || isRunning);
  useEffect(() => {
    if (!isRunning && defaultCollapsed) {
      // Slight delay so the user sees the result flash
      const t = setTimeout(() => setExpanded(false), 800);
      return () => clearTimeout(t);
    }
  }, [isRunning, defaultCollapsed]);

  const Icon = getToolIcon(entry.name);
  const color = getToolColor(entry.name);
  const label = humanLabel(entry.name);

  const toggle = useCallback(() => setExpanded((p) => !p), []);

  return (
    <div
      className="rounded-lg overflow-hidden my-1"
      style={{
        background: 'var(--bg-secondary)',
        border: '1px solid var(--border-subtle)',
        borderLeft: `3px solid ${color}`,
      }}
    >
      {/* Header */}
      <button
        onClick={toggle}
        className="w-full flex items-center gap-2 px-3 py-2 text-left transition-colors hover:bg-[rgba(255,255,255,0.02)]"
        style={{ cursor: 'pointer' }}
      >
        {/* Icon */}
        <span
          className="shrink-0 flex items-center justify-center rounded"
          style={{
            width: 22,
            height: 22,
            background: `${color}18`,
          }}
        >
          <Icon size={13} style={{ color }} />
        </span>

        {/* Label */}
        <span
          className="font-medium text-sm truncate"
          style={{ color: 'var(--text-primary)' }}
        >
          {label}
        </span>

        {/* Spacer */}
        <span className="flex-1" />

        {/* Status */}
        {isRunning && (
          <Loader2
            size={14}
            className="animate-spin shrink-0"
            style={{ color: 'var(--warning)' }}
          />
        )}
        {!isRunning && !errored && (
          <CheckCircle2 size={14} className="shrink-0" style={{ color: 'var(--success)' }} />
        )}
        {errored && (
          <XCircle size={14} className="shrink-0" style={{ color: 'var(--error)' }} />
        )}

        {/* Elapsed */}
        <span
          className="text-xs font-mono shrink-0"
          style={{ color: 'var(--text-muted)', minWidth: '3rem', textAlign: 'right' }}
        >
          {isRunning ? formatElapsed(elapsed) : ''}
        </span>

        {/* Chevron */}
        <motion.span
          animate={{ rotate: expanded ? 90 : 0 }}
          transition={{ duration: 0.15 }}
          className="shrink-0"
        >
          <ChevronRight size={14} style={{ color: 'var(--text-muted)' }} />
        </motion.span>
      </button>

      {/* Body */}
      <AnimatePresence initial={false}>
        {expanded && (
          <motion.div
            key="body"
            variants={toolCardExpand}
            initial="collapsed"
            animate="expanded"
            exit="collapsed"
          >
            <div
              className="px-3 pb-3 space-y-2"
              style={{ borderTop: '1px solid var(--border-subtle)' }}
            >
              {/* Arguments */}
              {entry.args != null && (
                <div className="pt-2">
                  <ToolArgDisplay toolName={entry.name} args={entry.args} />
                </div>
              )}

              {/* Result */}
              {entry.phase === 'result' && entry.result != null && (
                <div className="pt-1">
                  <ResultDisplay entry={entry} />
                </div>
              )}

              {/* Running indicator */}
              {isRunning && (
                <div
                  className="flex items-center gap-2 pt-1 text-xs"
                  style={{ color: 'var(--text-muted)' }}
                >
                  <Loader2 size={12} className="animate-spin" />
                  Running…
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});

ToolCard.displayName = 'ToolCard';

export default ToolCard;
