/**
 * Corgi Dashboard — NodeStatus
 * Shows paired nodes/devices from gateway: node.list
 */
import React, { useCallback, useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Smartphone, Monitor, HardDrive, Radio, ChevronDown } from 'lucide-react';
import { useGateway } from '../../gateway/hooks';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type NodePlatform = 'ios' | 'android' | 'macos' | 'windows' | 'linux' | 'unknown';

export interface NodeEntry {
  id: string;
  name: string;
  platform?: string;
  lastSeen?: string;
  lastSeenRelative?: string;
  online?: boolean;
}

interface UseNodeStatusReturn {
  nodes: NodeEntry[];
  onlineCount: number;
  loading: boolean;
  error: string | null;
  refresh: () => void;
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function relAgo(ms: number): string {
  const secs = Math.floor(ms / 1000);
  if (secs < 60) return 'just now';
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  return `${days}d ago`;
}

function platformIcon(platform?: string): React.ReactNode {
  const p = (platform ?? '').toLowerCase();
  if (p.includes('ios') || p.includes('iphone') || p.includes('ipad')) return <Smartphone size={11} />;
  if (p.includes('android')) return <Smartphone size={11} />;
  if (p.includes('mac')) return <Monitor size={11} />;
  if (p.includes('win')) return <Monitor size={11} />;
  if (p.includes('linux')) return <HardDrive size={11} />;
  return <Radio size={11} />;
}

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

export function useNodeStatus(): UseNodeStatusReturn {
  const { client } = useGateway();
  const [nodes, setNodes] = useState<NodeEntry[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchNodes = useCallback(async () => {
    if (!client) return;
    setLoading(true);
    setError(null);
    try {
      const res = await client.request<{
        nodes?: NodeEntry[];
        devices?: NodeEntry[];
        count?: number;
      }>('node.list');

      const raw = res?.nodes ?? res?.devices ?? [];
      const now = Date.now();

      const enriched = raw.map((n) => {
        const lastSeenMs = n.lastSeen ? now - new Date(n.lastSeen).getTime() : null;
        const online = lastSeenMs !== null ? lastSeenMs < 5 * 60 * 1000 : (n.online ?? false);
        return {
          ...n,
          online,
          lastSeenRelative: lastSeenMs !== null ? relAgo(lastSeenMs) : undefined,
        };
      });

      setNodes(enriched);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Nodes unavailable');
    } finally {
      setLoading(false);
    }
  }, [client]);

  useEffect(() => {
    fetchNodes();
    const t = setInterval(fetchNodes, 30_000);
    return () => clearInterval(t);
  }, [fetchNodes]);

  const onlineCount = nodes.filter((n) => n.online).length;

  return { nodes, onlineCount, loading, error, refresh: fetchNodes };
}

/* ------------------------------------------------------------------ */
/*  NodeStatus Component                                               */
/* ------------------------------------------------------------------ */

export interface NodeStatusProps {
  compact?: boolean;
  className?: string;
  style?: React.CSSProperties;
}

export const NodeStatus: React.FC<NodeStatusProps> = ({ compact = false, className = '', style }) => {
  const { nodes, onlineCount, loading, error } = useNodeStatus();
  const [expanded, setExpanded] = useState(false);

  if (compact) {
    // Inline status bar mode
    if (error || (!loading && nodes.length === 0)) {
      return (
        <span style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: 4, ...style }}>
          <Radio size={10} />
          <span>—</span>
        </span>
      );
    }
    return (
      <span
        className={className}
        style={{
          fontSize: 'var(--text-xs)',
          color: onlineCount > 0 ? 'var(--success)' : 'var(--text-muted)',
          display: 'flex',
          alignItems: 'center',
          gap: 4,
          cursor: 'default',
          userSelect: 'none',
          ...style,
        }}
        title={`${onlineCount}/${nodes.length} nodes online`}
      >
        <Radio size={10} style={{ flexShrink: 0 }} />
        <span>
          {onlineCount}/{nodes.length}
        </span>
      </span>
    );
  }

  // Full section mode
  return (
    <div
      className={className}
      style={{
        background: 'var(--bg-secondary)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 'var(--radius-lg)',
        overflow: 'hidden',
        ...style,
      }}
    >
      {/* Header */}
      <button
        onClick={() => setExpanded((v) => !v)}
        style={{
          width: '100%',
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--space-2)',
          padding: 'var(--space-2) var(--space-3)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
          fontSize: 'var(--text-xs)',
        }}
      >
        <Radio size={12} style={{ flexShrink: 0, color: 'var(--text-muted)' }} />
        <span style={{ color: 'var(--text-primary)', fontWeight: 'var(--font-semibold)' }}>Nodes</span>

        {loading ? (
          <span style={{ color: 'var(--text-muted)' }}>loading…</span>
        ) : error ? (
          <span style={{ color: 'var(--text-muted)' }}>—</span>
        ) : (
          <span style={{ color: 'var(--text-muted)' }}>
            {onlineCount}/{nodes.length} online
          </span>
        )}

        <span style={{ flex: 1 }} />
        <motion.span
          animate={{ rotate: expanded ? 180 : 0 }}
          transition={{ duration: 0.2 }}
          style={{ display: 'flex' }}
        >
          <ChevronDown size={12} style={{ color: 'var(--text-muted)' }} />
        </motion.span>
      </button>

      <AnimatePresence initial={false}>
        {expanded && (
          <motion.div
            key="nodes-body"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.22, ease: [0.16, 1, 0.3, 1] }}
            style={{ overflow: 'hidden' }}
          >
            <div
              style={{
                borderTop: '1px solid var(--border-subtle)',
                padding: 'var(--space-2) var(--space-3)',
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--space-1)',
              }}
            >
              {nodes.length === 0 && (
                <p style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)', textAlign: 'center', padding: 'var(--space-2)' }}>
                  No paired nodes.
                </p>
              )}
              {nodes.map((node) => (
                <div
                  key={node.id}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 'var(--space-2)',
                    padding: 'var(--space-1_5) var(--space-2)',
                    background: 'var(--bg-tertiary)',
                    borderRadius: 'var(--radius-md)',
                    fontSize: 'var(--text-xs)',
                  }}
                >
                  {/* Status dot */}
                  <div
                    style={{
                      width: 6,
                      height: 6,
                      borderRadius: 'var(--radius-full)',
                      background: node.online ? 'var(--success)' : 'var(--text-muted)',
                      flexShrink: 0,
                    }}
                  />

                  {/* Platform icon */}
                  <span style={{ color: 'var(--text-muted)', display: 'flex', alignItems: 'center' }}>
                    {platformIcon(node.platform)}
                  </span>

                  {/* Name */}
                  <span
                    style={{
                      flex: 1,
                      color: 'var(--text-primary)',
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                    title={node.name}
                  >
                    {node.name}
                  </span>

                  {/* Platform */}
                  {node.platform && (
                    <span style={{ color: 'var(--text-muted)', fontSize: '0.625rem', textTransform: 'capitalize', flexShrink: 0 }}>
                      {node.platform}
                    </span>
                  )}

                  {/* Last seen */}
                  {node.lastSeenRelative && (
                    <span style={{ color: node.online ? 'var(--success)' : 'var(--text-muted)', flexShrink: 0 }}>
                      {node.lastSeenRelative}
                    </span>
                  )}
                </div>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default NodeStatus;
