/**
 * ToolCardGroup — Collapsible group of consecutive tool cards.
 *
 * Shows a compact "🔧 Used N tools" header with mini icon row,
 * expands to individual ToolCards.
 */
import React, { useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronRight, Wrench } from 'lucide-react';
import { getToolIcon, getToolColor, toolCardExpand } from '@/theme';
import type { ToolStreamEntry } from '@/gateway/types';
import ToolCard from './ToolCard';

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

interface ToolCardGroupProps {
  entries: ToolStreamEntry[];
  /** Default collapsed state for the group itself */
  defaultCollapsed?: boolean;
}

const ToolCardGroup: React.FC<ToolCardGroupProps> = React.memo(
  ({ entries, defaultCollapsed = true }) => {
    const [expanded, setExpanded] = useState(!defaultCollapsed);
    const toggle = useCallback(() => setExpanded((p) => !p), []);

    // Single tool → just render the card directly
    if (entries.length === 1) {
      return <ToolCard entry={entries[0]} />;
    }

    // Unique tool names for mini icons
    const uniqueNames = Array.from(new Set(entries.map((e) => e.name)));
    const allDone = entries.every((e) => e.phase === 'result');

    return (
      <div
        className="rounded-lg overflow-hidden my-1"
        style={{
          background: 'var(--bg-secondary)',
          border: '1px solid var(--border-subtle)',
        }}
      >
        {/* Group header */}
        <button
          onClick={toggle}
          className="w-full flex items-center gap-2 px-3 py-2 text-left transition-colors hover:bg-[rgba(255,255,255,0.02)]"
          style={{ cursor: 'pointer' }}
        >
          <Wrench size={14} style={{ color: 'var(--text-muted)', flexShrink: 0 }} />

          <span
            className="font-medium text-sm"
            style={{ color: 'var(--text-primary)' }}
          >
            Used {entries.length} tools
          </span>

          {/* Mini icon row */}
          <span className="flex items-center gap-1 ml-1">
            {uniqueNames.slice(0, 6).map((name) => {
              const Icon = getToolIcon(name);
              const color = getToolColor(name);
              return (
                <span
                  key={name}
                  className="flex items-center justify-center rounded"
                  style={{
                    width: 18,
                    height: 18,
                    background: `${color}18`,
                  }}
                  title={name}
                >
                  <Icon size={11} style={{ color }} />
                </span>
              );
            })}
            {uniqueNames.length > 6 && (
              <span className="text-xs" style={{ color: 'var(--text-muted)' }}>
                +{uniqueNames.length - 6}
              </span>
            )}
          </span>

          <span className="flex-1" />

          {/* Status badge */}
          {allDone && (
            <span
              className="text-xs px-1.5 py-0.5 rounded"
              style={{ color: 'var(--success)', background: 'var(--success-muted)' }}
            >
              done
            </span>
          )}

          <motion.span
            animate={{ rotate: expanded ? 90 : 0 }}
            transition={{ duration: 0.15 }}
            className="shrink-0"
          >
            <ChevronRight size={14} style={{ color: 'var(--text-muted)' }} />
          </motion.span>
        </button>

        {/* Expanded cards */}
        <AnimatePresence initial={false}>
          {expanded && (
            <motion.div
              key="group-body"
              variants={toolCardExpand}
              initial="collapsed"
              animate="expanded"
              exit="collapsed"
            >
              <div
                className="px-2 pb-2 space-y-1"
                style={{ borderTop: '1px solid var(--border-subtle)' }}
              >
                {entries.map((entry) => (
                  <ToolCard
                    key={entry.toolCallId}
                    entry={entry}
                    defaultCollapsed
                  />
                ))}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    );
  },
);

ToolCardGroup.displayName = 'ToolCardGroup';

export default ToolCardGroup;
