/**
 * Corgi Dashboard — Skeleton Loading Component
 */
import React from 'react';
import { motion } from 'framer-motion';

type SkeletonVariant = 'text' | 'circle' | 'rect' | 'card';

interface SkeletonProps {
  variant?: SkeletonVariant;
  width?: string | number;
  height?: string | number;
  className?: string;
  /** Number of text lines to render (only for variant="text") */
  lines?: number;
}

const shimmerStyle: React.CSSProperties = {
  backgroundImage:
    'linear-gradient(90deg, var(--bg-tertiary) 0%, var(--border-subtle) 50%, var(--bg-tertiary) 100%)',
  backgroundSize: '200% 100%',
};

const variantDefaults: Record<SkeletonVariant, { width: string; height: string; borderRadius: string }> = {
  text: { width: '100%', height: '0.9375rem', borderRadius: 'var(--radius-sm)' },
  circle: { width: '2.5rem', height: '2.5rem', borderRadius: 'var(--radius-full)' },
  rect: { width: '100%', height: '4rem', borderRadius: 'var(--radius-md)' },
  card: { width: '100%', height: '8rem', borderRadius: 'var(--radius-lg)' },
};

export const Skeleton: React.FC<SkeletonProps> = ({
  variant = 'rect',
  width,
  height,
  className = '',
  lines = 1,
}) => {
  const defaults = variantDefaults[variant];

  const baseStyle: React.CSSProperties = {
    ...shimmerStyle,
    width: width ?? defaults.width,
    height: height ?? defaults.height,
    borderRadius: defaults.borderRadius,
    display: 'block',
  };

  if (variant === 'text' && lines > 1) {
    return (
      <div className={`flex flex-col gap-2 ${className}`}>
        {Array.from({ length: lines }).map((_, i) => (
          <motion.span
            key={i}
            style={{
              ...baseStyle,
              width: i === lines - 1 ? '60%' : '100%',
            }}
            initial={{ backgroundPosition: '-200% 0' }}
            animate={{ backgroundPosition: '200% 0' }}
            transition={{ duration: 1.5, repeat: Infinity, ease: 'linear', delay: i * 0.1 }}
          />
        ))}
      </div>
    );
  }

  return (
    <motion.div
      className={className}
      style={baseStyle}
      initial={{ backgroundPosition: '-200% 0' }}
      animate={{ backgroundPosition: '200% 0' }}
      transition={{ duration: 1.5, repeat: Infinity, ease: 'linear' }}
    />
  );
};

/** Pre-composed skeleton for a chat message */
export const MessageSkeleton: React.FC = () => (
  <div className="flex gap-3 p-4">
    <Skeleton variant="circle" width="2rem" height="2rem" />
    <div className="flex-1 flex flex-col gap-2">
      <Skeleton variant="text" width="30%" />
      <Skeleton variant="text" lines={3} />
    </div>
  </div>
);

/** Pre-composed skeleton for a card */
export const CardSkeleton: React.FC = () => (
  <div
    style={{
      background: 'var(--bg-secondary)',
      border: '1px solid var(--border-subtle)',
      borderRadius: 'var(--radius-lg)',
      padding: 'var(--space-4)',
    }}
    className="flex flex-col gap-3"
  >
    <div className="flex items-center gap-3">
      <Skeleton variant="circle" width="2rem" height="2rem" />
      <Skeleton variant="text" width="40%" />
    </div>
    <Skeleton variant="text" lines={2} />
    <Skeleton variant="rect" height="2rem" />
  </div>
);

export default Skeleton;
