import type {
  GatewayClientOptions,
  GatewayRequestFrame,
  GatewayResponseFrame,
  GatewayEventFrame,
  GatewayHelloOk,
  ConnectParams,
} from './types';
import { generateUUID, parseFrame } from './utils';

// ─── Reconnect Config ──────────────────────────────────────────────────────

const RECONNECT_INITIAL_MS = 800;
const RECONNECT_MULTIPLIER = 1.7;
const RECONNECT_MAX_MS = 15_000;
const REQUEST_TIMEOUT_MS = 30_000;

/** Error codes that should NOT trigger reconnect */
const AUTH_ERROR_CODES = new Set([
  'auth.missing_token',
  'auth.invalid_token',
  'auth.rate_limited',
  'auth.password_mismatch',
  'auth.unauthorized',
]);

// ─── Pending Request ───────────────────────────────────────────────────────

interface PendingRequest {
  resolve: (payload: unknown) => void;
  reject: (error: Error) => void;
  timer: ReturnType<typeof setTimeout>;
}

// ─── Client Class ──────────────────────────────────────────────────────────

export class GatewayClient {
  private opts: GatewayClientOptions;
  private ws: WebSocket | null = null;
  private instanceId: string;
  private pendingRequests = new Map<string, PendingRequest>();
  private lastSeq = 0;
  private reconnectDelay = RECONNECT_INITIAL_MS;
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private intentionalClose = false;
  private suppressReconnect = false;
  private _connected = false;

  constructor(opts: GatewayClientOptions) {
    this.opts = opts;
    this.instanceId = generateUUID();
  }

  // ─── Public API ─────────────────────────────────────────────

  get connected(): boolean {
    return this._connected;
  }

  connect(): void {
    this.intentionalClose = false;
    this.suppressReconnect = false;
    this.openSocket();
  }

  disconnect(): void {
    this.intentionalClose = true;
    this.suppressReconnect = true;
    this.clearReconnectTimer();
    this.closeSocket();
  }

  reconnect(): void {
    this.closeSocket();
    this.intentionalClose = false;
    this.suppressReconnect = false;
    this.reconnectDelay = RECONNECT_INITIAL_MS;
    this.openSocket();
  }

  async request<T = unknown>(method: string, params?: unknown): Promise<T> {
    return new Promise<T>((resolve, reject) => {
      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
        reject(new Error('WebSocket not connected'));
        return;
      }

      const id = generateUUID();
      const frame: GatewayRequestFrame = { type: 'req', id, method };
      if (params !== undefined) frame.params = params;

      const timer = setTimeout(() => {
        this.pendingRequests.delete(id);
        reject(new Error(`Request ${method} timed out after ${REQUEST_TIMEOUT_MS}ms`));
      }, REQUEST_TIMEOUT_MS);

      this.pendingRequests.set(id, {
        resolve: resolve as (v: unknown) => void,
        reject,
        timer,
      });

      try {
        this.ws.send(JSON.stringify(frame));
      } catch (err) {
        this.pendingRequests.delete(id);
        clearTimeout(timer);
        reject(err);
      }
    });
  }

  // ─── Socket Lifecycle ───────────────────────────────────────

  private openSocket(): void {
    this.closeSocket();

    try {
      this.ws = new WebSocket(this.opts.url);
    } catch (err) {
      this.scheduleReconnect();
      return;
    }

    this.ws.onopen = () => {
      // Wait for connect.challenge event; don't set connected yet
    };

    this.ws.onmessage = (ev) => {
      this.handleMessage(ev.data as string);
    };

    this.ws.onerror = () => {
      // onerror is always followed by onclose
    };

    this.ws.onclose = (ev) => {
      const wasConnected = this._connected;
      this._connected = false;
      this.rejectAllPending('WebSocket closed');

      if (wasConnected) {
        this.opts.onDisconnect?.(ev.reason || `code ${ev.code}`);
      }

      if (!this.intentionalClose && !this.suppressReconnect) {
        this.scheduleReconnect();
      }
    };
  }

  private closeSocket(): void {
    if (this.ws) {
      // Remove handlers to avoid spurious events
      this.ws.onopen = null;
      this.ws.onmessage = null;
      this.ws.onerror = null;
      this.ws.onclose = null;
      try {
        this.ws.close();
      } catch {
        // ignore
      }
      this.ws = null;
    }
    this._connected = false;
  }

  // ─── Message Handling ───────────────────────────────────────

  private handleMessage(raw: string): void {
    const frame = parseFrame(raw);
    if (!frame) return;

    switch (frame.type) {
      case 'event':
        this.handleEvent(frame as unknown as GatewayEventFrame);
        break;
      case 'res':
        this.handleResponse(frame as unknown as GatewayResponseFrame);
        break;
      default:
        // Ignore unknown frame types
        break;
    }
  }

  private handleEvent(ev: GatewayEventFrame): void {
    // Sequence tracking
    if (ev.seq !== undefined) {
      const expected = this.lastSeq + 1;
      if (this.lastSeq > 0 && ev.seq > expected) {
        this.opts.onGap?.(expected, ev.seq);
      }
      if (ev.seq > this.lastSeq) {
        this.lastSeq = ev.seq;
      }
    }

    // Handle connect.challenge
    if (ev.event === 'connect.challenge') {
      const nonce = (ev.payload as { nonce?: string })?.nonce;
      this.sendConnectRequest(nonce);
      return;
    }

    // Handle application-level ping — respond with pong to keep connection alive
    if (ev.event === 'ping' || ev.event === 'heartbeat') {
      this.sendPong();
      return;
    }

    // Route to callback
    this.opts.onEvent?.(ev);
  }

  private sendPong(): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
    try {
      // Respond with a pong frame (no-op request the gateway will ignore)
      const frame = { type: 'req', id: generateUUID(), method: 'pong' };
      this.ws.send(JSON.stringify(frame));
    } catch {
      // ignore send errors
    }
  }

  private handleResponse(res: GatewayResponseFrame): void {
    const pending = this.pendingRequests.get(res.id);
    if (!pending) return;

    this.pendingRequests.delete(res.id);
    clearTimeout(pending.timer);

    if (res.ok) {
      pending.resolve(res.payload);
    } else {
      const err = res.error;
      const error = new GatewayError(
        err?.message || 'Request failed',
        err?.code || 'unknown',
        err?.details,
      );
      pending.reject(error);

      // If auth error on connect, suppress reconnect
      if (err?.code && AUTH_ERROR_CODES.has(err.code)) {
        this.suppressReconnect = true;
      }
    }
  }

  // ─── Connect Handshake ──────────────────────────────────────

  private async sendConnectRequest(nonce?: string): Promise<void> {
    const auth: ConnectParams['auth'] = {};
    if (this.opts.token) auth.token = this.opts.token;
    if (this.opts.password) auth.password = this.opts.password;

    const params: ConnectParams = {
      minProtocol: 3,
      maxProtocol: 3,
      client: {
        id: 'eragon-control-ui',
        version: '1.0.0',
        platform: typeof navigator !== 'undefined' ? navigator.platform : 'unknown',
        mode: 'ui',
        instanceId: this.instanceId,
      },
      role: 'operator',
      scopes: ['operator.admin', 'operator.approvals', 'operator.pairing'],
      caps: ['tool-events'],
      auth,
      userAgent: typeof navigator !== 'undefined' ? navigator.userAgent : 'corgi-dashboard/1.0.0',
      locale: typeof navigator !== 'undefined' ? navigator.language : 'en',
    };
    // nonce is not needed for token auth (it's only for device auth inside the device object)

    try {
      const hello = await this.request<GatewayHelloOk>('connect', params);
      this._connected = true;
      this.reconnectDelay = RECONNECT_INITIAL_MS; // Reset backoff on success
      this.lastSeq = 0;
      this.opts.onConnect?.(hello);
    } catch (err) {
      // If auth error, don't reconnect
      if (err instanceof GatewayError && AUTH_ERROR_CODES.has(err.code)) {
        this.suppressReconnect = true;
        this.opts.onDisconnect?.(`Auth failed: ${err.message}`);
        this.closeSocket();
      } else {
        // Connection failed for non-auth reasons — close and schedule reconnect
        this.closeSocket();
        this.scheduleReconnect();
      }
    }
  }

  // ─── Reconnect ──────────────────────────────────────────────

  private scheduleReconnect(): void {
    if (this.suppressReconnect || this.intentionalClose) return;
    this.clearReconnectTimer();

    this.reconnectTimer = setTimeout(() => {
      this.reconnectTimer = null;
      this.openSocket();
    }, this.reconnectDelay);

    // Exponential backoff
    this.reconnectDelay = Math.min(
      this.reconnectDelay * RECONNECT_MULTIPLIER,
      RECONNECT_MAX_MS,
    );
  }

  private clearReconnectTimer(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
  }

  // ─── Cleanup ────────────────────────────────────────────────

  private rejectAllPending(reason: string): void {
    for (const [id, pending] of this.pendingRequests) {
      clearTimeout(pending.timer);
      pending.reject(new Error(reason));
    }
    this.pendingRequests.clear();
  }
}

// ─── Custom Error ──────────────────────────────────────────────────────────

export class GatewayError extends Error {
  code: string;
  details?: unknown;

  constructor(message: string, code: string, details?: unknown) {
    super(message);
    this.name = 'GatewayError';
    this.code = code;
    this.details = details;
  }
}
