import { create } from 'zustand';
import type {
  ConnectionStatus,
  GatewayHelloOk,
  ChatMessage,
  ChatSessionState,
  ChatSegment,
  ToolStreamEntry,
  SessionRow,
  AgentRow,
  ExecApprovalRequest,
  ToolCatalogGroup,
  StatusSummary,
  HealthSnapshot,
  PresenceEntry,
  ModelEntry,
  AgentIdentity,
} from './types';

const MAX_TOOL_STREAM = 50;

export interface GatewayStore {
  // ─── Connection ─────────────────────────────────────────────
  connectionStatus: ConnectionStatus;
  helloData: GatewayHelloOk | null;
  connectionError: string | null;

  setConnectionStatus: (status: ConnectionStatus) => void;
  setHelloData: (data: GatewayHelloOk) => void;
  setConnectionError: (error: string | null) => void;

  // ─── Active Session ─────────────────────────────────────────
  activeSessionKey: string | null;
  setActiveSessionKey: (key: string | null) => void;

  // ─── Chat State (per session) ───────────────────────────────
  chatSessions: Record<string, ChatSessionState>;

  getChatSession: (key: string) => ChatSessionState;
  setChatMessages: (key: string, messages: ChatMessage[]) => void;
  appendChatMessage: (key: string, message: ChatMessage) => void;
  setStreamingText: (key: string, text: string, runId: string) => void;
  commitStreamingSegment: (key: string) => void;
  addToolStreamEntry: (key: string, entry: ToolStreamEntry) => void;
  finaliseStream: (key: string, finalMessage?: ChatMessage) => void;
  abortStream: (key: string) => void;
  setChatLoading: (key: string, loading: boolean) => void;
  clearChat: (key: string) => void;

  // ─── Sessions ───────────────────────────────────────────────
  sessions: SessionRow[];
  sessionsCount: number;
  sessionsDefaults: { thinkingLevel?: string; reasoningLevel?: string } | null;

  setSessions: (sessions: SessionRow[], count: number, defaults?: { thinkingLevel?: string; reasoningLevel?: string }) => void;
  updateSession: (key: string, patch: Partial<SessionRow>) => void;
  removeSession: (key: string) => void;

  // ─── Approvals ──────────────────────────────────────────────
  approvals: ExecApprovalRequest[];

  addApproval: (approval: ExecApprovalRequest) => void;
  removeApproval: (id: string) => void;
  setApprovals: (approvals: ExecApprovalRequest[]) => void;

  // ─── Tools ──────────────────────────────────────────────────
  toolCatalog: ToolCatalogGroup[];
  setToolCatalog: (catalog: ToolCatalogGroup[]) => void;

  // ─── Agents ─────────────────────────────────────────────────
  agents: AgentRow[];
  defaultAgentId: string | null;
  agentIdentities: Record<string, AgentIdentity>;

  setAgents: (agents: AgentRow[], defaultId?: string) => void;
  setAgentIdentity: (agentId: string, identity: AgentIdentity) => void;

  // ─── Models ─────────────────────────────────────────────────
  models: ModelEntry[];
  currentModel: string | null;

  setModels: (models: ModelEntry[], current?: string) => void;

  // ─── Status / Health / Presence ─────────────────────────────
  status: StatusSummary | null;
  health: HealthSnapshot | null;
  presence: PresenceEntry[];

  setStatus: (status: StatusSummary) => void;
  setHealth: (health: HealthSnapshot) => void;
  setPresence: (presence: PresenceEntry[]) => void;

  // ─── Reset ──────────────────────────────────────────────────
  reset: () => void;
}

const emptyChatSession: ChatSessionState = {
  messages: [],
  streamingText: '',
  streamingRunId: null,
  segments: [],
  toolStream: [],
  isLoading: false,
};

export const useGatewayStore = create<GatewayStore>((set, get) => ({
  // ─── Connection ─────────────────────────────────────────────
  connectionStatus: 'disconnected' as ConnectionStatus,
  helloData: null,
  connectionError: null,

  setConnectionStatus: (status) => set({ connectionStatus: status }),
  setHelloData: (data) => set({ helloData: data }),
  setConnectionError: (error) => set({ connectionError: error }),

  // ─── Active Session ─────────────────────────────────────────
  activeSessionKey: null,
  setActiveSessionKey: (key) => set({ activeSessionKey: key }),

  // ─── Chat State ─────────────────────────────────────────────
  chatSessions: {},

  getChatSession: (key) => {
    return get().chatSessions[key] ?? { ...emptyChatSession };
  },

  setChatMessages: (key, messages) =>
    set((s) => ({
      chatSessions: {
        ...s.chatSessions,
        [key]: { ...(s.chatSessions[key] ?? { ...emptyChatSession }), messages },
      },
    })),

  appendChatMessage: (key, message) =>
    set((s) => {
      const session = s.chatSessions[key] ?? { ...emptyChatSession };
      return {
        chatSessions: {
          ...s.chatSessions,
          [key]: { ...session, messages: [...session.messages, message] },
        },
      };
    }),

  setStreamingText: (key, text, runId) =>
    set((s) => {
      const session = s.chatSessions[key] ?? { ...emptyChatSession };
      // Progressive full text: only accept if new length >= old length
      if (text.length < session.streamingText.length && runId === session.streamingRunId) {
        return s;
      }
      return {
        chatSessions: {
          ...s.chatSessions,
          [key]: { ...session, streamingText: text, streamingRunId: runId },
        },
      };
    }),

  commitStreamingSegment: (key) =>
    set((s) => {
      const session = s.chatSessions[key] ?? { ...emptyChatSession };
      if (!session.streamingText) return s;
      const seg: ChatSegment = { type: 'text', text: session.streamingText };
      return {
        chatSessions: {
          ...s.chatSessions,
          [key]: {
            ...session,
            segments: [...session.segments, seg],
            streamingText: '',
          },
        },
      };
    }),

  addToolStreamEntry: (key, entry) =>
    set((s) => {
      const session = s.chatSessions[key] ?? { ...emptyChatSession };
      let toolStream = [...session.toolStream, entry];
      // Cap at MAX_TOOL_STREAM, prune oldest
      if (toolStream.length > MAX_TOOL_STREAM) {
        toolStream = toolStream.slice(toolStream.length - MAX_TOOL_STREAM);
      }
      return {
        chatSessions: {
          ...s.chatSessions,
          [key]: { ...session, toolStream },
        },
      };
    }),

  finaliseStream: (key, finalMessage) =>
    set((s) => {
      const session = s.chatSessions[key] ?? { ...emptyChatSession };
      const messages = finalMessage
        ? [...session.messages, finalMessage]
        : session.messages;
      return {
        chatSessions: {
          ...s.chatSessions,
          [key]: {
            ...session,
            messages,
            streamingText: '',
            streamingRunId: null,
            segments: [],
            toolStream: [],
            isLoading: false,
          },
        },
      };
    }),

  abortStream: (key) =>
    set((s) => {
      const session = s.chatSessions[key] ?? { ...emptyChatSession };
      return {
        chatSessions: {
          ...s.chatSessions,
          [key]: {
            ...session,
            streamingText: '',
            streamingRunId: null,
            segments: [],
            isLoading: false,
          },
        },
      };
    }),

  setChatLoading: (key, loading) =>
    set((s) => {
      const session = s.chatSessions[key] ?? { ...emptyChatSession };
      return {
        chatSessions: {
          ...s.chatSessions,
          [key]: { ...session, isLoading: loading },
        },
      };
    }),

  clearChat: (key) =>
    set((s) => {
      const { [key]: _, ...rest } = s.chatSessions;
      return { chatSessions: rest };
    }),

  // ─── Sessions ───────────────────────────────────────────────
  sessions: [],
  sessionsCount: 0,
  sessionsDefaults: null,

  setSessions: (sessions, count, defaults) =>
    set({ sessions, sessionsCount: count, sessionsDefaults: defaults ?? null }),

  updateSession: (key, patch) =>
    set((s) => ({
      sessions: s.sessions.map((sess) =>
        sess.key === key ? { ...sess, ...patch } : sess,
      ),
    })),

  removeSession: (key) =>
    set((s) => ({
      sessions: s.sessions.filter((sess) => sess.key !== key),
      sessionsCount: Math.max(0, s.sessionsCount - 1),
    })),

  // ─── Approvals ──────────────────────────────────────────────
  approvals: [],

  addApproval: (approval) =>
    set((s) => {
      // Deduplicate
      if (s.approvals.some((a) => a.id === approval.id)) return s;
      return { approvals: [...s.approvals, approval] };
    }),

  removeApproval: (id) =>
    set((s) => ({ approvals: s.approvals.filter((a) => a.id !== id) })),

  setApprovals: (approvals) => set({ approvals }),

  // ─── Tools ──────────────────────────────────────────────────
  toolCatalog: [],
  setToolCatalog: (catalog) => set({ toolCatalog: catalog }),

  // ─── Agents ─────────────────────────────────────────────────
  agents: [],
  defaultAgentId: null,
  agentIdentities: {},

  setAgents: (agents, defaultId) =>
    set({ agents, defaultAgentId: defaultId ?? null }),

  setAgentIdentity: (agentId, identity) =>
    set((s) => ({
      agentIdentities: { ...s.agentIdentities, [agentId]: identity },
    })),

  // ─── Models ─────────────────────────────────────────────────
  models: [],
  currentModel: null,

  setModels: (models, current) =>
    set({ models, currentModel: current ?? null }),

  // ─── Status / Health / Presence ─────────────────────────────
  status: null,
  health: null,
  presence: [],

  setStatus: (status) => set({ status }),
  setHealth: (health) => set({ health }),
  setPresence: (presence) => set({ presence }),

  // ─── Reset ──────────────────────────────────────────────────
  reset: () =>
    set({
      connectionStatus: 'disconnected' as ConnectionStatus,
      helloData: null,
      connectionError: null,
      activeSessionKey: null,
      chatSessions: {},
      sessions: [],
      sessionsCount: 0,
      sessionsDefaults: null,
      approvals: [],
      toolCatalog: [],
      agents: [],
      defaultAgentId: null,
      agentIdentities: {},
      models: [],
      currentModel: null,
      status: null,
      health: null,
      presence: [],
    }),
}));
